let _jokeQueue=[];
let _currentJoke=null;
let _jokeShowTime=0;
const _JOKE_KEY='_arc_seen_jokes';
function getNextJoke(){
  const now=Date.now();
  // Keep the same joke for 30 seconds
  if(_currentJoke&&(now-_jokeShowTime)<30000)return _currentJoke;
  // Load seen list from localStorage
  let seen=[];
  try{seen=JSON.parse(localStorage.getItem(_JOKE_KEY)||'[]');}catch(e){}
  // If all jokes seen, reset the list (full cycle complete)
  if(seen.length>=_ARC_JOKES.length){seen=[];try{localStorage.setItem(_JOKE_KEY,'[]');}catch(e){}}
  // Build queue of unseen jokes if needed
  if(!_jokeQueue.length){
    const unseenIdxs=_ARC_JOKES.map((_,i)=>i).filter(i=>!seen.includes(i));
    // Fisher-Yates shuffle
    for(let i=unseenIdxs.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[unseenIdxs[i],unseenIdxs[j]]=[unseenIdxs[j],unseenIdxs[i]];}
    _jokeQueue=unseenIdxs;
  }
  if(!_jokeQueue.length)return _ARC_JOKES[0]; // fallback
  const idx=_jokeQueue.shift();
  seen.push(idx);
  try{localStorage.setItem(_JOKE_KEY,JSON.stringify(seen));}catch(e){}
  _currentJoke=_ARC_JOKES[idx];
  _jokeShowTime=now;
  return _currentJoke;
}

// Smooth time-based progress bar: fills toward ~90% over estSeconds, snaps to 100% on finish
function useSmoothProgress(estSeconds=15){
  const [state,setState]=useState(null); // null | {msg,pct}
  const timer=useRef(null);
  const startTime=useRef(0);
  const est=useRef(estSeconds);
  const msgRef=useRef("");
  const baseRef=useRef(0); // base pct offset for phase transitions

  const tick=useCallback(()=>{
    const elapsed=(Date.now()-startTime.current)/1000;
    const t=Math.min(elapsed/est.current,1);
    // Steady progression — nearly linear with gentle ease near end
    const curve=Math.pow(t,0.9);
    const pct=baseRef.current+(97-baseRef.current)*curve;
    setState({msg:msgRef.current,pct:Math.min(97,Math.round(pct)),wentBack:wentBackRef.current});
    timer.current=requestAnimationFrame(tick);
  },[]);

  const start=useCallback((msg,seconds)=>{
    if(seconds)est.current=seconds;
    msgRef.current=msg||"";
    baseRef.current=0;
    prevPctRef.current=0;
    wentBackRef.current=false;
    startTime.current=Date.now();
    if(timer.current)cancelAnimationFrame(timer.current);
    setState({msg:msgRef.current,pct:0,wentBack:false});
    timer.current=requestAnimationFrame(tick);
  },[tick]);

  // Transition to a new phase — continues smoothly from current pct
  const phase=useCallback((msg,seconds)=>{
    const elapsed=(Date.now()-startTime.current)/1000;
    const t=Math.min(elapsed/est.current,1);
    baseRef.current=Math.min(97,Math.round(baseRef.current+(97-baseRef.current)*Math.pow(t,0.9)));
    est.current=seconds||est.current;
    msgRef.current=msg||msgRef.current;
    startTime.current=Date.now();
  },[]);

  const update=useCallback((msg)=>{
    msgRef.current=msg||msgRef.current;
    // don't change pct — timer handles it
  },[]);

  // Jump to a real progress checkpoint and continue smooth animation from there
  const prevPctRef=useRef(0);
  const wentBackRef=useRef(false);
  const wentBackTimer=useRef(null);
  const set=useCallback((pct,msg)=>{
    const rounded=Math.min(97,Math.round(pct));
    if(rounded<prevPctRef.current-1){
      wentBackRef.current=true;
      if(wentBackTimer.current)clearTimeout(wentBackTimer.current);
      wentBackTimer.current=setTimeout(()=>{wentBackRef.current=false;},15000);
    }
    prevPctRef.current=rounded;
    baseRef.current=Math.min(97,pct);
    startTime.current=Date.now();
    if(msg)msgRef.current=msg;
    setState({msg:msgRef.current,pct:rounded,wentBack:wentBackRef.current});
    if(!timer.current)timer.current=requestAnimationFrame(tick);
  },[tick]);

  const dismissTimer=useRef(null);
  const finish=useCallback((msg)=>{
    if(timer.current){cancelAnimationFrame(timer.current);timer.current=null;}
    if(dismissTimer.current)clearTimeout(dismissTimer.current);
    baseRef.current=0;
    setState(msg?{msg,pct:100}:null);
    if(msg)dismissTimer.current=setTimeout(()=>setState(null),3500);
  },[]);

  const stop=useCallback(()=>{
    if(timer.current){cancelAnimationFrame(timer.current);timer.current=null;}
    baseRef.current=0;
    setState(null);
  },[]);

  const running=useCallback(()=>!!timer.current,[]);

  useEffect(()=>()=>{if(timer.current)cancelAnimationFrame(timer.current);},[]);

  return{progress:state,start,phase,update,set,finish,stop,running};
}

// Subscribe to background task registry updates
function useBgTasks(){
  const [tasks,setTasks]=useState({..._bgTasks});
  useEffect(()=>{
    const fn=t=>setTasks(t);
    _bgListeners.add(fn);
    return()=>_bgListeners.delete(fn);
  },[]);
  return tasks;
}

// ── CUSTOMER LOGO ──
const _logoCache={};
function useCustomerLogo(name){
  const [logo,setLogo]=useState(()=>{
    if(!name)return null;
    const k=name.toLowerCase().trim();
    return k in _logoCache?_logoCache[k]:undefined;
  });
  useEffect(()=>{
    if(!name)return;
    const k=name.toLowerCase().trim();
    if(k in _logoCache){setLogo(_logoCache[k]);return;}
    setLogo(undefined);
    fetch(`https://autocomplete.clearbit.com/v1/companies/suggest?query=${encodeURIComponent(k)}`)
      .then(r=>r.json())
      .then(d=>{const url=d&&d[0]?.logo||null;_logoCache[k]=url;setLogo(url);})
      .catch(()=>{_logoCache[k]=null;setLogo(null);});
  },[name]);
  return logo||null;
}

