let _apiKey=null;
// DECISION(v1.19.410): Load API key from user config first, then fall back to company config.
// This ensures new team members get the shared API key without needing admin to set it per-user.
async function loadApiKey(uid){
  try{const d=await fbDb.doc(`users/${uid}/config/api`).get();if(d.exists&&d.data().key){_apiKey=d.data().key;console.log("API key loaded from user config");}}catch(e){console.warn("loadApiKey user config failed:",e.message);}
  if(!_apiKey&&_appCtx.configPath){
    try{const cd=await fbDb.doc(`${_appCtx.configPath}/api`).get();if(cd.exists&&cd.data().key){_apiKey=cd.data().key;console.log("API key loaded from company config");}}catch(e){console.warn("loadApiKey company config failed:",e.message);}
  }
  if(!_apiKey)console.warn("API key not found — extraction, pricing, and AI features will be disabled. Set the key in Settings.");
}

// ── ARC NEURAL IQ (NIQ) — AI learning & standards knowledge engine ──
let _niqCache=null;
async function loadNIQ(){
  if(_niqCache)return _niqCache;
  if(!_appCtx.companyId)return[];
  try{
    const snap=await fbDb.collection(`companies/${_appCtx.companyId}/knowledgeBase`).get();
    _niqCache=snap.docs.map(d=>({id:d.id,...d.data()}));
    console.log(`[NIQ] Loaded ${_niqCache.length} Neural IQ docs (${_niqCache.reduce((s,d)=>(d.content||'').length+s,0)} chars)`);
    return _niqCache;
  }catch(e){console.warn('[NIQ] Load failed:',e);return[];}
}
function searchNIQ(niqDocs,terms){
  // Search ARC Neural IQ pages for terms, return top matches (max chars)
  if(!niqDocs?.length||!terms?.length)return'';
  const words=terms.flatMap(t=>t.toLowerCase().replace(/[^a-z0-9\s]/g,' ').split(/\s+/)).filter(w=>w.length>=3);
  if(!words.length)return'';
  const stopWords=new Set(['the','and','for','are','but','not','you','all','can','had','was','one','our','has','how','what','when','where','which','who','does','this','that','with','from','they','been','have','many','some','them','than','each','make','like','over','into','also']);
  const filtered=words.filter(w=>!stopWords.has(w));
  if(!filtered.length)return'';
  const scores=[];
  niqDocs.forEach(doc=>{
    if(!doc.content)return;
    const pages=doc.content.split(/--- PAGE (\d+) ---/).filter(Boolean);
    for(let i=0;i<pages.length-1;i+=2){
      const pageNum=pages[i],text=pages[i+1]||'',textLow=text.toLowerCase();
      let score=0;
      filtered.forEach(w=>{let idx=0;while((idx=textLow.indexOf(w,idx))!==-1){score++;idx+=w.length;}});
      if(score>0)scores.push({pageNum,text:text.trim(),score,source:doc.source||doc.id});
    }
    // Also handle non-paged docs (HazLoc DOCX extracts use === filename === format)
    if(!doc.content.includes('--- PAGE ')){
      const sections=doc.content.split(/=== (.+?) ===/).filter(Boolean);
      for(let i=0;i<sections.length-1;i+=2){
        const name=sections[i],text=sections[i+1]||'',textLow=text.toLowerCase();
        let score=0;
        filtered.forEach(w=>{let idx=0;while((idx=textLow.indexOf(w,idx))!==-1){score++;idx+=w.length;}});
        if(score>0)scores.push({pageNum:name.trim(),text:text.trim(),score,source:doc.source||doc.id});
      }
    }
  });
  scores.sort((a,b)=>b.score-a.score);
  let result='',chars=0;
  const MAX=12000;
  for(const pg of scores){
    if(chars+pg.text.length>MAX)break;
    result+=`\n[${pg.source} — Page ${pg.pageNum}]\n${pg.text}\n`;
    chars+=pg.text.length;
  }
  return result;
}

