// ── BACKGROUND TASK REGISTRY ──
let _bgTasks={};           // { [taskId]: { taskId, panelName, projectId, status, msg } }
let _bgDeleteTimers={};    // { [taskId]: timerHandle } — cancel stale timers on bgStart
let _bgListeners=new Set();

// DECISION(v1.19.589): Pending-pages cache keyed by panel.id. Survives PanelCard
// remounts (which happen when user navigates away from the project and back),
// so drawings dropped from Outlook (or anywhere else) don't get silently lost
// if user clicks away before confirming extraction.
// Entries: { pages: [...livePages], newItems: [...items], awaiting: true }
// Cleared when user confirms (confirmAndExtract) or explicitly cancels.
// NOT persisted across page reloads — intentional trade-off; badge on the Project
// Card uses _bgTasks (which is similarly module-scoped) to signal "needs review".
let _pendingPagesCache={};
let _pendingPagesListeners=new Set();
function _pendingPagesNotify(){_pendingPagesListeners.forEach(fn=>fn({..._pendingPagesCache}));}
function pendingPagesSet(panelId,data){_pendingPagesCache[panelId]=data;_pendingPagesNotify();}
function pendingPagesClear(panelId){if(panelId in _pendingPagesCache){delete _pendingPagesCache[panelId];_pendingPagesNotify();}}
function pendingPagesGet(panelId){return _pendingPagesCache[panelId]||null;}
function _bgNotify(){_bgListeners.forEach(fn=>fn({..._bgTasks}));}
function bgStart(taskId,panelName,projectId,msg){
  // Cancel any pending delete timer so a re-upload within the cleanup window doesn't wipe the new task
  if(_bgDeleteTimers[taskId]){clearTimeout(_bgDeleteTimers[taskId]);delete _bgDeleteTimers[taskId];}
  _bgTasks[taskId]={taskId,panelName,projectId,status:"running",msg:msg||"Processing…",pct:0,startedAt:Date.now()};
  _bgNotify();
  // DECISION(v1.19.599): Mirror to Firestore so teammates see cross-user extraction status.
  try{rbgStart(taskId,panelName,projectId,null);}catch(e){}
}
function bgSetPct(taskId,pct,msg){
  if(!_bgTasks[taskId])return;
  _bgTasks[taskId]={..._bgTasks[taskId],pct,...(msg&&{msg})};
  _bgNotify();
  try{rbgUpdate(taskId,msg||null,pct);}catch(e){}
}
function bgUpdate(taskId,msg){
  if(!_bgTasks[taskId])return;
  _bgTasks[taskId]={..._bgTasks[taskId],msg};
  _bgNotify();
  try{rbgUpdate(taskId,msg,null);}catch(e){}
}
function bgDone(taskId,msg){
  if(!_bgTasks[taskId])return;
  _bgTasks[taskId]={..._bgTasks[taskId],status:"done",pct:100,msg:msg||"Complete"};
  _bgNotify();
  _bgDeleteTimers[taskId]=setTimeout(()=>{delete _bgTasks[taskId];delete _bgDeleteTimers[taskId];_bgNotify();},4000);
  try{rbgDone(taskId,msg);}catch(e){}
}
function bgError(taskId,msg){
  if(!_bgTasks[taskId])return;
  _bgTasks[taskId]={..._bgTasks[taskId],status:"error",msg:msg||"Error"};
  _bgNotify();
  // No auto-dismiss — user must acknowledge errors
  try{rbgError(taskId,msg);}catch(e){}
}
function bgDismiss(taskId){
  if(_bgDeleteTimers[taskId]){clearTimeout(_bgDeleteTimers[taskId]);delete _bgDeleteTimers[taskId];}
  delete _bgTasks[taskId];
  _bgNotify();
}

// ── REMOTE BACKGROUND TASKS (team-wide visibility) ──
// DECISION(v1.19.599): Mirror extraction status to Firestore so other company members
// see what's being extracted on their dashboards. Path: companies/{cid}/activeExtractions/{uid_taskId}.
// Writes are throttled (≥2s between progress updates) to avoid Firestore write spam.
// Stale filter (>3 min since last heartbeat) ignores crashed/closed tabs client-side.
const _rbgWriteState={}; // {taskId: {lastWriteMs, pending}}
const _rbgDocId=(uid,taskId)=>`${uid}_${taskId}`;
function _rbgPath(){
  if(!_appCtx||!_appCtx.companyId||!_appCtx.uid)return null;
  return `companies/${_appCtx.companyId}/activeExtractions`;
}
async function rbgStart(taskId,panelName,projectId,projectName){
  const path=_rbgPath();if(!path)return;
  try{
    const uid=_appCtx.uid;
    const docId=_rbgDocId(uid,taskId);
    const entry={
      uid,userEmail:fbAuth.currentUser?.email||'',userName:fbAuth.currentUser?.displayName||'',
      taskId,panelName:panelName||'',projectId:projectId||'',projectName:projectName||'',
      status:'running',msg:'Starting extraction…',pct:0,
      startedAt:Date.now(),heartbeatAt:Date.now(),
    };
    await fbDb.doc(`${path}/${docId}`).set(entry);
    _rbgWriteState[taskId]={lastWriteMs:Date.now(),pending:null};
  }catch(e){console.warn('rbgStart failed:',e.message);}
}
async function _rbgFlush(taskId,fields){
  const path=_rbgPath();if(!path)return;
  try{
    const docId=_rbgDocId(_appCtx.uid,taskId);
    await fbDb.doc(`${path}/${docId}`).update({...fields,heartbeatAt:Date.now()});
  }catch(e){/* silent — throttled updates are best-effort */}
}
function rbgUpdate(taskId,msg,pct){
  const path=_rbgPath();if(!path)return;
  const now=Date.now();
  const state=_rbgWriteState[taskId]||(_rbgWriteState[taskId]={lastWriteMs:0,pending:null});
  const fields={};
  if(msg!=null)fields.msg=String(msg).slice(0,200);
  if(pct!=null)fields.pct=Math.max(0,Math.min(100,Math.round(pct)));
  // Throttle: ≥2s between writes. Batch pending update via setTimeout.
  if(now-state.lastWriteMs>=2000){
    state.lastWriteMs=now;
    if(state.pending){clearTimeout(state.pending);state.pending=null;}
    _rbgFlush(taskId,fields);
  }else{
    // Defer until throttle window clears. Last caller wins (merge fields).
    state.bufferedFields={...(state.bufferedFields||{}),...fields};
    if(state.pending)return;
    const delay=2000-(now-state.lastWriteMs);
    state.pending=setTimeout(()=>{
      state.lastWriteMs=Date.now();
      const f=state.bufferedFields||{};state.bufferedFields=null;state.pending=null;
      _rbgFlush(taskId,f);
    },delay);
  }
}
async function rbgDone(taskId,msg,status){
  const path=_rbgPath();if(!path)return;
  const state=_rbgWriteState[taskId];
  if(state?.pending){clearTimeout(state.pending);state.pending=null;}
  try{
    const docId=_rbgDocId(_appCtx.uid,taskId);
    // Mark done with brief TTL, then delete after 4s (matches local bgDone behavior)
    await fbDb.doc(`${path}/${docId}`).update({status:status||'done',msg:(msg||'Complete').slice(0,200),pct:100,heartbeatAt:Date.now()});
    setTimeout(async()=>{
      try{await fbDb.doc(`${path}/${docId}`).delete();}catch(e){}
      delete _rbgWriteState[taskId];
    },4000);
  }catch(e){/* silent */}
}
async function rbgError(taskId,msg){
  const path=_rbgPath();if(!path)return;
  const state=_rbgWriteState[taskId];
  if(state?.pending){clearTimeout(state.pending);state.pending=null;}
  try{
    const docId=_rbgDocId(_appCtx.uid,taskId);
    await fbDb.doc(`${path}/${docId}`).update({status:'error',msg:(msg||'Error').slice(0,200),heartbeatAt:Date.now()});
    // Errors auto-clear after 15s so we don't leave stale scary-looking entries on teammates' screens
    setTimeout(async()=>{
      try{await fbDb.doc(`${path}/${docId}`).delete();}catch(e){}
      delete _rbgWriteState[taskId];
    },15000);
  }catch(e){}
}
// On tab close, best-effort delete own in-progress tasks so teammates don't see ghosts
if(typeof window!=='undefined'){
  window.addEventListener('beforeunload',()=>{
    const path=_rbgPath();if(!path)return;
    for(const taskId of Object.keys(_rbgWriteState)){
      try{
        const docId=_rbgDocId(_appCtx.uid,taskId);
        // fire-and-forget (beforeunload won't await)
        fbDb.doc(`${path}/${docId}`).delete().catch(()=>{});
      }catch(e){}
    }
  });
}

// ── PROJECT LIVE UPDATE SYSTEM (for background extraction notifications) ──
const _projectListeners={};
function onProjectUpdated(projectId,fn){_projectListeners[projectId]=fn;return()=>{delete _projectListeners[projectId];};}
let _appProjectUpdateFn=null;
function notifyProjectListeners(projectId,liveProject){
  if(_projectListeners[projectId])_projectListeners[projectId](liveProject);
  if(_appProjectUpdateFn)_appProjectUpdateFn(liveProject);
}

// ── LABOR RATE DEFAULTS ──
const LABOR_RATE_DEFAULTS={
  wireMinPerPoint:10,         // Per wire point: 10 min
  doorDeviceMinPerDevice:11,  // Door-mounted device wiring: 11 min
  mountingMinPerDevice:4,     // Device mounting: 4 min
  ductDinMinPerFoot:10,       // Duct & DIN rail: 10 min/ft
  holesMinPerHole:15,         // Panel holes: 15 min/hole
  hmiHoleEquivalent:25,       // 1 HMI cutout = 25 standard holes
  squareCutoutMinPerCut:180,  // Square side cutout (horn, etc.): 3 hrs each
  // DECISION(v1.19.713): Control Panel Lead Time config — per-day crew hours
  // (feeds laborDays calc) and lead-time batch debounce window.
  dailyCrewHours:8,           // Productive labor hours per calendar day
  leadTimeBatchSeconds:30,    // Debounce window for batched BC lead-time writes
};
let LABOR_RATES={...LABOR_RATE_DEFAULTS};
const DOOR_DEVICE_TYPES=new Set(["pushbutton","pilot_light","selector_switch","hmi","e_stop","horn","meter"]);

// ── LABOR ESTIMATION (centralized) ──
function computeFallbackLaborHours(wireCount){
  if(!wireCount)return 0;
  return Math.round((Math.ceil(wireCount/12)+Math.ceil(wireCount/8))/2);
}

function computeLaborEstimate(panel){
  const pr=panel.pricing||{};
  const laborRate=pr.laborRate??45;
  const ld=panel.laborData||null;
  const fmt=n=>"$"+n.toLocaleString("en-US",{minimumFractionDigits:2,maximumFractionDigits:2});

  // Total override: laborHoursOverride bypasses everything
  if((pr.laborHoursOverride??null)!==null){
    const hrs=pr.laborHoursOverride;
    const cost=hrs*laborRate;
    return{lines:[{category:"Total Override",qty:hrs,unit:"hr",rate:laborRate,hours:hrs,cost}],totalCost:cost,totalHours:hrs,inputs:{},hasLayoutData:false,isLegacy:false,isOverride:true};
  }

  // Legacy fallback: no laborData
  if(!ld){
    // DECISION(v1.19.816): Manual labor entry fallback. When the panel has no schematic
    // data (laborData null), check for `_manualLabor` rows in panel.bom — these are the
    // CUT/LAYOUT/WIRE rows the user typed hours into via the BOM table for budgetary
    // quoting on BOM-only panels. Emit them as labor estimate lines using categories
    // that the existing GDEF/bcPatchLaborPlanningLines filters already bucket correctly
    // (Panel Holes → CUT, Device Mounting → LAYOUT, Wire Time → WIRE). All downstream
    // code (Panel Summary, Quote builder, BC sync) sees this estimate transparently.
    const manualLabor=(panel.bom||[]).filter(r=>r.isLaborRow&&r._manualLabor&&(+r.qty||0)>0);
    if(manualLabor.length){
      const CAT_MAP={CUT:"Panel Holes",LAYOUT:"Device Mounting",WIRE:"Wire Time"};
      const lines=manualLabor.map(r=>{
        const desc=(r.description||"").toUpperCase();
        const category=CAT_MAP[desc]||r.description||"Manual Labor";
        const hours=+r.qty||0;
        const rate=+r.unitPrice||laborRate;
        return{category,qty:hours,unit:"hr",rate,hours,cost:hours*rate};
      });
      const groups={};
      manualLabor.forEach(r=>{
        const key=(r.description||"").toLowerCase();
        if(key)groups[key]={hours:+r.qty||0,cost:(+r.qty||0)*(+r.unitPrice||laborRate)};
      });
      const totalHours=lines.reduce((s,l)=>s+l.hours,0);
      const totalCost=lines.reduce((s,l)=>s+l.cost,0);
      return{lines,groups,totalCost,totalHours,inputs:{},hasLayoutData:false,isLegacy:false,isOverride:false,isManual:true};
    }
    const wireCount=panel.validation?.wireCount||0;
    if(!wireCount)return{lines:[],totalCost:0,totalHours:0,inputs:{},hasLayoutData:false,isLegacy:true,isOverride:false};
    const hrs=computeFallbackLaborHours(wireCount);
    const cost=hrs*laborRate;
    return{lines:[{category:"Wire Time (legacy)",qty:wireCount,unit:"wires",rate:laborRate,cost,hours:hrs}],totalCost:cost,totalHours:hrs,inputs:{wireCount},hasLayoutData:false,isLegacy:true,isOverride:false};
  }

  // Full labor estimation from laborData
  const counts=ld.counts||{};
  const overrides=ld.overrides||{};
  const defaults=ld.defaults||{};
  const hasLayout=ld.hasLayoutData||false;

  // Helper: override > auto > default
  const val=(field,def)=>overrides[field]??counts[field]??defaults[field]??def;

  const wireCount=val("wireCount",0);
  const wireTerminations=val("wireTerminations",0);
  const doorDevices=val("doorDevices",0);
  const allDevices=val("allDevices",0);
  const panelHoles=val("panelHoles",0);
  const ductDinFeet=val("ductDinFeet",0);
  const sideTopSmallCount=val("sideTopSmallCount",0);
  const sideTopLargeCount=val("sideTopLargeCount",0);
  const squareCutoutCount=val("squareCutoutCount",0);
  const sideDeviceHours=val("sideDeviceHours",0);
  const sideDeviceCount=val("sideDeviceCount",0);
  const labelHours=val("labelHours",4);

  const lines=[];
  const addLine=(category,qty,minPerUnit,unit,field)=>{
    const hours=qty*minPerUnit/60;
    const cost=hours*laborRate;
    lines.push({category,qty,unit,minPerUnit,hours,cost,field});
  };

  addLine("Wire Time",wireCount,LABOR_RATES.wireMinPerPoint,"wires","wireCount");
  addLine("Door Wiring",doorDevices,LABOR_RATES.doorDeviceMinPerDevice,"devices","doorDevices");
  addLine("Device Mounting",allDevices,LABOR_RATES.mountingMinPerDevice,"devices","allDevices");
  addLine("Duct & DIN Rail",ductDinFeet,LABOR_RATES.ductDinMinPerFoot,"feet","ductDinFeet");
  addLine("Panel Holes",panelHoles,LABOR_RATES.holesMinPerHole,"holes","panelHoles");
  // Side-mounted components (unified: fans, ACs, fan shrouds, horns, etc.)
  if(sideDeviceHours>0)lines.push({category:"Side-Mounted Components",qty:sideDeviceHours,unit:"hours",minPerUnit:60,hours:sideDeviceHours,cost:sideDeviceHours*laborRate,field:"sideDeviceHours"});
  // Labels: stored as hours directly
  lines.push({category:"Labels",qty:labelHours,unit:"hours",minPerUnit:60,hours:labelHours,cost:labelHours*laborRate,field:"labelHours"});
  // DECISION(v1.19.436): Removed Project Mgmt and Crating Time from labor calculations — not needed.

  // DECISION(v1.19.426): Round each line cost and total to nearest dollar.
  // Prevents ARC vs BC mismatch from fractional cents in labor calculations.
  lines.forEach(l=>{l.cost=Math.round(l.cost);});
  // DECISION(v1.19.438): Calculate totalCost the SAME way as BOM rows — group hours, round per group,
  // then multiply by rate. This ensures the labor summary matches the BOM labor Ext $ exactly.
  // DECISION(v1.19.439): Calculate grouped labor ONCE — used by both Panel Summary and BOM rows.
  // No separate calculation paths that can diverge.
  const cutHrs=lines.filter(l=>["Panel Holes","Side-Mounted Components"].includes(l.category)).reduce((s,l)=>s+l.hours,0);
  const layoutHrs=lines.filter(l=>["Device Mounting","Duct & DIN Rail","Labels"].includes(l.category)).reduce((s,l)=>s+l.hours,0);
  const wireHrs=lines.filter(l=>["Wire Time","Door Wiring"].includes(l.category)).reduce((s,l)=>s+l.hours,0);
  const groups={
    cut:{hours:Math.ceil(cutHrs),cost:Math.ceil(cutHrs)*laborRate},
    layout:{hours:Math.ceil(layoutHrs),cost:Math.ceil(layoutHrs)*laborRate},
    wire:{hours:Math.ceil(wireHrs),cost:Math.ceil(wireHrs)*laborRate}
  };
  const totalHours=groups.cut.hours+groups.layout.hours+groups.wire.hours;
  const totalCost=groups.cut.cost+groups.layout.cost+groups.wire.cost;

  return{
    lines,totalCost,totalHours,groups,
    inputs:{wireCount,wireTerminations,doorDevices,allDevices,panelHoles,ductDinFeet,sideTopSmallCount,sideTopLargeCount,squareCutoutCount,sideDeviceHours,sideDeviceCount,labelHours},
    hasLayoutData:hasLayout,
    isLegacy:false,
    isOverride:false
  };
}

function isPanelBudgetary(panel){
  // A panel is BUDGETARY if it has at least one BOM item that is not confirmed in BC.
  // Panels with no BOM items are treated as non-budgetary (blank/not-yet-extracted).
  const bom=(panel.bom||[]).filter(r=>!r.isLaborRow&&!r.isCrossed);
  if(!bom.length)return false;
  return !bom.every(r=>r.priceSource==='bc');
}

function computePanelSellPrice(panel){
  const pr=panel.pricing||{};
  const laborEst=computeLaborEstimate(panel);
  // DECISION(v1.19.314): Do NOT filter out isCrossed items here. Crossed items ARE the replacements
  // (the new part that replaced the old one). Filtering them out excluded replacement costs from the sell price.
  const bom=(panel.bom||[]).filter(r=>!r.isLaborRow);
  const materialCost=bom.reduce((s,r)=>s+(r.unitPrice||0)*(r.qty||1),0);
  // Contingency costs are now BOM line items (BOM CONTINGENCY, WIRE & CONSUMABLES) — included in materialCost
  const laborCost=laborEst.totalHours>0?laborEst.totalCost:(pr.manualLaborCost||0);
  const grandTotal=materialCost+laborCost;
  // DECISION(v1.19.399): Use MARGIN formula, not markup.
  // Margin: sellPrice = cost / (1 - margin%). At 30% margin, $100 cost → $142.86 sell.
  // Markup would be: sellPrice = cost × (1 + markup%). At 30% markup, $100 cost → $130 sell.
  const marginPct=pr.markup??30;
  if(marginPct>=100)return grandTotal; // Prevent division by zero
  return Math.round(grandTotal/(1-marginPct/100)*100)/100;
}

// DECISION(v1.19.772): Cheap project-level total used by the Kanban column $ headers
// and the Sent/Sold/Lost dashboard boxes on the main page. Mirrors the logic at the
// quote print site (sum of computePanelSellPrice × lineQty across panels). Returns
// 0 when the project has no panels — keeps reduce() callers safe.
function computeProjectTotal(p){
  if(!p||!Array.isArray(p.panels))return 0;
  return p.panels.reduce((s,pan)=>s+computePanelSellPrice(pan)*(pan.lineQty??1),0);
}

// ── LABOR BOM ROWS (auto-managed, always first 3 rows) ──
const LABOR_BOM_GROUPS=[
  {partNumber:"1012",description:"CUT",   cats:["Panel Holes","Side-Mounted Components"]},
  {partNumber:"1013",description:"LAYOUT",cats:["Device Mounting","Duct & DIN Rail","Labels"]},
  {partNumber:"1014",description:"WIRE",  cats:["Wire Time","Door Wiring"]},
];
function buildLaborBomRows(panel){
  const est=computeLaborEstimate(panel);
  if(!est.lines.length||!est.groups)return[];
  // DECISION(v1.19.439): Use groups from computeLaborEstimate — single source of truth.
  // No separate calculation — BOM rows reference the same values as Panel Summary.
  // DECISION(v1.19.816): Preserve `_manualLabor` flag when est is the manual fallback
  // (BOM-only panel where the user typed hours into the BOM table).
  const laborRate=panel.pricing?.laborRate??45;
  const groupMap={cut:est.groups.cut,layout:est.groups.layout,wire:est.groups.wire};
  return LABOR_BOM_GROUPS.map(g=>{
    const key=g.description.toLowerCase();
    const grp=groupMap[key]||{hours:0};
    return{id:`labor-${g.partNumber}`,isLaborRow:true,_manualLabor:!!est.isManual,partNumber:g.partNumber,description:g.description,qty:grp.hours||0,unitPrice:laborRate,priceSource:est.isManual?"manual":"bc",priceDate:Date.now(),manufacturer:"",notes:""};
  });
}
function syncLaborBomRows(panel){
  const laborRows=buildLaborBomRows(panel);
  if(!laborRows.length)return panel;
  const nonLabor=(panel.bom||[]).filter(r=>!r.isLaborRow);
  return{...panel,bom:[...laborRows,...nonLabor]};
}

// DECISION(v1.19.706): Control Panel Lead Time compute. Pure function — takes panel +
// project, returns { shipDate, leadDays, breakdown, drivers, largestContributor }.
// All three durations sum sequentially (material arrives → labor builds → production
// finishes) to give the soonest possible ship date.
// Spec: docs/superpowers/specs/2026-04-24-control-panel-lead-time-design.md
const _ONE_DAY_MS=24*60*60*1000;
// DECISION(v1.19.736): Absolute cutoff (in days) for items that make it into the Lead
// Time Drivers note. Anything at or below this is considered routine lead time.
const LEAD_DRIVER_THRESHOLD_DAYS=30;
function _startOfDay(ts){const d=new Date(ts);d.setHours(0,0,0,0);return d.getTime();}
function _isoDate(ts){const d=new Date(ts);return d.toISOString().slice(0,10);}
function computeControlPanelLeadTime(panel,project){
  if(!panel)return{shipDate:null,leadDays:0,longestItemDays:0,laborDays:0,productionDays:0,averageItemLeadDays:0,drivers:[],largestContributor:"material",hasAiLeads:false,noDataWarning:true};
  const today=_startOfDay(Date.now());
  const bom=(panel.bom||[]).filter(r=>!r.isLaborRow&&(typeof _isExcludedFromPriceCheck==="function"?!_isExcludedFromPriceCheck(r):true)&&(+r.leadTimeDays||0)>0);
  const longestItemDays=bom.reduce((m,r)=>Math.max(m,+r.leadTimeDays||0),0);
  const lab=(typeof computeLaborEstimate==="function")?computeLaborEstimate(panel):{totalHours:0};
  // DECISION(v1.19.713): Daily crew hours config lives in the app-level LABOR_RATES
  // (loaded from laborRates Firestore doc on mount). Falls back to 8 if unset.
  const dailyCrewHours=+(typeof LABOR_RATES!=="undefined"?LABOR_RATES.dailyCrewHours:null)||+project?.laborConfig?.dailyCrewHours||8;
  const laborDays=Math.ceil((lab.totalHours||0)/dailyCrewHours);
  // DECISION(v1.19.714): productionDays derived from productionEndDate (YYYY-MM-DD).
  // Represents post-assembly production time. If end date is before assembly complete,
  // productionDays=0 (material+labor is binding). Legacy panel.productionDays (numeric)
  // still read as fallback for projects saved before the date-picker change.
  const assemblyCompleteBeforeProd=today+(longestItemDays+laborDays)*_ONE_DAY_MS;
  let productionDays=0;
  if(panel.productionEndDate){
    const prodEnd=_startOfDay(new Date(panel.productionEndDate).getTime());
    if(!isNaN(prodEnd)&&prodEnd>assemblyCompleteBeforeProd){
      productionDays=Math.ceil((prodEnd-assemblyCompleteBeforeProd)/_ONE_DAY_MS);
    }
  }else if(panel.productionDays!=null){
    productionDays=Math.max(0,Math.min(365,+panel.productionDays||0));
  }
  const totalDays=longestItemDays+laborDays+productionDays;
  const shipDate=today+totalDays*_ONE_DAY_MS;
  // Largest contributor
  let largestContributor="material",largest=longestItemDays;
  if(laborDays>largest){largestContributor="labor";largest=laborDays;}
  if(productionDays>largest){largestContributor="production";largest=productionDays;}
  // DECISION(v1.19.736): Drivers = BOM items with leadTimeDays > LEAD_DRIVER_THRESHOLD_DAYS
  // (30 days). Previously used "above BOM average," which for panels with a few long-lead
  // items and many short-lead ones listed far too many rows in the auto-generated Notes
  // block. An absolute cutoff keeps the list focused on items that genuinely drive the
  // schedule — the only ones worth flagging on a customer-facing quote note.
  const ldValues=bom.map(r=>+r.leadTimeDays||0).filter(n=>n>0);
  const avg=ldValues.length?ldValues.reduce((s,n)=>s+n,0)/ldValues.length:0;
  const drivers=[...bom]
    .filter(r=>(+r.leadTimeDays||0)>LEAD_DRIVER_THRESHOLD_DAYS)
    .sort((a,b)=>(+b.leadTimeDays||0)-(+a.leadTimeDays||0))
    .map(r=>({qty:+r.qty||1,partNumber:r.partNumber||"",description:r.description||"",leadTimeDays:+r.leadTimeDays,source:r.leadTimeSource||"unknown"}));
  return{
    shipDate:_isoDate(shipDate),
    leadDays:totalDays,
    longestItemDays,laborDays,productionDays,
    averageItemLeadDays:Math.round(avg*10)/10,
    drivers,largestContributor,
    hasAiLeads:bom.some(r=>r.leadTimeSource==="ai"),
    noDataWarning:longestItemDays===0&&laborDays===0&&productionDays===0,
  };
}
// Expose for console testing
if(typeof window!=="undefined"){window.computeControlPanelLeadTime=computeControlPanelLeadTime;window._startOfDay=_startOfDay;window._isoDate=_isoDate;}

// DECISION(v1.19.710): Lead drivers note — per-panel. Items with leadTimeDays above
// THAT panel's average get listed. Skip if fewer than 3 priced items in the panel
// (average not meaningful). AI-sourced entries flagged with asterisk + footnote.
// DECISION(v1.19.718): Switched destination from project.quote.lineNotes to the
// panel-card's Notes field (panel.bomNotes) which already perpetuates to the quote.
// This keeps the auto-note visible in the UI where users expect it and avoids
// clobbering any quote-level lineNotes the user might set manually.
// DECISION(v1.19.719): Multi-line format per user — header + one line per driver:
//   Lead Time Drivers:
//   Qty 1 · Part# 0800886 = 90 Days
//   Qty 2 · Part# 140G-G6C3-C20 = 45 Days *
//   * ARC estimate
function _formatLeadDriversNote(drivers){
  if(!drivers.length)return "";
  const anyAi=drivers.some(d=>d.source==="ai");
  // DECISION(v1.19.737): Compact format per user — Qty · Part# · Days. Description dropped
  // to keep the quote notes tight (the part number already identifies the item).
  // DECISION(v1.19.742): Footnote label says "ARC estimate" instead of "AI estimate" so
  // the customer-facing quote stays branded under ARC. The strip regex below still matches
  // the legacy "AI estimate" wording so existing saved notes get cleaned up on refresh.
  const lines=drivers.map(d=>{
    const qty=d.qty||1;
    const aiMark=d.source==="ai"?" *":"";
    return`Qty ${qty} · Part# ${d.partNumber} = ${d.leadTimeDays} Days${aiMark}`.replace(/\s+/g," ").trim();
  });
  return`Lead Time Drivers:\n${lines.join("\n")}${anyAi?"\n* ARC estimate":""}`;
}
function _computePanelLeadDriversLine(panel){
  const rows=(panel?.bom||[]).filter(r=>!r.isLaborRow&&(typeof _isExcludedFromPriceCheck==="function"?!_isExcludedFromPriceCheck(r):true)&&(+r.leadTimeDays||0)>0);
  // DECISION(v1.19.736): Absolute threshold — only items with lead times > 30 days.
  const drivers=[...rows]
    .filter(r=>(+r.leadTimeDays||0)>LEAD_DRIVER_THRESHOLD_DAYS)
    .sort((a,b)=>(+b.leadTimeDays||0)-(+a.leadTimeDays||0))
    .map(r=>({qty:+r.qty||1,partNumber:r.partNumber||"",description:r.description||"",leadTimeDays:+r.leadTimeDays,source:r.leadTimeSource||"unknown"}));
  return _formatLeadDriversNote(drivers);
}
// Back-compat wrapper: single-panel → panel line; multi-panel → aggregated across panels.
function _computeProjectLeadDriversLine(project){
  const panels=project?.panels||[];
  if(!panels.length)return"";
  if(panels.length===1)return _computePanelLeadDriversLine(panels[0]);
  const allRows=[];
  for(const p of panels){
    for(const r of (p.bom||[])){
      if(!r.isLaborRow&&(typeof _isExcludedFromPriceCheck==="function"?!_isExcludedFromPriceCheck(r):true)&&(+r.leadTimeDays||0)>0){
        allRows.push(r);
      }
    }
  }
  // DECISION(v1.19.736): Absolute threshold — only items with lead times > 30 days.
  const drivers=[...allRows]
    .filter(r=>(+r.leadTimeDays||0)>LEAD_DRIVER_THRESHOLD_DAYS)
    .sort((a,b)=>(+b.leadTimeDays||0)-(+a.leadTimeDays||0))
    .map(r=>({qty:+r.qty||1,partNumber:r.partNumber||"",description:r.description||"",leadTimeDays:+r.leadTimeDays,source:r.leadTimeSource||"unknown"}));
  return _formatLeadDriversNote(drivers);
}
// DECISION(v1.19.718/719): Refresh the "Lead Time Drivers" block in EACH panel's bomNotes.
// The block = header "Lead Time Drivers:" + one or more "Part# ..." lines + optional
// "* ARC estimate" footnote (legacy notes used "* AI estimate" — both are still matched
// by the strip regex so v1.19.741-and-earlier saves get migrated automatically).
// Also strips any stale v1.19.710-era "Lead drivers (...): ..." single-line format.
function _refreshLeadDriversInQuote(project){
  const panels=project?.panels||[];
  if(!panels.length)return project;
  // DECISION(v1.19.737/742): Block body matches either the new "Qty … Part# … = N Days"
  // lines OR the legacy "Part# … = N Days" lines so older saved notes get cleanly stripped
  // and replaced on the next refresh pass. Footnote matches both "ARC estimate" (current)
  // and "AI estimate" (legacy) so existing notes upgrade automatically.
  const newBlockRe=/Lead Time Drivers:(?:\n(?:(?:Qty\s[^\n]*|Part#[^\n]*)|\* (?:ARC|AI) estimate))+/;
  // Legacy single-line format from v1.19.710 — cleaned up on first write
  const legacyRe=/Lead drivers[^\n]*\n?/;
  let changed=false;
  // DECISION(v1.19.720): Lead Time Drivers block ALWAYS lives at the TOP of the Notes
  // field. Any existing instance of the block is removed from wherever it was, and a
  // fresh version is prepended (followed by a blank line if there's other content).
  // User's hand-written notes below the block are preserved verbatim.
  const stripBlockRe=/\n?\s*Lead Time Drivers:(?:\n(?:(?:Qty\s[^\n]*|Part#[^\n]*)|\* (?:ARC|AI) estimate))+\s*/;
  const newPanels=panels.map(panel=>{
    const line=_computePanelLeadDriversLine(panel);
    let existing=panel.bomNotes||"";
    // Strip legacy single-line format first
    if(legacyRe.test(existing))existing=existing.replace(legacyRe,"").trim();
    // Strip any prior block wherever it was
    if(newBlockRe.test(existing))existing=existing.replace(stripBlockRe,"").trim();
    // Prepend fresh block if we have one
    const next=line?(existing?`${line}\n\n${existing}`:line):existing;
    if(next===(panel.bomNotes||""))return panel;
    changed=true;
    return{...panel,bomNotes:next};
  });
  if(!changed)return project;
  // Also strip any stale block from quote.lineNotes left over from the v1.19.710 version.
  let newQuote=project.quote||{};
  const qNotes=newQuote.lineNotes||"";
  let cleanedQ=qNotes;
  if(newBlockRe.test(cleanedQ))cleanedQ=cleanedQ.replace(/\n?\s*Lead Time Drivers:(?:\n(?:(?:Qty\s[^\n]*|Part#[^\n]*)|\* (?:ARC|AI) estimate))+/,"").trim();
  if(legacyRe.test(cleanedQ))cleanedQ=cleanedQ.replace(legacyRe,"").trim();
  if(cleanedQ!==qNotes){
    newQuote={...newQuote,lineNotes:cleanedQ};
    return{...project,panels:newPanels,quote:newQuote};
  }
  return{...project,panels:newPanels};
}
if(typeof window!=="undefined"){
  window._computePanelLeadDriversLine=_computePanelLeadDriversLine;
  window._computeProjectLeadDriversLine=_computeProjectLeadDriversLine;
  window._refreshLeadDriversInQuote=_refreshLeadDriversInQuote;
}

// DECISION(v1.19.740): AI lead times present → quote is not firm. Helpers to detect
// AI-sourced lead times, auto-flip panels into "Budgetary" when the user tries to print
// or send a quote, and offer to revert the Budgetary flag once every AI estimate has
// been replaced with a firm (manual/supplier/BC/scraper) lead time.
//
// The auto-set leaves a sentinel `isBudgetaryAiAutoSet: true` on panel.pricing so we can
// tell ARC-set budgetary apart from a user-set one — we only propose to clear the flag
// when ARC was the one that set it. A manually-checked Budgetary box is never touched.
function _hasAiLeadTimes(project){
  return (project?.panels||[]).some(p=>
    (p.bom||[]).some(r=>!r.isLaborRow&&r.leadTimeSource==="ai")
  );
}
function _countAiLeadTimes(project){
  return (project?.panels||[]).reduce((n,p)=>
    n+(p.bom||[]).filter(r=>!r.isLaborRow&&r.leadTimeSource==="ai").length,0);
}
// Mark every panel as budgetary and record that ARC did it. Returns {updatedProject, changed}.
function _markProjectBudgetaryForAiLeads(project){
  let changed=false;
  const panels=(project.panels||[]).map(p=>{
    const pr=p.pricing||{};
    if(pr.isBudgetary)return p; // user already checked it, or a previous pass already flipped it
    changed=true;
    return{...p,pricing:{...pr,isBudgetary:true,isBudgetaryAiAutoSet:true}};
  });
  return{updatedProject:changed?{...project,panels}:project,changed};
}
// Clear the auto-set budgetary flag (and the sentinel). Only affects panels where ARC
// auto-set the flag — user-marked budgetary panels are left alone.
function _clearAutoBudgetary(project){
  let changed=false;
  const panels=(project.panels||[]).map(p=>{
    const pr=p.pricing||{};
    if(!pr.isBudgetaryAiAutoSet)return p;
    changed=true;
    const{isBudgetaryAiAutoSet:_a,isBudgetary:_b,...rest}=pr;
    return{...p,pricing:rest};
  });
  return{updatedProject:changed?{...project,panels}:project,changed};
}
function _hasArcAutoBudgetary(project){
  return (project?.panels||[]).some(p=>(p.pricing||{}).isBudgetaryAiAutoSet);
}
if(typeof window!=="undefined"){
  window._hasAiLeadTimes=_hasAiLeadTimes;
  window._countAiLeadTimes=_countAiLeadTimes;
  window._markProjectBudgetaryForAiLeads=_markProjectBudgetaryForAiLeads;
  window._clearAutoBudgetary=_clearAutoBudgetary;
  window._hasArcAutoBudgetary=_hasArcAutoBudgetary;
}

// Load MSAL on demand — not at page load (avoids conflict with Firebase Microsoft auth)
function loadMsalScript(){
  return new Promise((res,rej)=>{
    if(window.msal){res();return;}
    const s=document.createElement("script");
    s.src="https://alcdn.msauth.net/browser/2.28.1/js/msal-browser.min.js";
    s.onload=()=>res();
    s.onerror=()=>rej(new Error("Failed to load MSAL"));
    document.head.appendChild(s);
  });
}

async function ensureMsal(){
  if(_msalReady)return _msalInstance;
  await loadMsalScript();
  try{
    _msalInstance=new msal.PublicClientApplication({
      auth:{clientId:BC_CLIENT_ID,authority:`https://login.microsoftonline.com/${BC_TENANT}`,redirectUri:window.location.origin},
      cache:{cacheLocation:"sessionStorage"}
    });
    await _msalInstance.initialize();
    _msalReady=true;
    return _msalInstance;
  }catch(e){console.warn("MSAL init failed:",e);return null;}
}

async function acquireBcToken(interactive=true){
  const inst=await ensureMsal();
  if(!inst)return null;
  const scopes=["https://api.businesscentral.dynamics.com/.default"];
  // Try silent with cached accounts first
  try{
    const accounts=inst.getAllAccounts();
    if(accounts.length>0){
      const resp=await inst.acquireTokenSilent({scopes,account:accounts[0]});
      _bcToken=resp.accessToken;
      return _bcToken;
    }
  }catch(e){console.log("Silent BC token failed, trying ssoSilent…");}
  // Try SSO silent — works if the user already has an active Microsoft browser session
  try{
    const hint=fbAuth.currentUser?.email;
    const resp=await inst.ssoSilent({scopes,...(hint?{loginHint:hint}:{})});
    _bcToken=resp.accessToken;
    return _bcToken;
  }catch(e){}
  if(!interactive)return null;
  try{
    const resp=await inst.acquireTokenPopup({scopes});
    _bcToken=resp.accessToken;
    tryGraphTokenSilent().catch(()=>{}); // background: pre-consent Mail.Send if already granted
    return _bcToken;
  }catch(e){console.warn("BC token acquisition failed:",e);return null;}
}

let _graphToken=null;
// DECISION(v1.19.338): Mail.Read needed to search existing conversations for reply-to-thread.
// Mail.ReadWrite needed to create draft replies with attachments before sending.
const GRAPH_MAIL_SCOPES=["https://graph.microsoft.com/Mail.Send","https://graph.microsoft.com/Mail.Read","https://graph.microsoft.com/Mail.ReadWrite"];

async function tryGraphTokenSilent(){
  try{
    const inst=await ensureMsal();
    if(!inst)return null;
    const accounts=inst.getAllAccounts();
    if(!accounts.length)return null;
    const resp=await inst.acquireTokenSilent({scopes:GRAPH_MAIL_SCOPES,account:accounts[0]});
    _graphToken=resp.accessToken;return _graphToken;
  }catch(e){return null;}
}

async function acquireGraphToken(){
  const inst=await ensureMsal();
  if(!inst)return null;
  try{
    const accounts=inst.getAllAccounts();
    if(accounts.length>0){
      const resp=await inst.acquireTokenSilent({scopes:GRAPH_MAIL_SCOPES,account:accounts[0]});
      _graphToken=resp.accessToken;return _graphToken;
    }
  }catch(e){}
  try{
    const resp=await inst.acquireTokenPopup({scopes:GRAPH_MAIL_SCOPES});
    _graphToken=resp.accessToken;return _graphToken;
  }catch(e){console.warn("Graph token acquisition failed:",e);return null;}
}

// ── PERFORMANCE: Debug logging flag — set window._arcDebug=true in console to enable verbose logs ──
window._arcDebug=false;
const _dbg=(...a)=>{if(window._arcDebug)console.log(...a);};

// ── ARC DIALOG SYSTEM ──
// DECISION(v1.19.778): Replace native browser popups (alert / confirm / prompt) with
// in-app modals. Browser popups carry the URL ("matrix-arc.web.app says…"), can't
// be styled, block on the main thread, and look out of place on a dark-themed app.
//
// Imperative API — works from anywhere (event handlers, async functions, top-level
// code, even non-React modules). Returns a Promise:
//   await arcAlert("Saved.")                             → undefined
//   await arcAlert("Operation failed.", {kind:"error"})  → undefined
//   const ok = await arcConfirm("Delete this row?")      → boolean
//   const txt = await arcPrompt("Enter notes:")          → string | null (null=cancel)
//
// `kind` (info|success|warning|error) tints the icon + accent. ArcDialogHost
// (mounted once at App root) renders the queue. Multiple rapid calls queue up and
// resolve in order so a sequence like alert → confirm doesn't lose the second one.
let _arcDialogQueue=[];
const _arcDialogSubs=new Set();
function _arcDialogPush(item){_arcDialogQueue=[..._arcDialogQueue,item];_arcDialogSubs.forEach(s=>s());}
function _arcDialogShift(){_arcDialogQueue=_arcDialogQueue.slice(1);_arcDialogSubs.forEach(s=>s());}
function arcAlert(message,opts){
  return new Promise(resolve=>{
    _arcDialogPush({type:"alert",message:String(message==null?"":message),kind:(opts&&opts.kind)||"info",title:(opts&&opts.title)||null,okLabel:(opts&&opts.okLabel)||"OK",resolve});
  });
}
function arcConfirm(message,opts){
  return new Promise(resolve=>{
    _arcDialogPush({type:"confirm",message:String(message==null?"":message),kind:(opts&&opts.kind)||"info",title:(opts&&opts.title)||null,okLabel:(opts&&opts.okLabel)||"OK",cancelLabel:(opts&&opts.cancelLabel)||"Cancel",destructive:!!(opts&&opts.destructive),resolve});
  });
}
function arcPrompt(message,opts){
  return new Promise(resolve=>{
    _arcDialogPush({type:"prompt",message:String(message==null?"":message),defaultValue:(opts&&opts.defaultValue)||"",placeholder:(opts&&opts.placeholder)||"",multiline:!!(opts&&opts.multiline),title:(opts&&opts.title)||null,okLabel:(opts&&opts.okLabel)||"OK",cancelLabel:(opts&&opts.cancelLabel)||"Cancel",resolve});
  });
}
// Expose globally so non-React utility code (Cloud Function callers, BC helpers)
// can call them too without importing.
window.arcAlert=arcAlert;window.arcConfirm=arcConfirm;window.arcPrompt=arcPrompt;

// ArcDialogHost — mounted once at App root. Renders the current head of the queue.
function ArcDialogHost(){
  const [,setTick]=useState(0);
  const [inputValue,setInputValue]=useState("");
  const inputRef=useRef(null);
  useEffect(()=>{
    const sub=()=>setTick(t=>t+1);
    _arcDialogSubs.add(sub);
    return()=>{_arcDialogSubs.delete(sub);};
  },[]);
  const item=_arcDialogQueue[0];
  // Reset input value whenever a new prompt becomes active
  useEffect(()=>{
    if(item&&item.type==="prompt"){
      setInputValue(item.defaultValue||"");
      // Focus the input shortly after mount
      setTimeout(()=>{try{inputRef.current&&inputRef.current.focus();inputRef.current&&inputRef.current.select&&inputRef.current.select();}catch(e){}},30);
    }
  },[item]);
  if(!item)return null;
  const KIND_COLORS={
    info:{accent:"#38bdf8",bg:"#0c2233",border:"#38bdf844",icon:"ⓘ"},
    success:{accent:"#10b981",bg:"#052e16",border:"#10b98144",icon:"✓"},
    warning:{accent:"#f59e0b",bg:"#3a1f00",border:"#f59e0b44",icon:"⚠"},
    error:{accent:"#ef4444",bg:"#2a0a0a",border:"#ef444444",icon:"⚠"},
  };
  const k=KIND_COLORS[item.kind]||KIND_COLORS.info;
  function close(value){
    const r=item.resolve;
    _arcDialogShift();
    r&&r(value);
  }
  function onOk(){
    if(item.type==="alert")close(undefined);
    else if(item.type==="confirm")close(true);
    else if(item.type==="prompt")close(inputValue);
  }
  function onCancel(){
    if(item.type==="confirm")close(false);
    else if(item.type==="prompt")close(null);
    else close(undefined);
  }
  function onKey(e){
    // Enter = OK (except multiline prompts where Enter inserts a newline; use Ctrl+Enter)
    if(e.key==="Enter"){
      if(item.type==="prompt"&&item.multiline&&!e.ctrlKey)return;
      e.preventDefault();onOk();
    }
    if(e.key==="Escape"){e.preventDefault();onCancel();}
  }
  // Default title per kind if caller didn't supply one
  const titleByKind={info:"Notice",success:"Success",warning:"Warning",error:"Error"};
  const title=item.title||(item.type==="confirm"?"Please confirm":item.type==="prompt"?"Input required":titleByKind[item.kind]||"Notice");
  return ReactDOM.createPortal(
    <div onKeyDown={onKey} tabIndex={-1}
      style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.78)",zIndex:99999,display:"flex",alignItems:"center",justifyContent:"center",padding:16}}>
      <div onMouseDown={e=>e.stopPropagation()}
        style={{background:"#0d0d1a",border:`1px solid ${k.accent}66`,borderRadius:12,padding:"22px 26px",width:"100%",maxWidth:item.type==="prompt"&&item.multiline?640:480,boxShadow:`0 0 36px ${k.accent}55, 0 12px 48px rgba(0,0,0,0.7)`,fontFamily:"inherit"}}>
        <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:12}}>
          <div style={{width:32,height:32,borderRadius:"50%",background:k.bg,border:`1px solid ${k.border}`,display:"flex",alignItems:"center",justifyContent:"center",color:k.accent,fontSize:18,fontWeight:800}}>{k.icon}</div>
          <div style={{fontSize:15,fontWeight:700,color:"#f1f5f9",flex:1}}>{title}</div>
          <button onClick={onCancel} title="Close" style={{background:"none",border:"none",color:"#94a3b8",cursor:"pointer",fontSize:18,lineHeight:1,padding:"2px 6px"}}>✕</button>
        </div>
        <div style={{fontSize:13,color:"#cbd5e1",lineHeight:1.55,marginBottom:item.type==="prompt"?10:18,whiteSpace:"pre-wrap"}}>{item.message}</div>
        {item.type==="prompt"&&(
          item.multiline?
            <textarea ref={inputRef} value={inputValue} onChange={e=>setInputValue(e.target.value)} placeholder={item.placeholder}
              style={{width:"100%",minHeight:120,background:"#0a0a14",border:"1px solid #3d6090",color:"#f1f5f9",borderRadius:6,padding:"8px 10px",fontSize:13,outline:"none",fontFamily:"inherit",resize:"vertical",marginBottom:14,boxSizing:"border-box"}}/>
            :
            <input ref={inputRef} value={inputValue} onChange={e=>setInputValue(e.target.value)} placeholder={item.placeholder}
              style={{width:"100%",background:"#0a0a14",border:"1px solid #3d6090",color:"#f1f5f9",borderRadius:6,padding:"8px 10px",fontSize:13,outline:"none",fontFamily:"inherit",marginBottom:14,boxSizing:"border-box"}}/>
        )}
        <div style={{display:"flex",gap:8,justifyContent:"flex-end"}}>
          {(item.type==="confirm"||item.type==="prompt")&&(
            <button onClick={onCancel}
              style={{background:"transparent",color:"#94a3b8",border:"1px solid #3d6090",borderRadius:7,padding:"7px 18px",fontSize:13,cursor:"pointer",fontFamily:"inherit"}}>{item.cancelLabel}</button>
          )}
          <button onClick={onOk} autoFocus={item.type!=="prompt"}
            style={{background:item.destructive?"#ef4444":k.accent,color:"#fff",border:"none",borderRadius:7,padding:"7px 20px",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"inherit",boxShadow:`0 0 12px ${item.destructive?"#ef4444":k.accent}55`}}>{item.okLabel}</button>
        </div>
      </div>
    </div>,
    document.body
  );
}

