// Heuristic: same chars different formatting = format; very different = extraction
function guessCorrection(origPN,newPN){
  const norm=s=>s.replace(/[-\s./\\()]/g,'').toUpperCase();
  const a=norm(origPN),b=norm(newPN);
  if(a===b)return'format';
  // Count overlapping chars
  let matches=0;
  const shorter=a.length<=b.length?a:b;
  const longer=a.length>b.length?a:b;
  for(const c of shorter){if(longer.includes(c))matches++;}
  const ratio=matches/Math.max(a.length,b.length,1);
  return ratio>=0.55?'format':'extraction';
}

// ── QUOTE NUMBER COUNTER ──
// Stores next quote number in Firestore; uses transaction for atomic increment.
// Path: {configPath}/quoteCounter  doc: {next: <number>}
// Format: MTX-Q2##### starting at MTX-Q202000
async function getNextQuoteNumber(uid){
  const path=(_appCtx.configPath||`users/${uid}/config`)+"/quoteCounter";
  const ref=fbDb.doc(path);
  const num=await fbDb.runTransaction(async tx=>{
    const doc=await tx.get(ref);
    const stored=doc.exists?(doc.data().next||0):0;
    const next=Math.max(stored,202000); // enforce minimum start
    tx.set(ref,{next:next+1});
    return next;
  });
  return "MTX-Q"+String(num);
}

