async function logPanelToCPD(uid,panel,categorizedBom,metadata=null){
  const cpd=await loadCPD(uid);
  const plcProc=categorizedBom.filter(r=>r.cpdCategory==='PLC Processor').length;
  const plcIn=categorizedBom.filter(r=>r.cpdCategory==='PLC I/O Module'&&/(input|DI|AI)/i.test(r.description||'')).length;
  const plcOut=categorizedBom.filter(r=>r.cpdCategory==='PLC I/O Module'&&/(output|DO|AO)/i.test(r.description||'')).length;
  const motors=categorizedBom.filter(r=>['VFD','Contactor'].includes(r.cpdCategory)).length;
  const existing=cpd.panels||[];
  const prev=existing.find(p=>p.panelId===panel.id)||{};
  const spec={
    ...prev,
    panelId:panel.id,panelName:panel.name||panel.drawingNo||'Panel',
    projectId:panel.projectId||'',
    drawingNo:panel.drawingNo||'',
    specs:{plcProcessors:plcProc,plcInputs:plcIn,plcOutputs:plcOut,motorCount:motors,
      itemCount:categorizedBom.filter(r=>!r.isLaborRow).length},
    bomSummary:categorizedBom.filter(r=>!r.isLaborRow).map(r=>({category:r.cpdCategory||'Other',partNumber:r.partNumber,description:r.description,qty:r.qty||1})),
    ...(metadata?{
      panelType:metadata.panelType||prev.panelType||'',
      controlledEquipment:metadata.controlledEquipment||prev.controlledEquipment||'',
      voltages:metadata.voltages||prev.voltages||{},
      plcBrand:metadata.plcBrand||prev.plcBrand||'',
      enclosureType:metadata.enclosureType||prev.enclosureType||'',
      additionalNotes:metadata.additionalNotes||prev.additionalNotes||'',
      ...(metadata.inputCount>0?{specs:{...spec.specs,plcInputs:metadata.inputCount}}:{}),
      ...(metadata.outputCount>0?{specs:{...spec.specs,plcOutputs:metadata.outputCount}}:{}),
      ...(metadata.motorCount>0?{specs:{...spec.specs,motorCount:metadata.motorCount}}:{})
    }:{}),
    scannedAt:Date.now()
  };
  const panels=[...(cpd.panels||[]).filter(p=>p.panelId!==panel.id),spec];
  // Merge new products
  const existingProds=cpd.products||[];
  const newProds=[...existingProds];
  categorizedBom.filter(r=>!r.isLaborRow&&r.partNumber).forEach(r=>{
    const pn=(r.partNumber||'').trim();
    if(!pn)return;
    const idx=newProds.findIndex(p=>p.partNumber===pn);
    if(idx>=0){newProds[idx]={...newProds[idx],seenCount:(newProds[idx].seenCount||1)+1,lastSeen:Date.now()};}
    else{newProds.push({partNumber:pn,description:r.description||'',manufacturer:r.manufacturer||'',category:r.cpdCategory||'Other',approvals:{ul:'',ce:'',csa:''},seenCount:1,lastSeen:Date.now()});}
  });
  await saveCPD(uid,{panels,products:newProds});
}
// Background product enrichment — looks up specs for parts without details
// Throttled: max 4 parts per session to avoid excessive API usage
let _enrichSessionCount=0;
async function enrichProductDetails(uid,partNumber,description,category){
  if(!_apiKey||_enrichSessionCount>=4)return;
  _enrichSessionCount++;
  try{
    const resp=await apiCall({
      max_tokens:300,
      messages:[{role:"user",content:`You are an industrial parts expert. For this part: "${partNumber}" (${description||'no description'}, category: ${category||'unknown'}), provide technical specifications.
Return ONLY valid JSON (no markdown):
{"voltageRating":"","currentRating":"","brand":"","series":"","ul":"yes/no/unknown","ce":"yes/no/unknown","csa":"yes/no/unknown","shortSpec":"one sentence description of what this part is and its key specs"}`}]
    });
    const raw=resp.content[0].text.replace(/```json|```/g,'').trim();
    const m=raw.match(/\{[\s\S]*\}/);
    if(!m)return;
    const specs=JSON.parse(m[0]);
    const cpd=await loadCPD(uid);
    const products=(cpd.products||[]).map(p=>p.partNumber===partNumber?{...p,
      manufacturer:specs.brand||p.manufacturer,
      approvals:{ul:specs.ul||'',ce:specs.ce||'',csa:specs.csa||''},
      voltageRating:specs.voltageRating||'',
      currentRating:specs.currentRating||'',
      shortSpec:specs.shortSpec||'',
      enriched:true,enrichedAt:Date.now()
    }:p);
    await saveCPD(uid,{products});
  }catch(e){}
}

// Keyword-based part categorizer
function categorizePart(partNumber,description){
  const t=((description||'')+(partNumber||'')).toLowerCase();
  if(/controllogix|compactlogix|micrologix|1756-l|1769-l|s7-\d{3}|plc.*cpu|cpu.*plc|processor.*module/.test(t))return'PLC Processor';
  if(/1756-[io]|1769-[io]|input.*module|output.*module|analog.*input|analog.*output|digital.*input|digital.*output|ai\d|ao\d|di\d|do\d|ib16|ob16|ia8|oa8/.test(t))return'PLC I/O Module';
  if(/\bvfd\b|variable.freq|powerflex|altivar|optidrive|micromaster|g120|g110|sv0/.test(t))return'VFD';
  if(/\bcontactor\b|iec.*motor|definite.purpose|dp.?contactor|100-[ccd]/.test(t))return'Contactor';
  if(/\brelay\b|ice\d|700-|750-|intermediate.relay|plug.in.relay|cr\d\d/.test(t))return'Relay';
  if(/mccb|molded.case|main.*breaker|hfd|hja|hjd|lal|main.*disconnect/.test(t))return'MCCB';
  if(/\bbreaker\b|ul.?489|qo\d|qob|hom|faz|c60n|miniature.circuit/.test(t))return'Circuit Breaker';
  if(/\bduct\b|wireway|panduit.*duct|wiring.duct|trunking/.test(t))return'Wire Duct';
  if(/din.?rail|ts.?35|top.hat|omega.rail|g-rail/.test(t))return'DIN Rail';
  if(/terminal|ptfix|sak\d|ut\d|pt \d|fence.*term|din.*term|terminal.*block/.test(t))return'Terminal Block';
  if(/enclosure.*heat|cabinet.*heat|strip.heat|ptc.heat|\bheater\b/.test(t))return'Heater';
  if(/air.cond|vortex|cooler|thermal.manag|cabinet.*cool/.test(t))return'Air Conditioner';
  if(/\bhorn\b|\bbeacon\b|\bsiren\b|\bstrobe\b|signal.tower|stack.?light|xvbc|k80l/.test(t))return'Horn/Beacon';
  if(/enclosure|nema.*\d|hoffman|rittal|junction.box|wireway.encl/.test(t))return'Enclosure';
  if(/\bhmi\b|panelview|pro-face|touch.*screen|operator.*interface|weintek/.test(t))return'HMI';
  if(/pilot.light|push.?button|selector|door.op|xb\d|800f|800h|illuminated/.test(t))return'Pilot Light/Operator';
  return'Other';
}

async function apiCall(body){
  if(!_apiKey)throw new Error("API key not set. Open Settings and add your Anthropic key.");
  const r=await fetch("https://api.anthropic.com/v1/messages",{
    method:"POST",
    headers:{"Content-Type":"application/json","x-api-key":_apiKey,"anthropic-version":"2023-06-01","anthropic-dangerous-direct-browser-access":"true"},
    body:JSON.stringify({model:"claude-opus-4-6",...body})
  });
  const d=await r.json();
  if(!r.ok){console.error("API ERROR:",r.status,d.error?.type,d.error?.message);throw new Error(d.error?.message||"API error");}
  return d.content?.[0]?.text||"";
}

async function parallelMap(items,fn,concurrency=4){
  const results=[];
  let idx=0;
  const workers=Array.from({length:Math.min(concurrency,items.length)},async()=>{
    while(idx<items.length){
      const i=idx++;
      results[i]=await fn(items[i],i);
    }
  });
  await Promise.all(workers);
  return results;
}

// ── BUSINESS CENTRAL API ──
async function bcGetCompanyId(){
  if(_bcCompanyId)return _bcCompanyId;
  if(!_bcToken)return null;
  try{
    const r=await fetch(`${BC_API_BASE}/companies?$filter=name eq '${BC_COMPANY_NAME}'`,{
      headers:{"Authorization":`Bearer ${_bcToken}`}
    });
    if(!r.ok)return null;
    const d=await r.json();
    const co=(d.value||[])[0];
    if(co)_bcCompanyId=co.id;
    return _bcCompanyId;
  }catch(e){console.warn("BC company lookup failed:",e);return null;}
}

async function bcFetchCompanyInfo(){
  const compId=await bcGetCompanyId();
  if(!compId||!_bcToken)return null;
  try{
    const r=await fetch(`${BC_API_BASE}/companies(${compId})`,{
      headers:{"Authorization":`Bearer ${_bcToken}`}
    });
    if(!r.ok)return null;
    const d=await r.json();
    const parts=[d.addressLine1,d.addressLine2].filter(Boolean);
    const cityLine=[d.city,d.state,d.postalCode].filter(Boolean).join(' ');
    if(cityLine)parts.push(cityLine);
    const address=parts.join(', ');
    const phone=d.phoneNumber||'';
    const name=d.name||'';
    const email=d.email||'';
    return{name,address,phone,email};
  }catch(e){console.warn("bcFetchCompanyInfo failed:",e);return null;}
}

async function bcGetJobGuid(jobNumber){
  const compId=await bcGetCompanyId();
  if(!compId||!_bcToken)throw new Error("Not connected to BC");
  const r=await fetch(`${BC_API_BASE}/companies(${compId})/projects?$filter=number eq '${encodeURIComponent(jobNumber)}'&$select=id,number`,{
    headers:{"Authorization":`Bearer ${_bcToken}`}
  });
  if(!r.ok)throw new Error(`BC job lookup failed: ${r.status}`);
  const d=await r.json();
  const job=(d.value||[])[0];
  if(!job)throw new Error(`BC project '${jobNumber}' not found`);
  return{compId,jobId:job.id};
}

// DECISION(v1.19.333): Sanitizes both expected and actual filenames before comparing.
// Drawing numbers like LCP-100/200/500 contain slashes that BC mangles on upload.
// Also uses flexible lineSuffix matching so old-format files are still found.
// Without this, the "Deleted — Re-Upload" warning fires permanently for panels with special chars.
async function bcCheckAttachmentExists(jobNumber,fileName){
  try{
    const {compId,jobId}=await bcGetJobGuid(jobNumber);
    const r=await fetch(`${BC_API_BASE}/companies(${compId})/projects(${jobId})/documentAttachments`,{
      headers:{"Authorization":`Bearer ${_bcToken}`}
    });
    if(!r.ok){console.log("BC_ATT_CHECK: fetch failed",r.status);return null;}
    const d=await r.json();
    const atts=d.value||[];
    console.log("BC_ATT_CHECK: looking for:",fileName);
    console.log("BC_ATT_CHECK: BC has",atts.length,"attachments:",atts.map(a=>a.fileName));
    const sanitize=s=>(s||"").toLowerCase().replace(/[\/\\:*?"<>|]/g,"-");
    const target=sanitize(fileName);
    const targetNoExt=target.replace(/\.pdf$/i,"");
    // Extract lineSuffix from filename for flexible matching (e.g. "- 100" pattern)
    const lineSuffixMatch=target.match(/- (\d{3,4})(?:\.pdf)?$/);
    const lineSuffix=lineSuffixMatch?lineSuffixMatch[1]:null;
    const found=atts.some(a=>{
      const f=sanitize(a.fileName);
      // Exact match or no-extension match (both sanitized)
      if(f===target||f===targetNoExt||f+".pdf"===target)return true;
      // Also try with .pdf appended
      if(f.replace(/\.pdf$/,"")+".pdf"===target)return true;
      // Flexible: any AS-QUOTED or APPROVED file with same lineSuffix for this project
      if(lineSuffix&&(f.includes("as-quoted")||f.includes("approved to produce"))&&f.includes("- "+lineSuffix))return true;
      return false;
    });
    console.log("BC_ATT_CHECK: found=",found);
    return found;
  }catch(e){console.log("BC_ATT_CHECK: error",e.message);return null;}
}

// DECISION(v1.19.374): Delete by fetching ALL attachments and matching client-side.
// BC $filter on fileName fails with special chars (&) and doesn't handle with/without .pdf extension.
async function bcDeleteAttachmentByName(jobNumber,targetFileName){
  if(!targetFileName)return;
  try{
    const {compId,jobId}=await bcGetJobGuid(jobNumber);
    const r=await fetch(`${BC_API_BASE}/companies(${compId})/projects(${jobId})/documentAttachments`,{headers:{"Authorization":`Bearer ${_bcToken}`}});
    if(!r.ok)return;
    const allAtts=(await r.json()).value||[];
    const target=(targetFileName||"").toLowerCase().replace(/\.pdf$/i,"");
    const atts=allAtts.filter(a=>{const f=(a.fileName||"").toLowerCase().replace(/\.pdf$/i,"");return f===target;});
    for(const a of atts){
      try{
        const dr=await fetch(`${BC_API_BASE}/companies(${compId})/projects(${jobId})/documentAttachments(${a.id})`,{
          method:"DELETE",headers:{"Authorization":`Bearer ${_bcToken}`,"If-Match":"*"}
        });
        if(dr.ok||dr.status===204)console.log("Deleted BC attachment:",a.fileName);
        else console.warn("Failed to delete BC attachment:",a.fileName,dr.status);
      }catch(e){console.warn("Delete attachment error:",a.fileName,e.message);}
    }
  }catch(e){console.warn("bcDeleteAttachmentByName error:",e.message);}
}

// DECISION(v1.19.334): Bulk cleanup runs after every drawing upload and quote upload.
// Prior bugs produced dozens of duplicate files in BC (bad filenames, re-uploads without deletion,
// old quote revisions not cleaned). This scans ALL attachments and removes: exact duplicates (keeps newest),
// superseded quote revisions, and known bad-name patterns (bare lineSuffix, NoDWG). Keeps files in keepFileNames.
async function bcCleanupDuplicateAttachments(jobNumber,keepFileNames=[]){
  if(!_bcToken||!jobNumber)return{deleted:0};
  try{
    const {compId,jobId}=await bcGetJobGuid(jobNumber);
    const r=await fetch(`${BC_API_BASE}/companies(${compId})/projects(${jobId})/documentAttachments`,{headers:{"Authorization":`Bearer ${_bcToken}`}});
    if(!r.ok)return{deleted:0};
    const atts=(await r.json()).value||[];
    if(!atts.length)return{deleted:0};
    const keepSet=new Set(keepFileNames.map(n=>(n||"").toLowerCase().replace(/\.pdf$/i,"")));
    // Group by fileName — keep newest (highest id or latest in list) of exact dupes
    const groups={};
    atts.forEach(a=>{const k=(a.fileName||"").toLowerCase();if(!groups[k])groups[k]=[];groups[k].push(a);});
    const toDelete=[];
    for(const [fname,copies] of Object.entries(groups)){
      if(copies.length>1){
        // Keep the last one (most recent), delete the rest
        copies.slice(0,-1).forEach(a=>toDelete.push(a));
      }
      // Delete old quote revisions (keep only the latest rev)
      // Pattern: [MTX-Qxxxxxx Rev NN] — if a higher rev exists, delete lower revs
      const revMatch=fname.match(/^\[mtx-q\d+\s+rev\s+(\d+)\]/);
      if(revMatch){
        const revNum=parseInt(revMatch[1]);
        const quoteBase=fname.replace(/rev\s+\d+/,"rev");
        // Check if a higher rev exists in the full attachment list
        const hasHigherRev=atts.some(a2=>{const f2=(a2.fileName||"").toLowerCase();const m2=f2.match(/^\[mtx-q\d+\s+rev\s+(\d+)\]/);return m2&&f2.replace(/rev\s+\d+/,"rev")===quoteBase&&parseInt(m2[1])>revNum;});
        if(hasHigherRev)copies.forEach(a=>{if(!toDelete.includes(a))toDelete.push(a);});
      }
      // Delete known bad patterns
      if(/^\d{3,4}\s*-\s*prj/i.test(fname)){copies.forEach(a=>{if(!toDelete.includes(a))toDelete.push(a);});}
      if(/nodwg/i.test(fname)&&/as-quoted/i.test(fname)){copies.forEach(a=>{if(!toDelete.includes(a))toDelete.push(a);});}
    }
    // Never delete files in the keep list
    const finalDelete=toDelete.filter(a=>!keepSet.has((a.fileName||"").toLowerCase().replace(/\.pdf$/i,"")));
    let deleted=0;
    for(const a of finalDelete){
      try{
        const dr=await fetch(`${BC_API_BASE}/companies(${compId})/projects(${jobId})/documentAttachments(${a.id})`,{
          method:"DELETE",headers:{"Authorization":`Bearer ${_bcToken}`,"If-Match":"*"}
        });
        if(dr.ok||dr.status===204){deleted++;console.log("CLEANUP: deleted",a.fileName);}
      }catch(e){}
    }
    console.log(`CLEANUP: removed ${deleted} of ${finalDelete.length} duplicates from ${jobNumber}`);
    return{deleted,total:finalDelete.length};
  }catch(e){console.warn("bcCleanupDuplicateAttachments error:",e.message);return{deleted:0};}
}

async function bcAttachPdfToJob(jobNumber,fileName,pdfArrayBuffer,previousFileName){
  const {compId,jobId}=await bcGetJobGuid(jobNumber);
  // Delete the previous rev drawing attachment by exact filename
  if(previousFileName)await bcDeleteAttachmentByName(jobNumber,previousFileName);
  // Step 1: create attachment record
  const cr=await fetch(`${BC_API_BASE}/companies(${compId})/projects(${jobId})/documentAttachments`,{
    method:"POST",
    headers:{"Authorization":`Bearer ${_bcToken}`,"Content-Type":"application/json"},
    body:JSON.stringify({fileName})
  });
  if(!cr.ok){const t=await cr.text();throw new Error(`BC attachment create failed (${cr.status}): ${t}`);}
  const att=await cr.json();
  const editLink=att["attachmentContent@odata.mediaEditLink"];
  if(!editLink)throw new Error("BC did not return mediaEditLink for attachment");
  const etag=att["@odata.etag"]||"*";
  // Step 2: upload binary content
  const ur=await fetch(editLink,{
    method:"PATCH",
    headers:{"Authorization":`Bearer ${_bcToken}`,"Content-Type":"application/pdf","If-Match":etag},
    body:pdfArrayBuffer
  });
  if(!ur.ok){const t=await ur.text();throw new Error(`BC attachment upload failed (${ur.status}): ${t}`);}
  return att;
}

async function bcAttachPdfQueued(jobNumber,fileName,pdfArrayBuffer,previousFileName){
  if(!_bcToken||!jobNumber){
    if(jobNumber&&fileName&&pdfArrayBuffer){
      try{
        const pdfBase64=btoa(String.fromCharCode(...new Uint8Array(pdfArrayBuffer)));
        bcEnqueue('attachPdf',{jobNumber,fileName,pdfBase64},`Attach "${fileName}" to BC project ${jobNumber}`);
      }catch(e){console.warn("Could not queue PDF attachment:",e);}
    }
    return;
  }
  try{
    await bcAttachPdfToJob(jobNumber,fileName,pdfArrayBuffer,previousFileName);
  }catch(e){
    if(!_bcToken&&jobNumber&&fileName&&pdfArrayBuffer){
      try{
        const pdfBase64=btoa(String.fromCharCode(...new Uint8Array(pdfArrayBuffer)));
        bcEnqueue('attachPdf',{jobNumber,fileName,pdfBase64},`Attach "${fileName}" to BC project ${jobNumber}`);
      }catch(e2){console.warn("Could not queue PDF attachment:",e2);}
    }else throw e;
  }
}

async function bcCopyProjectFromTemplate(fromProjectNumber, toProjectNumber){
  // BC v2.0 REST API does not expose projectTasks — use OData via published web services instead.
  // Requires a "JobTaskLines" page (Object ID 1002) published in BC Web Services.
  const allPages=await bcDiscoverODataPages();
  console.log("bcCopy: available OData pages:",allPages.join(", "));

  // Find a task page — common names: JobTaskLines, Job_Task_Lines, ProjectTaskLines
  const taskPage=allPages.find(n=>/job.?task|project.?task/i.test(n))||null;
  if(!taskPage){
    console.warn("bcCopy: No job task OData page found. Publish page 1002 (Job Task Lines) as a BC web service named 'JobTaskLines'.");
    return 0;
  }
  console.log(`bcCopy: using OData page "${taskPage}" for tasks`);

  // Read tasks from template via OData — BC OData field names use underscores
  const readUrl=`${BC_ODATA_BASE}/${taskPage}?$filter=Job_No eq '${encodeURIComponent(fromProjectNumber)}'`;
  const tr=await fetch(readUrl,{headers:{"Authorization":`Bearer ${_bcToken}`}});
  if(!tr.ok){console.warn(`bcCopy: task read failed (${tr.status})`);return 0;}
  const tasks=(await tr.json()).value||[];
  console.log(`bcCopy: ${tasks.length} tasks to copy from ${fromProjectNumber} → ${toProjectNumber}`);

  // Write each task to the new project via OData POST
  let copied=0;
  for(const task of tasks){
    const body={
      Job_No:toProjectNumber,
      Job_Task_No:task.Job_Task_No||task.jobTaskNumber||"",
      Description:task.Description||task.description||"",
      Job_Task_Type:task.Job_Task_Type||task.jobTaskType||"Posting"
    };
    if(task.Totaling||task.totaling)body.Totaling=task.Totaling||task.totaling;
    if(task.New_Page!=null)body.New_Page=task.New_Page;
    if(task.Indentation!=null)body.Indentation=task.Indentation||task.indentation||0;
    const r=await fetch(`${BC_ODATA_BASE}/${taskPage}`,{
      method:"POST",
      headers:{"Authorization":`Bearer ${_bcToken}`,"Content-Type":"application/json"},
      body:JSON.stringify(body)
    });
    if(r.ok){copied++;console.log(`bcCopy: task ${body.Job_Task_No} copied`);}
    else console.warn(`bcCopy: task ${body.Job_Task_No} failed (${r.status}):`,await r.text());
  }
  return copied;
}

async function bcCreatePanelTaskStructure(projectNumber, projectName, panels){
  // Creates the ARC-defined BC Job Task hierarchy for a new project.
  //
  // Numbering scheme:
  //   10000   = Project header (Begin-Total)             "{projectNumber} - {projectName}"
  //   20N00   = Panel N Begin-Total                      "{projectNumber}-{N*100} - {panelName}"
  //   20N10   = Panel N BOM / Drawing work (Posting)     "{projectNumber}-{N*100} Rev - - {panelName}"
  //             → Planning lines will be populated from BOM (future step)
  //             → Dwg Rev# will be tracked as an ARC panel field (future build-out)
  //   20N20   = Engineering / Design / Programming / Onsite Commissioning (Posting — future build-out)
  //   20N30   = ECO 1 for Panel N  ← created on-demand via bcAddEcoTask() (future build-out)
  //   20N31   = ECO 2 for Panel N  ← created on-demand
  //   ...up to 20N39 = ECO 10 for Panel N (10 ECO slots per panel)
  //   ECO tasks are NOT pre-created; only added when an ECO is created in ARC for a quote.
  //   20N99   = Panel N End-Total                        "TOTAL: {projectNumber}-{N*100} - {panelName}"
  //   99999   = Project End-Total                        "TOTAL: {projectNumber} - {projectName}"
  //
  // Panel index N is 1-based: Panel 1 → base 20100, Panel 2 → 20200, etc.

  const allPages=await bcDiscoverODataPages();
  const taskPage=allPages.find(n=>/^project.?task/i.test(n))||allPages.find(n=>/job.?task/i.test(n))||null;
  if(!taskPage){
    const msg=`No Project Task OData page found (available: ${allPages.join(", ")||"none"}). Publish BC web service page 1002 as 'ProjectTaskLines'.`;
    console.warn("bcCreatePanelTaskStructure:",msg);
    throw new Error(msg);
  }

  // Helper: build a task object using the given field-name prefix ("Project" or "Job")
  function makeTask(prefix,noVal,taskNoVal,desc,type,extra={}){
    return{[`${prefix}_No`]:noVal,[`${prefix}_Task_No`]:taskNoVal,Description:desc,[`${prefix}_Task_Type`]:type,...extra};
  }

  function buildTasks(prefix){
    const t=[];
    t.push(makeTask(prefix,projectNumber,"10000",`${projectNumber} - ${projectName}`,"Begin-Total"));
    for(let i=0;i<panels.length;i++){
      const n=i+1,base=20000+n*100,suffix=n*100;
      const beginNo=String(base),endNo=String(base+99),postingNo=String(base+10),engNo=String(base+20);
      const panelDesc=projectName||panels[i].drawingDesc||panels[i].name||`Panel ${n}`;
      const rev=panels[i].drawingRev||"-";
      const pfx=`${projectNumber}-${suffix}`;
      t.push(makeTask(prefix,projectNumber,beginNo,`${pfx} - ${panelDesc}`,"Begin-Total"));
      const pQty=panels[i].lineQty??1;
      t.push(makeTask(prefix,projectNumber,postingNo,`${panels[i].drawingNo||pfx} Rev ${rev} - ${panelDesc} [${pQty}]`,"Posting"));
      t.push(makeTask(prefix,projectNumber,engNo,`Engineering Design - ${panelDesc}`,"Posting"));
      t.push(makeTask(prefix,projectNumber,endNo,`TOTAL: ${pfx} - ${panelDesc}`,"End-Total",{Totaling:`${beginNo}..${endNo}`}));
    }
    t.push(makeTask(prefix,projectNumber,"99999",`TOTAL: ${projectNumber} - ${projectName}`,"End-Total",{Totaling:"10000..99999"}));
    return t;
  }

  // Probe: try first task with Project_ fields; auto-fall back to Job_ if BC rejects Project_No
  async function postTasks(prefix){
    const tasks=buildTasks(prefix);
    const taskNoField=`${prefix}_Task_No`;
    let created=0;
    for(const task of tasks){
      const r=await fetch(`${BC_ODATA_BASE}/${taskPage}`,{
        method:"POST",
        headers:{"Authorization":`Bearer ${_bcToken}`,"Content-Type":"application/json"},
        body:JSON.stringify(task)
      });
      if(r.ok){created++;console.log(`bcCreatePanelTaskStructure: task ${task[taskNoField]} created (${prefix}_No)`);}
      else{
        const txt=await r.text();
        if(created===0&&prefix==="Project"&&txt.includes("'Project_No' does not exist")){
          console.log("bcCreatePanelTaskStructure: Project_No rejected, retrying with Job_No");
          return postTasks("Job");
        }
        console.warn(`bcCreatePanelTaskStructure: task ${task[taskNoField]} failed (${r.status}):`,txt);
      }
    }
    return created;
  }

  console.log(`bcCreatePanelTaskStructure: using page '${taskPage}', probing with Project_No fields`);
  return postTasks("Project");
}

async function bcAddEcoTask(projectNumber, panelIndex, ecoNumber, panelName){
  // Adds a single ECO task line to BC for a specific panel.
  // Called on-demand when an ECO is created in ARC — NOT at project init.
  //
  // panelIndex : 1-based panel number (1 = Panel 1, 2 = Panel 2, …)
  // ecoNumber  : 1-based ECO number (1–10 supported; maps to slots 20N30–20N39)
  //
  // Task No. formula:  20{panelIndex}3{ecoNumber-1}
  //   Panel 1 ECO 1  → 20130,  ECO 2 → 20131, … ECO 10 → 20139
  //   Panel 2 ECO 1  → 20230,  ECO 2 → 20231, … ECO 10 → 20239
  //
  // Description: "ECO {ecoNumber} - Change Order for {panelName}"
  //
  // FUTURE BUILD-OUT: wire this to an "Add ECO" action in the ARC Quote view.
  // Store eco list on project (e.g. panel.ecos:[{number,description,status}]) and
  // call this function when a new ECO is saved.

  if(ecoNumber<1||ecoNumber>10)throw new Error(`ECO number must be 1–10 (got ${ecoNumber})`);
  const n=panelIndex;
  const base=20000+n*100;
  const taskNo=String(base+30+(ecoNumber-1)); // 20130, 20131, …

  const allPages=await bcDiscoverODataPages();
  const taskPage=allPages.find(p=>/^project.?task/i.test(p))||allPages.find(p=>/job.?task/i.test(p))||null;
  if(!taskPage)throw new Error("bcAddEcoTask: No project task OData page found");
  const useProj=taskPage&&/^project/i.test(taskPage);

  const body={
    [useProj?"Project_No":"Job_No"]:projectNumber,
    [useProj?"Project_Task_No":"Job_Task_No"]:taskNo,
    Description:`ECO ${ecoNumber} - Change Order for ${panelName}`,
    [useProj?"Project_Task_Type":"Job_Task_Type"]:"Posting",
    Indentation:2
  };
  const r=await fetch(`${BC_ODATA_BASE}/${taskPage}`,{
    method:"POST",
    headers:{"Authorization":`Bearer ${_bcToken}`,"Content-Type":"application/json"},
    body:JSON.stringify(body)
  });
  if(!r.ok)throw new Error(`bcAddEcoTask: task ${taskNo} failed (${r.status}): ${await r.text()}`);
  console.log(`bcAddEcoTask: ECO ${ecoNumber} task ${taskNo} created for panel ${panelIndex}`);
  return taskNo;
}

async function bcSyncPanelTaskDescriptions(projectNumber, panelIndex, panel, projectName){
  // PATCHes the description fields on the four task lines for a specific panel
  // (Begin-Total 20N00, Posting 20N10, Engineering 20N20, End-Total 20N99)
  // to match the current drawingDesc/drawingRev values.
  // Called automatically by bcSyncPanelPlanningLines to keep tasks in sync.
  const n=panelIndex;
  const suffix=n*100;
  const pfx=`${projectNumber}-${suffix}`;
  const panelDesc=projectName||panel.drawingDesc||panel.name||`Panel ${n}`;
  const rev=panel.drawingRev||"-";
  const base=20000+n*100;
  const pQty=panel.lineQty??1;
  const taskDescs={
    [String(base)]:    `${pfx} - ${panelDesc}`,
    [String(base+10)]: `${panel.drawingNo||pfx} Rev ${rev} - ${panelDesc} [${pQty}]`,
    [String(base+20)]: `Engineering Design - ${panelDesc}`,
    [String(base+99)]: `TOTAL: ${pfx} - ${panelDesc}`,
  };

  const allPages=await bcDiscoverODataPages();
  const taskPage=allPages.find(p=>/^project.?task/i.test(p))||allPages.find(p=>/job.?task/i.test(p))||null;
  if(!taskPage){console.warn("bcSyncPanelTaskDescriptions: no task page found");return;}
  // Probe field names
  let FP_NO="Project_No",FP_TASK_NO="Project_Task_No";
  {
    const pr=await fetch(`${BC_ODATA_BASE}/${taskPage}?$top=1`,{headers:{"Authorization":`Bearer ${_bcToken}`,"Accept":"application/json"}});
    if(pr.ok){const pd=await pr.json();const rec=(pd.value||[])[0];if(rec&&"Job_No"in rec&&!("Project_No"in rec)){FP_NO="Job_No";FP_TASK_NO="Job_Task_No";}}
  }
  for(const [taskNo,desc] of Object.entries(taskDescs)){
    const url=`${BC_ODATA_BASE}/${taskPage}(${FP_NO}='${encodeURIComponent(projectNumber)}',${FP_TASK_NO}='${encodeURIComponent(taskNo)}')`;
    const r=await fetch(url,{method:"PATCH",headers:{"Authorization":`Bearer ${_bcToken}`,"Content-Type":"application/json","If-Match":"*"},body:JSON.stringify({Description:desc})});
    if(r.ok){console.log(`bcSyncPanelTaskDescriptions: task ${taskNo} updated`);}
    else{const t=await r.text();console.warn(`bcSyncPanelTaskDescriptions: task ${taskNo} PATCH failed (${r.status}):`,t);}
  }
}

async function bcSyncPanelPlanningLines(projectNumber, panelIndex, panel, projectName){
  // Full sync of BC Job Planning Lines for task 20N10 (where N = panelIndex, 1-based).
  // Strategy: delete all existing lines for the task, then recreate from current ARC state.
  //
  // Line structure:
  //   10000  Billable / Item  "PROGRESS BILLING"   unit price = panel sell price, qty = panel.lineQty
  //   20000  Budget  / R0020  "ENGINEERING"         qty = 0 (not yet tracked in ARC — future build-out)
  //   30000  Budget  / R0020  "CUT"                 qty = CUT hours from ARC labor estimate
  //   40000  Budget  / R0020  "LAYOUT"              qty = LAYOUT hours from ARC labor estimate
  //   50000  Budget  / R0020  "WIRE"                qty = WIRE hours from ARC labor estimate
  //   60000+ Budget  / Item   BOM rows              starting at 60000, step 10000, non-labor non-crossed rows

  const n=panelIndex;
  const base=20000+n*100;
  const taskNo=String(base+10); // "20110", "20210", …
  const suffix=n*100;
  const pfx=`${projectNumber}-${suffix}`;

  // Discover Project Planning Lines OData page
  const allPages=await bcDiscoverODataPages();
  const planPage=allPages.find(p=>/^project.?planning/i.test(p))||allPages.find(p=>/job.?planning/i.test(p))||null;
  if(!planPage)throw new Error(`No Project Planning Lines OData page found (available: ${allPages.join(", ")||"none"}). Publish BC web service page 1007 as 'ProjectPlanningLines'.`);

  // Probe: GET one record to detect whether page uses Project_No or Job_No.
  // DECISION(v1.19.615): If the $top=1 probe returns 0 records (empty table), inspect
  // the OData $metadata endpoint as a secondary probe — it lists every property even when
  // no rows exist. Cache result per-session to avoid re-probing on every sync.
  let FP_NO="Project_No",FP_TASK_NO="Project_Task_No";
  if(!window._bcPlanFieldsCache)window._bcPlanFieldsCache={};
  const cacheKey=`${BC_ODATA_BASE}::${planPage}`;
  if(window._bcPlanFieldsCache[cacheKey]){
    FP_NO=window._bcPlanFieldsCache[cacheKey].FP_NO;
    FP_TASK_NO=window._bcPlanFieldsCache[cacheKey].FP_TASK_NO;
  }else{
    let detected=false;
    try{
      const probeUrl=`${BC_ODATA_BASE}/${planPage}?$top=1`;
      const pr=await fetch(probeUrl,{headers:{"Authorization":`Bearer ${_bcToken}`,"Accept":"application/json"}});
      if(pr.ok){
        const pd=await pr.json();
        const rec=(pd.value||[])[0];
        if(rec){
          if("Job_No"in rec&&!("Project_No"in rec)){FP_NO="Job_No";FP_TASK_NO="Job_Task_No";detected=true;}
          else if("Project_No"in rec){detected=true;}
        }
      }
    }catch(e){/* probe failed — fall through to metadata */}
    // Fallback: OData $metadata (XML describing the schema) lists properties even when no data rows exist.
    if(!detected){
      try{
        const metaUrl=`${BC_ODATA_BASE}/$metadata`;
        const mr=await fetch(metaUrl,{headers:{"Authorization":`Bearer ${_bcToken}`,"Accept":"application/xml"}});
        if(mr.ok){
          const xml=await mr.text();
          // Find the EntityType for this page and check its Property names
          const entityRe=new RegExp(`<EntityType Name="${planPage.replace(/[.*+?^${}()|[\\\]\\\\]/g,'\\\\$&')}"[\\\\s\\\\S]*?</EntityType>`);
          const m=xml.match(entityRe);
          const entityXml=m?m[0]:xml;
          if(/Name="Job_No"/.test(entityXml)&&!/Name="Project_No"/.test(entityXml)){
            FP_NO="Job_No";FP_TASK_NO="Job_Task_No";detected=true;
          }else if(/Name="Project_No"/.test(entityXml)){detected=true;}
        }
      }catch(e){/* metadata probe failed — keep defaults */}
    }
    window._bcPlanFieldsCache[cacheKey]={FP_NO,FP_TASK_NO,detected};
    console.log(`bcSyncPlanningLines: detected ${FP_NO}/${FP_TASK_NO} for '${planPage}'${detected?"":" (defaults — neither probe succeeded)"}`);
  }

  // Step 1: fetch existing planning lines for this task (for incremental sync)
  const filterUrl=`${BC_ODATA_BASE}/${planPage}?$filter=${FP_NO} eq '${encodeURIComponent(projectNumber)}' and ${FP_TASK_NO} eq '${encodeURIComponent(taskNo)}'`;
  const gr=await fetch(filterUrl,{headers:{"Authorization":`Bearer ${_bcToken}`}});
  const existingLines=gr.ok?(await gr.json()).value||[]:[];
  const existingByLineNo=Object.fromEntries(existingLines.map(l=>[l.Line_No,l]));

  // Step 2: build lines
  const today=new Date().toISOString().split('T')[0];
  const lines=[];

  // 10000 — Progress Billing (Billable)
  const sellPrice=computePanelSellPrice(panel);
  const lineQty=panel.lineQty??1;
  const panelDesc=projectName||panel.drawingDesc||panel.name||`Panel ${n}`;
  const rev=panel.drawingRev||"-";
  lines.push({[FP_NO]:projectNumber,[FP_TASK_NO]:taskNo,Line_No:10000,Planning_Date:panel.requestedShipDate||today,
    Line_Type:"Billable",Type:"Item",No:"PROGRESS BILLING",
    Description:`${panel.drawingNo||pfx} Rev ${rev} - ${panelDesc} [${lineQty}]`,
    Quantity:lineQty,Unit_Price:sellPrice,Location_Code:"MAIN"});

  // 20000 — Engineering (Budget, qty=0 until ARC tracks engineering hours)
  lines.push({[FP_NO]:projectNumber,[FP_TASK_NO]:taskNo,Line_No:20000,Planning_Date:today,
    Line_Type:"Budget",Type:"Resource",No:"R0020",Description:"ENGINEERING",
    Quantity:0,Unit_of_Measure_Code:"HR",Location_Code:"MAIN"});

  // Labor hours from ARC
  const laborEst=computeLaborEstimate(panel);
  const cutHrs=laborEst.lines.filter(l=>["Panel Holes","Side-Mounted Components"].includes(l.category)).reduce((s,l)=>s+l.hours,0);
  const layoutHrs=laborEst.lines.filter(l=>["Device Mounting","Duct & DIN Rail","Labels"].includes(l.category)).reduce((s,l)=>s+l.hours,0);
  const wireHrs=laborEst.lines.filter(l=>["Wire Time","Door Wiring"].includes(l.category)).reduce((s,l)=>s+l.hours,0);

  // DECISION(v1.19.429): Push rounded whole hours to BC — no Unit_Price. BC calculates cost
  // from R0020's configured rate × hours. Previously pushed fractional hours causing mismatch.
  // 30000 — CUT (multiply by lineQty like BOM items)
  lines.push({[FP_NO]:projectNumber,[FP_TASK_NO]:taskNo,Line_No:30000,Planning_Date:today,
    Line_Type:"Budget",Type:"Resource",No:"R0020",Description:"CUT",
    Quantity:Math.ceil(cutHrs)*lineQty,Unit_of_Measure_Code:"HR",Location_Code:"MAIN"});

  // 40000 — LAYOUT
  lines.push({[FP_NO]:projectNumber,[FP_TASK_NO]:taskNo,Line_No:40000,Planning_Date:today,
    Line_Type:"Budget",Type:"Resource",No:"R0020",Description:"LAYOUT",
    Quantity:Math.ceil(layoutHrs)*lineQty,Unit_of_Measure_Code:"HR",Location_Code:"MAIN"});

  // 50000 — WIRE
  lines.push({[FP_NO]:projectNumber,[FP_TASK_NO]:taskNo,Line_No:50000,Planning_Date:today,
    Line_Type:"Budget",Type:"Resource",No:"R0020",Description:"WIRE",
    Quantity:Math.ceil(wireHrs)*lineQty,Unit_of_Measure_Code:"HR",Location_Code:"MAIN"});

  // 60000+ — ALL BOM items (non-labor; isCrossed rows ARE the replacement parts and must be included)
  const bomRows=(panel.bom||[]).filter(r=>!r.isLaborRow);
  let lineNo=60000;
  for(const row of bomRows){
    const desc=(row.description||"").slice(0,100);
    const fallbackDesc=`${row.partNumber||""} - ${(row.description||"").slice(0,90)}`.slice(0,100).trim();
    lines.push({[FP_NO]:projectNumber,[FP_TASK_NO]:taskNo,Line_No:lineNo,Planning_Date:today,
      Line_Type:"Budget",Type:"Item",No:row.partNumber,
      Description:desc,
      // DECISION(v1.19.462): Push Unit_Cost from ARC so BC planning lines reflect ARC's costing.
      // Unit_Price is NOT set (caused BC rejection errors on Budget/Item lines).
      Quantity:(row.qty||1)*lineQty,Unit_Cost:row.unitPrice||0,Location_Code:"MAIN",
      _row:row,
      _fallback:{[FP_NO]:projectNumber,[FP_TASK_NO]:taskNo,Line_No:lineNo,Planning_Date:today,
        Line_Type:"Budget",Type:"Text",
        Description:fallbackDesc,
        Quantity:(row.qty||1)*lineQty}});
    lineNo+=10000;
  }

  // Step 2b: Auto-fix items with missing Gen_Prod_Posting_Group (prevents sync failures)
  const bomParts=lines.filter(l=>l.Type==="Item"&&l.Line_No>=60000).map(l=>l.No).filter(Boolean);
  if(bomParts.length>0){
    for(const pn of bomParts){
      try{
        const chk=await fetch(`${BC_ODATA_BASE}/ItemCard?$filter=No eq '${encodeURIComponent(pn)}'&$select=No,Gen_Prod_Posting_Group,Inventory_Posting_Group`,{headers:{"Authorization":`Bearer ${_bcToken}`}});
        if(chk.ok){
          const rec=((await chk.json()).value||[])[0];
          if(rec){
            const patch={};
            if(!rec.Gen_Prod_Posting_Group)patch.Gen_Prod_Posting_Group="INVENTORY";
            if(!rec.Inventory_Posting_Group)patch.Inventory_Posting_Group="RAW MAT";
            if(Object.keys(patch).length){
              try{await bcPatchItemOData(pn,patch);console.log(`bcSyncPlanningLines: auto-fixed posting groups for ${pn}`);}catch(e){}
            }
          }
        }
      }catch(e){}
    }
  }

  // Step 3: Incremental sync — only add/update/delete what changed
  const sleep=ms=>new Promise(res=>setTimeout(res,ms));
  const failedRows=[];
  let created=0,updated=0,deleted=0,skipped=0;
  const desiredLineNos=new Set(lines.map(l=>l.Line_No));

  // DECISION(v1.19.615): Exponential-backoff retry (up to 3 attempts) on 429 Too Many Requests.
  // Was: single 2-s retry, which still left tens of failed lines on busy BC tenants. Also suppress
  // per-line 429 warnings — caller logs a summary of failures at the end.
  async function postLine(payload){
    for(let attempt=0;attempt<4;attempt++){
      const r=await fetch(`${BC_ODATA_BASE}/${planPage}`,{method:"POST",headers:{"Authorization":`Bearer ${_bcToken}`,"Content-Type":"application/json"},body:JSON.stringify(payload)});
      if(r.status!==429)return r;
      if(attempt===3)return r; // exhausted
      await sleep(1000*Math.pow(2,attempt)); // 1s, 2s, 4s
    }
  }
  async function patchLine(lineNo,fields,etag){
    const url=`${BC_ODATA_BASE}/${planPage}(${FP_NO}='${encodeURIComponent(projectNumber)}',${FP_TASK_NO}='${encodeURIComponent(taskNo)}',Line_No=${lineNo})`;
    for(let attempt=0;attempt<4;attempt++){
      const r=await fetch(url,{method:"PATCH",headers:{"Authorization":`Bearer ${_bcToken}`,"Content-Type":"application/json","If-Match":etag||"*"},body:JSON.stringify(fields)});
      if(r.status!==429)return r;
      if(attempt===3)return r;
      await sleep(1000*Math.pow(2,attempt));
    }
  }

  // Compare desired lines with existing — PATCH if changed, POST if new, skip if identical
  for(const line of lines){
    const {_fallback,_row,...payload}=line;
    const existing=existingByLineNo[line.Line_No];
    if(existing){
      // Check if anything changed — compare key fields
      const noChanged=existing.No!==(payload.No||"");
      const descChanged=existing.Description!==(payload.Description||"");
      const qtyChanged=Math.abs((existing.Quantity||0)-(payload.Quantity||0))>0.001;
      // DECISION(v1.19.462): Compare Unit_Price for Billable lines, Unit_Cost for Budget/Item lines.
      const isBillable=payload.Line_Type==="Billable";
      const priceChanged=isBillable&&"Unit_Price"in payload&&Math.abs((existing.Unit_Price||0)-(payload.Unit_Price||0))>0.001;
      const costChanged=!isBillable&&"Unit_Cost"in payload&&Math.abs((existing.Unit_Cost||0)-(payload.Unit_Cost||0))>0.001;
      if(!noChanged&&!descChanged&&!qtyChanged&&!priceChanged&&!costChanged){skipped++;continue;}
      // PATCH changed fields
      await sleep(300); // was 100 — slower to avoid BC rate limiting
      const patch={};
      if(noChanged)patch.No=payload.No||"";
      if(descChanged)patch.Description=payload.Description||"";
      if(qtyChanged)patch.Quantity=payload.Quantity||0;
      if(priceChanged)patch.Unit_Price=payload.Unit_Price||0;
      if(costChanged)patch.Unit_Cost=payload.Unit_Cost||0;
      const pr=await patchLine(line.Line_No,patch,existing["@odata.etag"]);
      // DECISION(v1.19.615): Suppress per-line console.log/warn — caller logs a summary at end.
      if(pr.ok||pr.status===204){updated++;}
      else{const txt=await pr.text();
        if(_row)failedRows.push({partNumber:_row.partNumber||"",description:_row.description||"",rowId:_row.id,lineNo:line.Line_No,error:txt});}
    }else{
      // New line — POST
      await sleep(300); // was 150 — slower to avoid BC rate limiting
      const r=await postLine(payload);
      if(r.ok){created++;}
      else if(_fallback){
        const txt=await r.text();
        await sleep(400);
        const r2=await postLine(_fallback);
        if(r2.ok){created++;}else{const txt2=await r2.text();if(_row)failedRows.push({partNumber:_row.partNumber||"",description:_row.description||"",rowId:_row.id,lineNo:line.Line_No,error:txt2});}
      }else{const txt=await r.text();if(_row)failedRows.push({partNumber:_row.partNumber||"",description:_row.description||"",rowId:_row.id,lineNo:line.Line_No,error:txt});}
    }
  }

  // Delete BC lines that are no longer in ARC (e.g. BOM rows removed)
  for(const ex of existingLines){
    if(!desiredLineNos.has(ex.Line_No)){
      await sleep(100);
      const delUrl=`${BC_ODATA_BASE}/${planPage}(${FP_NO}='${encodeURIComponent(projectNumber)}',${FP_TASK_NO}='${encodeURIComponent(taskNo)}',Line_No=${ex.Line_No})`;
      const dr=await fetch(delUrl,{method:"DELETE",headers:{"Authorization":`Bearer ${_bcToken}`,"If-Match":"*"}});
      if(dr.ok||dr.status===204){deleted++;console.log(`bcSyncPlanningLines: DELETED orphan line ${ex.Line_No}`);}
    }
  }

  console.log(`bcSyncPlanningLines: ${created} created, ${updated} updated, ${skipped} unchanged, ${deleted} deleted${failedRows.length?`, ${failedRows.length} FAILED`:""}`,failedRows);
  return{created,updated,skipped,deleted,total:lines.length,failed:failedRows};
}

async function bcCreateProject(displayName, customerNumber){
  if(!_bcToken)throw new Error("Not connected to Business Central");
  if(!customerNumber)throw new Error("A customer must be selected");
  const compId=await bcGetCompanyId();
  if(!compId)throw new Error("Could not resolve Business Central company");
  let projectId=null;
  try{
    // Step 1: Create project (name only)
    const r=await fetch(`${BC_API_BASE}/companies(${compId})/projects`,{
      method:"POST",
      headers:{"Authorization":`Bearer ${_bcToken}`,"Content-Type":"application/json"},
      body:JSON.stringify({displayName})
    });
    if(!r.ok){const txt=await r.text();throw new Error(`BC project creation failed (${r.status}): ${txt}`);}
    const d=await r.json();
    projectId=d.id;

    // Step 2: PATCH project defaults via OData (BC requires customer before task lines)
    // Ending_Date (customer requested ship date) is a future ARC field — not yet tracked.
    // Global_Dimension_1_Code = "Project Code" (custom dimension, integrator-added) = BC project number
    const today=new Date().toISOString().split('T')[0];
    const _patchFields={
      Bill_to_Customer_No:customerNumber,
      Global_Dimension_1_Code:d.number,
      Location_Code:"MAIN",
      Status:"Quote",
      Job_Posting_Group:"DEFAULT",
      Bin_Code:"PROJ-IN",
      WIP_Method:"COMPLETED CONTRACT",
      WIP_Posting_Method:"Per Project",
      Starting_Date:today
    };
    await bcPatchJobOData(d.number,_patchFields).then(()=>{
      console.log("bcCreateProject: Project Code dimension (Global_Dimension_1_Code) set to",d.number);
    }).catch(e=>{
      if(!_bcToken)bcEnqueue('patchJob',{projectNumber:d.number,fields:_patchFields},`Update BC project ${d.number}`);
      else throw e;
    });

    // Step 3: Panel task structure is created by the caller (bcCreatePanelTaskStructure) after panels are known
    return{id:d.id,number:d.number,displayName:d.displayName,customerNumber:customerNumber,customerName:null};
  }catch(e){
    // Rollback: delete the BC project if it was created
    if(projectId){
      try{
        const g=await fetch(`${BC_API_BASE}/companies(${compId})/projects(${projectId})`,{headers:{"Authorization":`Bearer ${_bcToken}`}});
        if(g.ok){
          const etag=g.headers.get("ETag");
          await fetch(`${BC_API_BASE}/companies(${compId})/projects(${projectId})`,{method:"DELETE",headers:{"Authorization":`Bearer ${_bcToken}`,"If-Match":etag||"*"}});
          console.log("bcCreateProject: rolled back BC project",projectId);
        }
      }catch(re){console.warn("bcCreateProject: rollback failed",re);}
    }
    throw e;
  }
}

async function bcLoadAllCustomers(){
  // Load all customers once — filtered client-side for case-insensitive search
  if(!_bcToken)return[];
  const compId=await bcGetCompanyId();
  if(!compId)return[];
  try{
    const r=await fetch(`${BC_API_BASE}/companies(${compId})/customers?$top=500&$orderby=displayName`,{headers:{"Authorization":`Bearer ${_bcToken}`}});
    if(r.status===401){_bcToken=null;return[];}
    if(!r.ok){console.warn("bcLoadAllCustomers failed:",r.status);return[];}
    const d=await r.json();
    return(d.value||[]).map(r=>({number:r.number||"",displayName:r.displayName||""}));
  }catch(e){console.warn("bcLoadAllCustomers error:",e);return[];}
}

async function bcLoadAllProjects(){
  if(!_bcToken)return[];
  const compId=await bcGetCompanyId();
  if(!compId)return[];
  try{
    const r=await fetch(`${BC_API_BASE}/companies(${compId})/projects?$top=1000`,{headers:{"Authorization":`Bearer ${_bcToken}`}});
    if(r.status===401){_bcToken=null;return[];}
    if(!r.ok){console.warn("bcLoadAllProjects failed:",r.status);return[];}
    const d=await r.json();
    return(d.value||[]);
  }catch(e){console.warn("bcLoadAllProjects error:",e);return[];}
}
async function bcLoadAllProjectsOData(){
  // Fetches project cards from OData which includes Bill_to_Customer_No, Bill_to_Name etc.
  if(!_bcToken)return[];
  try{
    const allPages=await bcDiscoverODataPages();
    const projectPage=allPages.find(n=>/^project(card)?$/i.test(n))||null;
    if(!projectPage){console.warn("bcLoadAllProjectsOData: no project OData page found");return[];}
    const r=await fetch(`${BC_ODATA_BASE}/${projectPage}`,{headers:{"Authorization":`Bearer ${_bcToken}`}});
    if(!r.ok){console.warn("bcLoadAllProjectsOData failed:",r.status);return[];}
    const d=await r.json();
    console.log("OData project fields:",(d.value||[])[0]?Object.keys((d.value||[])[0]):[])
    return(d.value||[]);
  }catch(e){console.warn("bcLoadAllProjectsOData error:",e);return[];}
}
function bcFilterCustomers(allCustomers,query){
  if(!query.trim())return allCustomers.slice(0,25);
  const q=query.trim().toLowerCase();
  return allCustomers.filter(c=>
    c.displayName.toLowerCase().includes(q)||c.number.toLowerCase().includes(q)
  ).slice(0,25);
}

async function bcCreateCustomer(displayName,phone,email){
  if(!_bcToken)throw new Error("Not connected to Business Central");
  const compId=await bcGetCompanyId();
  if(!compId)throw new Error("Could not resolve Business Central company");
  const body={displayName};
  if(phone)body.phoneNumber=phone;
  if(email)body.email=email;
  const r=await fetch(`${BC_API_BASE}/companies(${compId})/customers`,{
    method:"POST",
    headers:{"Authorization":`Bearer ${_bcToken}`,"Content-Type":"application/json"},
    body:JSON.stringify(body)
  });
  if(!r.ok){const txt=await r.text();throw new Error(`BC customer creation failed (${r.status}): ${txt}`);}
  const d=await r.json();
  return{number:d.number||"",displayName:d.displayName||displayName};
}

// DECISION(v1.19.349): Fetches contacts by customer code, not name. First gets the company Contact_No
// from BC Customer Card via OData (stable link by code), then fetches all person contacts under that
// company contact. Falls back to REST API customer displayName if OData lookup fails.
// This is stable even if the company name changes in BC.
async function bcFetchCustomerContacts(customerNumber){
  if(!_bcToken||!customerNumber)return[];
  try{
    const compId=await bcGetCompanyId();
    if(!compId)return[];
    // Step 1: Get the company contact number linked to this customer via OData Customer Card
    // DECISION(v1.19.352): Field is Primary_Contact_No (not Contact_No) on Customer_Card_Excel.
    // If empty, fall back to REST API displayName for contact lookup.
    // Company names with & must be URL-encoded in the $filter to avoid breaking the query.
    let companyContactNo="";let custName="";
    try{
      const allPages=await bcDiscoverODataPages();
      const custPage=allPages.find(n=>/^Customer_Card/i.test(n));
      if(custPage){
        const cr=await fetch(`${BC_ODATA_BASE}/${custPage}?$filter=No eq '${customerNumber}'&$select=No,Primary_Contact_No,Contact_No,Name&$top=1`,{headers:{"Authorization":`Bearer ${_bcToken}`}});
        if(cr.ok){const cd=((await cr.json()).value||[])[0];if(cd){companyContactNo=cd.Primary_Contact_No||cd.Contact_No||"";custName=cd.Name||"";}}
      }
    }catch(e){}
    // Fallback: REST API customer → use displayName
    if(!companyContactNo&&!custName){
      try{
        const cr=await fetch(`${BC_API_BASE}/companies(${compId})/customers?$filter=number eq '${customerNumber}'&$select=number,displayName&$top=1`,{headers:{"Authorization":`Bearer ${_bcToken}`}});
        if(cr.ok){const cd=((await cr.json()).value||[])[0];if(cd)custName=cd.displayName||"";}
      }catch(e){}
    }
    // Step 2: Fetch contacts — by companyNumber (contact code) or companyName (fallback)
    // Build URL with proper encoding — company names may contain & which breaks query strings
    let filterParam="";
    if(companyContactNo){
      filterParam="$filter=companyNumber eq '"+companyContactNo+"'";
    }else if(custName){
      filterParam="$filter="+encodeURIComponent("companyName eq '"+custName.replace(/'/g,"''")+"'");
    }
    if(!filterParam){console.warn("bcFetchCustomerContacts: no filter for",customerNumber);return[];}
    const r=await fetch(`${BC_API_BASE}/companies(${compId})/contacts?${filterParam}&$select=number,displayName,email,phoneNumber,companyName,type&$top=50&$orderby=displayName`,{
      headers:{"Authorization":`Bearer ${_bcToken}`}
    });
    if(!r.ok){console.warn("bcFetchCustomerContacts failed:",r.status);return[];}
    const d=await r.json();
    return(d.value||[]).filter(c=>c.type==="Person"||(c.displayName&&c.displayName!==c.companyName)).map(c=>({
      number:c.number||"",displayName:c.displayName||"",email:c.email||"",phone:c.phoneNumber||"",companyName:c.companyName||""
    }));
  }catch(e){console.warn("bcFetchCustomerContacts error:",e);return[];}
}

// DECISION(v1.19.362): bcCreateContact resolves the company contact number (CT######) from the
// customer number (C#####) before creating. BC contacts API's companyNumber field expects the
// company-type contact number, not the customer number. Without this, contacts are created
// but not linked to the company card.
async function bcCreateContact(displayName,customerNumber,email,phone){
  if(!_bcToken)throw new Error("Not connected to Business Central");
  const compId=await bcGetCompanyId();
  if(!compId)throw new Error("Could not resolve BC company");
  // Resolve company contact number from customer number
  let companyContactNo="";
  try{
    const allPages=await bcDiscoverODataPages();
    const custPage=allPages.find(n=>/^Customer_Card/i.test(n));
    if(custPage){
      const cr=await fetch(`${BC_ODATA_BASE}/${custPage}?$filter=No eq '${customerNumber}'&$select=No,Primary_Contact_No,Contact_No&$top=1`,{headers:{"Authorization":`Bearer ${_bcToken}`}});
      if(cr.ok){const cd=((await cr.json()).value||[])[0];if(cd)companyContactNo=cd.Primary_Contact_No||cd.Contact_No||"";}
    }
  }catch(e){}
  // Fallback: find the company-type contact by customer name
  if(!companyContactNo){
    try{
      const cr=await fetch(`${BC_API_BASE}/companies(${compId})/customers?$filter=number eq '${customerNumber}'&$select=number,displayName&$top=1`,{headers:{"Authorization":`Bearer ${_bcToken}`}});
      if(cr.ok){
        const cust=((await cr.json()).value||[])[0];
        if(cust?.displayName){
          const filterParam="$filter="+encodeURIComponent("companyName eq '"+cust.displayName.replace(/'/g,"''")+"' and type eq 'Company'");
          const ccr=await fetch(`${BC_API_BASE}/companies(${compId})/contacts?${filterParam}&$select=number&$top=1`,{headers:{"Authorization":`Bearer ${_bcToken}`}});
          if(ccr.ok){const ccd=((await ccr.json()).value||[])[0];if(ccd)companyContactNo=ccd.number||"";}
        }
      }
    }catch(e){}
  }
  if(!companyContactNo)console.warn("bcCreateContact: could not resolve company contact number for customer",customerNumber);
  const body={displayName,type:"Person"};
  if(companyContactNo)body.companyNumber=companyContactNo;
  // Sanitize email — trim whitespace, remove trailing @/dots, validate format
  const cleanEmail=(email||"").trim().replace(/@+$/,"").replace(/\.+$/,"");
  if(cleanEmail&&/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(cleanEmail))body.email=cleanEmail;
  else if(cleanEmail)console.warn("bcCreateContact: invalid email skipped:",cleanEmail);
  if(phone)body.phoneNumber=phone;
  const r=await fetch(`${BC_API_BASE}/companies(${compId})/contacts`,{
    method:"POST",
    headers:{"Authorization":`Bearer ${_bcToken}`,"Content-Type":"application/json"},
    body:JSON.stringify(body)
  });
  if(!r.ok){const txt=await r.text();throw new Error(`BC contact creation failed (${r.status}): ${txt}`);}
  const d=await r.json();
  return{number:d.number||"",displayName:d.displayName||displayName,email:d.email||email||"",phone:d.phoneNumber||phone||""};
}

async function bcCreateVendor(displayName,phone,email,opts={}){
  if(!_bcToken)throw new Error("Not connected to Business Central");
  const compId=await bcGetCompanyId();
  if(!compId)throw new Error("Could not resolve Business Central company");
  const body={displayName};
  if(phone)body.phoneNumber=phone;
  if(email)body.email=email;
  const r=await fetch(`${BC_API_BASE}/companies(${compId})/vendors`,{
    method:"POST",
    headers:{"Authorization":`Bearer ${_bcToken}`,"Content-Type":"application/json"},
    body:JSON.stringify(body)
  });
  if(!r.ok){const txt=await r.text();throw new Error(`BC vendor creation failed (${r.status}): ${txt}`);}
  const d=await r.json();
  const vendorNo=d.number||"";
  // Patch posting groups via OData if provided
  if(vendorNo&&(opts.genBusPostGroup||opts.vendorPostGroup||opts.taxAreaCode)){
    try{
      const patch={};
      if(opts.genBusPostGroup)patch.Gen_Bus_Posting_Group=opts.genBusPostGroup;
      if(opts.vendorPostGroup)patch.Vendor_Posting_Group=opts.vendorPostGroup;
      if(opts.taxAreaCode)patch.Tax_Area_Code=opts.taxAreaCode;
      const gr=await fetch(`${BC_ODATA_BASE}/Vendor_Card_Excel?$filter=No eq '${vendorNo}'`,{headers:{"Authorization":`Bearer ${_bcToken}`}});
      if(gr.ok){const gd=await gr.json();const rec=(gd.value||[])[0];
        if(rec){const etag=rec["@odata.etag"]||"*";
          await fetch(`${BC_ODATA_BASE}/Vendor_Card_Excel('${vendorNo}')`,{method:"PATCH",headers:{"Authorization":`Bearer ${_bcToken}`,"Content-Type":"application/json","If-Match":etag},body:JSON.stringify(patch)});
        }
      }
    }catch(e){console.warn("Vendor posting group patch failed:",e.message);}
  }
  return{number:vendorNo,displayName:d.displayName||displayName};
}

async function bcDeleteProject(bcProjectId){
  if(!_bcToken||!bcProjectId)throw new Error("Not connected to Business Central");
  const compId=await bcGetCompanyId();
  if(!compId)throw new Error("Could not resolve Business Central company");
  const g=await fetch(`${BC_API_BASE}/companies(${compId})/projects(${bcProjectId})`,{headers:{"Authorization":`Bearer ${_bcToken}`}});
  if(!g.ok)throw new Error(`BC project not found (${g.status})`);
  const etag=g.headers.get("ETag");
  const d=await fetch(`${BC_API_BASE}/companies(${compId})/projects(${bcProjectId})`,{
    method:"DELETE",
    headers:{"Authorization":`Bearer ${_bcToken}`,"If-Match":etag||"*"}
  });
  if(!d.ok)throw new Error(`BC delete failed (${d.status}): ${await d.text()}`);
}

async function bcUpdateProject(bcProjectId, displayName){
  if(!bcProjectId)return false;
  if(!_bcToken){_bcToken=await acquireBcToken(false)||null;}
  if(!_bcToken){_bcToken=await acquireBcToken(true)||null;}
  if(!_bcToken)return false;
  const compId=await bcGetCompanyId();
  if(!compId)return false;
  try{
    const g=await fetch(`${BC_API_BASE}/companies(${compId})/projects(${bcProjectId})`,{
      headers:{"Authorization":`Bearer ${_bcToken}`}
    });
    if(g.status===401){_bcToken=await acquireBcToken(true)||null;if(!_bcToken)return false;}
    if(!g.ok){console.warn("bcUpdateProject GET failed:",g.status);return false;}
    const etag=g.headers.get("ETag");
    const r=await fetch(`${BC_API_BASE}/companies(${compId})/projects(${bcProjectId})`,{
      method:"PATCH",
      headers:{"Authorization":`Bearer ${_bcToken}`,"Content-Type":"application/json","If-Match":etag||"*"},
      body:JSON.stringify({displayName})
    });
    if(!r.ok){console.warn("bcUpdateProject PATCH failed:",r.status,await r.text());return false;}
    return true;
  }catch(e){console.warn("bcUpdateProject error:",e);return false;}
}

// DECISION(v1.19.684): BC DateFormula helpers. Item Card Lead_Time_Calculation and
// ItemVendorCatalog Lead_Time_Calculation are stored as "14D" / "2W" / "1M" / "1Y"
// (BC's DateFormula data type). Convert to days for ARC's integer leadTimeDays field
// and back for writeback to BC. See docs/superpowers/specs/2026-04-23-item-lead-times-design.md
function _bcDateFormulaToDays(f){
  if(!f)return null;
  const m=String(f).toUpperCase().replace(/^P/,"").match(/^(\d+)\s*([DWMY])$/);
  if(!m)return null;
  const n=+m[1], u=m[2];
  return u==="D"?n : u==="W"?n*7 : u==="M"?n*30 : u==="Y"?n*365 : null;
}
function _daysToBcDateFormula(days){
  if(days==null||days<=0)return "";
  return `${Math.round(days)}D`;
}

async function bcLookupItem(partNumber){
  if(!_bcToken||!partNumber||!partNumber.trim())return null;
  const compId=await bcGetCompanyId();
  if(!compId)return null;
  const pn=partNumber.trim().replace(/'/g,"''");
  try{
    const r=await fetch(`${BC_API_BASE}/companies(${compId})/items?$filter=number eq '${pn}'`,{
      headers:{"Authorization":`Bearer ${_bcToken}`}
    });
    if(!r.ok){console.warn("BC item lookup failed:",r.status);return null;}
    const d=await r.json();
    const item=(d.value||[])[0];
    if(!item||item.blocked)return null;
    // DECISION(v1.19.591): Preserve BC cost of 0 (don't coerce to null). An item that exists in
    // BC with zero cost still represents a real BC link — downstream callers should mark the row
    // priceSource="bc" and NOT fall back to AI. Use ?? so undefined becomes null but 0 stays 0.
    return{unitCost:item.unitCost??null,unitPrice:item.unitPrice??null,displayName:item.displayName||"",inventory:item.inventory||0,number:item.number||"",vendorNo:item.vendorNo||""};
  }catch(e){console.warn("BC item lookup error:",e);return null;}
}

// DECISION(v1.19.685): Read Lead_Time_Calculation from BC Item Card. The /items v2 API
// doesn't expose leadTimeCalculation by default, so we hit ItemCard OData. Returns
// parsed integer days or null.
async function bcLookupLeadTime(partNumber){
  if(!_bcToken||!partNumber||!partNumber.trim())return null;
  const pn=partNumber.trim().replace(/'/g,"''");
  try{
    const r=await fetch(`${BC_ODATA_BASE}/ItemCard?$filter=No eq '${encodeURIComponent(pn)}'&$select=No,Lead_Time_Calculation`,{
      headers:{"Authorization":`Bearer ${_bcToken}`}
    });
    if(!r.ok)return null;
    const d=await r.json();
    const row=(d.value||[])[0];
    return row?_bcDateFormulaToDays(row.Lead_Time_Calculation):null;
  }catch(e){console.warn("bcLookupLeadTime error:",e);return null;}
}

// DECISION(v1.19.691): Upsert ItemVendorCatalog with supplier-quoted lead time.
// Safeguards:
//   - partNumber must be non-blank (HARD REJECT — per user requirement)
//   - vendorNo must be resolved (skip if null)
//   - leadTimeDays must be > 0
// Always writes an audit entry to companies/{cid}/bcLeadTimeWrites regardless of outcome.
async function bcUpsertItemVendorLeadTime({partNumber,vendorNo,vendorName,vendorItemNo,leadTimeDays,projectId,uid,cid}){
  const auditEntry={
    writtenAt:Date.now(),
    writtenBy:uid,
    projectId:projectId||null,
    vendorNo:vendorNo||null,
    vendorName:vendorName||null,
    itemNo:partNumber||null,
    leadTimeDays:leadTimeDays||null,
    previousLeadTime:null,
    outcome:"failed",
    error:null,
  };
  // HARD REJECT guard — never write a blank partNumber to BC
  if(!partNumber||!String(partNumber).trim()){
    auditEntry.error="blank partNumber — HARD REJECT";
  }else if(!vendorNo){
    auditEntry.error="vendor_no not resolved — skipped";
  }else if(!leadTimeDays||leadTimeDays<=0){
    auditEntry.error="leadTimeDays must be > 0 — skipped";
  }else if(!_bcToken){
    auditEntry.error="BC not connected — skipped";
  }else{
    try{
      // DECISION(v1.19.697): Detect when BC Page 114 'ItemVendorCatalog' Web Service isn't
      // published at all — previously every attempt failed with a cryptic 404. Now we check
      // the OData service document once and return an actionable error telling the BC admin
      // to publish Page 114 as Web Service name 'ItemVendorCatalog'.
      const allPages=await bcDiscoverODataPages().catch(()=>[]);
      if(allPages.length>0&&!allPages.some(n=>/^ItemVendorCatalog$/i.test(n))){
        auditEntry.error="BC Web Service 'ItemVendorCatalog' (Page 114) is not published. BC admin must publish Page 114 with service name 'ItemVendorCatalog' before lead times can sync.";
        // Skip the rest of the try body
      } else {
      const pn=String(partNumber).trim().replace(/'/g,"''");
      const vn=String(vendorNo).trim().replace(/'/g,"''");
      // DECISION(v1.19.698): Page 114 'ItemVendorCatalog' uses legacy NAV.* metadata which
      // does NOT expose a SystemId property. Dropped SystemId from $select (previously
      // caused 400 BadRequest). PATCH uses the compound-key URL form, which BC accepts
      // once the service is actually published.
      const existing=await fetch(`${BC_ODATA_BASE}/ItemVendorCatalog?$filter=Item_No eq '${encodeURIComponent(pn)}' and Vendor_No eq '${encodeURIComponent(vn)}'&$select=Item_No,Vendor_No,Vendor_Item_No,Lead_Time_Calculation`,{
        headers:{"Authorization":`Bearer ${_bcToken}`,"Accept":"application/json"}
      });
      let existingRec=null,etag=null,odataId=null;
      if(existing.ok){
        const d=await existing.json();
        existingRec=(d.value||[])[0]||null;
        if(existingRec){
          auditEntry.previousLeadTime=_bcDateFormulaToDays(existingRec.Lead_Time_Calculation);
          etag=existingRec["@odata.etag"]||existing.headers.get("ETag")||null;
          odataId=existingRec["@odata.id"]||existingRec["@odata.editLink"]||null;
        }
      }else{
        auditEntry.error=`GET existing failed: ${existing.status} ${await existing.text().then(t=>t.slice(0,120)).catch(()=>'')}`;
      }
      if(!auditEntry.error){
        const body={
          Item_No:String(partNumber).trim(),
          Vendor_No:String(vendorNo).trim(),
          Lead_Time_Calculation:_daysToBcDateFormula(leadTimeDays),
        };
        if(vendorItemNo&&String(vendorItemNo).trim()&&String(vendorItemNo).trim()!==String(partNumber).trim()){
          body.Vendor_Item_No=String(vendorItemNo).trim();
        }
        if(existingRec){
          // DECISION(v1.19.698): Page 114 NAV.* type has no SystemId — compound-key URL is
          // the only way to address a specific record. @odata.id fallback kept for safety.
          const patchUrls=[];
          patchUrls.push(`${BC_ODATA_BASE}/ItemVendorCatalog(Item_No='${encodeURIComponent(pn)}',Vendor_No='${encodeURIComponent(vn)}')`);
          if(odataId&&!patchUrls.includes(odataId))patchUrls.push(odataId);
          let lastErr=null,ok=false;
          for(const u of patchUrls){
            try{
              const pr=await fetch(u,{
                method:"PATCH",
                headers:{"Authorization":`Bearer ${_bcToken}`,"Content-Type":"application/json","If-Match":etag||"*","Accept":"application/json"},
                body:JSON.stringify(body),
              });
              if(pr.ok){auditEntry.outcome="updated";ok=true;break;}
              const txt=await pr.text().then(t=>t.slice(0,160)).catch(()=>'');
              lastErr=`PATCH ${pr.status} @ ${u.replace(BC_ODATA_BASE,"")}: ${txt}`;
              // On 404, try next URL format; on other errors, bail fast
              if(pr.status!==404)break;
            }catch(e){lastErr=`PATCH exception: ${e.message||String(e)}`;break;}
          }
          if(!ok)auditEntry.error=lastErr||"PATCH failed";
        }else{
          const cr=await fetch(`${BC_ODATA_BASE}/ItemVendorCatalog`,{
            method:"POST",
            headers:{"Authorization":`Bearer ${_bcToken}`,"Content-Type":"application/json","Accept":"application/json"},
            body:JSON.stringify(body),
          });
          if(cr.ok){auditEntry.outcome="created";}
          else{auditEntry.error=`POST failed: ${cr.status} ${await cr.text().then(t=>t.slice(0,160)).catch(()=>'')}`;}
        }
      }
      } // close else branch for published-page check
    }catch(e){auditEntry.error=e.message||String(e);}
  }
  // Audit always writes — even skips are logged
  try{
    if(cid)await fbDb.collection(`companies/${cid}/bcLeadTimeWrites`).add(auditEntry);
  }catch(e){console.warn("bcLeadTimeWrites audit failed:",e);}
  return auditEntry;
}

// DECISION(v1.19.685): Per-vendor lead time from ItemVendorCatalog (Page 114). When a
// BOM row has a specific bcVendorNo, prefer this over the item-level default.
async function bcLookupItemVendorLeadTime(partNumber,vendorNo){
  if(!_bcToken||!partNumber||!vendorNo)return null;
  const pn=partNumber.trim().replace(/'/g,"''");
  const vn=String(vendorNo).trim().replace(/'/g,"''");
  if(!pn||!vn)return null;
  try{
    const r=await fetch(`${BC_ODATA_BASE}/ItemVendorCatalog?$filter=Item_No eq '${encodeURIComponent(pn)}' and Vendor_No eq '${encodeURIComponent(vn)}'&$select=Item_No,Vendor_No,Lead_Time_Calculation`,{
      headers:{"Authorization":`Bearer ${_bcToken}`}
    });
    if(!r.ok)return null;
    const d=await r.json();
    const row=(d.value||[])[0];
    return row?_bcDateFormulaToDays(row.Lead_Time_Calculation):null;
  }catch(e){console.warn("bcLookupItemVendorLeadTime error:",e);return null;}
}

async function bcLookupItems(bomItems){
  const result={};
  for(const row of bomItems){
    const pn=(row.partNumber||"").trim();
    if(!pn)continue;
    const item=await bcLookupItem(pn);
    if(item&&item.unitCost!=null){
      result[String(row.id)]={unitPrice:item.unitCost,source:"bc",bcDisplayName:item.displayName,bcInventory:item.inventory};
    }
  }
  return result;
}

// DECISION(v1.19.417): Filter out blocked items from all BC searches.
// Blocked items should never appear in ARC search results or BOM matching.
async function _bcFetchItems(compId,filter,top,skip){
  const blockedFilter=filter?`(${filter}) and blocked eq false`:`blocked eq false`;
  const url=`${BC_API_BASE}/companies(${compId})/items?$filter=${blockedFilter}&$top=${top}&$skip=${skip}&$orderby=number`;
  console.log("bcSearchItems URL:",url);
  const r=await fetch(url,{headers:{"Authorization":`Bearer ${_bcToken}`}});
  if(r.status===401){
    _bcToken=await acquireBcToken(false)||null;
    if(!_bcToken)return null;
    const r2=await fetch(url,{headers:{"Authorization":`Bearer ${_bcToken}`}});
    if(!r2.ok){_bcToken=null;return null;}
    const d2=await r2.json();
    return(d2.value||[]).map(item=>({number:item.number||"",displayName:item.displayName||"",unitCost:item.unitCost??null,unitPrice:item.unitPrice??null,inventory:item.inventory||0,lastModifiedDateTime:item.lastModifiedDateTime||"",vendorNo:item.vendorNo||""}));
  }
  if(!r.ok){console.warn("bcSearchItems failed:",r.status,await r.text());return null;}
  const d=await r.json();
  return(d.value||[]).map(item=>({
    number:item.number||"",displayName:item.displayName||"",
    unitCost:item.unitCost??null,unitPrice:item.unitPrice??null,
    inventory:item.inventory||0,lastModifiedDateTime:item.lastModifiedDateTime||"",vendorNo:item.vendorNo||""
  }));
}

// DECISION(v1.19.807): ItemCard OData v4 search — exposes Description_2, Search_Description,
// Vendor_Item_No, Common_Item_No that the standard /items REST endpoint hides. BC's native
// item list searches all of these; users searching "Network Switch" expect to find items
// where "Network" is in Description_2 or Vendor_Item_No while Description has just "Switch"
// or vice-versa. This function fetches ItemCard rows and maps them to the same shape the
// rest of ARC expects.
async function _bcFetchItemsViaItemCard(filter,top,skip){
  const blockedFilter=filter?`(${filter}) and Blocked eq false`:`Blocked eq false`;
  const url=`${BC_ODATA_BASE}/ItemCard?$filter=${blockedFilter}&$top=${top}&$skip=${skip}&$orderby=No`;
  console.log("bcSearchItems URL (ItemCard):",url);
  let r=await fetch(url,{headers:{"Authorization":`Bearer ${_bcToken}`}});
  if(r.status===401){
    _bcToken=await acquireBcToken(false)||null;
    if(!_bcToken)return null;
    r=await fetch(url,{headers:{"Authorization":`Bearer ${_bcToken}`}});
  }
  if(!r.ok){console.warn("bcSearchItems(ItemCard) failed:",r.status,await r.text());return null;}
  const d=await r.json();
  return(d.value||[]).map(item=>({
    // ItemCard uses BC field names (Pascal_Case with underscores). Map to the canonical
    // shape that ARC's UI expects: lowercase camelCase. displayName falls back to
    // Description_2 when Description is empty (the very case that motivated this switch).
    number:item.No||"",
    displayName:(item.Description||"").trim()||(item.Description_2||"").trim()||(item.Search_Description||"").trim(),
    unitCost:item.Unit_Cost??null,
    unitPrice:item.Unit_Price??null,
    inventory:item.Inventory||0,
    lastModifiedDateTime:item.Last_Date_Modified||"",
    vendorNo:item.Vendor_No||"",
    // Keep the raw text fields so multi-token client-side filtering can check them too.
    // Without this, an item whose only "switch" hit is in Vendor_Item_No would fail
    // client-side filtering after the primary "network" pass narrowed via Description.
    _desc2:item.Description_2||"",
    _searchDesc:item.Search_Description||"",
    _vendorItemNo:item.Vendor_Item_No||"",
    _commonItemNo:item.Common_Item_No||"",
    _mfrCode:item.Manufacturer_Code||""
  }));
}
// DECISION(v1.19.800): Reverted to BC-native search behavior. Synonym groups + semantic
// expansion (v1.19.797–.799) was over-engineered — it surfaced items the user did NOT
// type ("switch" returning selectors/disconnects/rotary), violated multi-term search
// intent, and didn't actually match BC's own item-search results. The simpler rule:
// substring AND across user-typed tokens, with relevance ranking that surfaces literal
// hits first. The synonym table is preserved (unused) in case we re-enable it as an
// opt-in "broader search" toggle later. The substring match already handles the user's
// fuzziness need: typing "net" matches "NETWORK" / "ETHERNET" / "MAGNET" via contains();
// "port" matches "PORT" / "PORTS" / "IMPORT" / "EXPORT". No semantic expansion needed.
// DECISION(v1.19.799): Synonym groups are now curated to avoid SHORT AMBIGUOUS TOKENS
// (≤3 chars unless completely unambiguous like "vfd"/"plc"/"hmi"). Substring contains()
// makes 2-3 letter tokens flood unrelated items: "ss" matches STAINLESS, "rot" matches
// ROTOR/PROTECT, "sel" matches WEASEL, "net" matches PLANET/MAGNET, "eth" matches METHOD.
// That flooding pushed legitimate hits past the page-50 cutoff. Whatever the user typed
// literally is also passed through as a strict-literal pass (see _andOnLiteral) so the
// exact word always surfaces even if its variants aren't in the synonym list.
const BC_SEARCH_SYNONYMS=[
  // Networking
  ["network","ntwk","netwk","ethernet","enet"],
  ["switch","swtch","selector","slctr","limit","lmsw","disconnect","disconn","dsconn","toggle","rotary"],
  ["port","ports"],
  ["hub","hubs"],
  ["router"],
  ["modem"],
  ["cable","cbl"],
  ["patch"],
  // Power / protection
  ["xfmr","transformer","xform"],
  ["breaker","brkr","mccb"],
  ["fuse","fuses"],
  ["relay","rly"],
  ["contactor","contctr"],
  ["overload","ovld"],
  ["surge","arrester"],
  // Drives / motors
  ["vfd","drive","inverter"],
  ["motor","mtr"],
  ["starter"],
  // PLC / control
  ["plc","controller","ctlr"],
  ["hmi","panelview","operator","display","screen"],
  ["module","modul","modular"],
  ["input","inputs"],
  ["output","outputs"],
  ["analog"],
  ["digital"],
  ["processor","logix"],
  ["chassis","rack"],
  // Terminals / wiring
  ["terminal","term"],
  ["block","blocks"],
  ["ground","gnd","grnd"],
  ["jumper"],
  ["lug","lugs"],
  ["wire","wiring","conductor"],
  ["duct","wireway","wirway","trough"],
  ["rail","rails"],
  ["marker","label","tag"],
  ["splice"],
  ["ferrule"],
  // Power supplies / UPS
  ["psu","supply"],
  ["ups","battery"],
  // Enclosures / mechanical
  ["enclosure","encl","cabinet","housing"],
  ["panel"],
  ["door","doors"],
  ["window","wndw"],
  ["fan","blower"],
  ["heater","htr"],
  ["light","lamp"],
  ["pushbutton","push"],
  ["pilot"],
  ["horn","alarm"],
  ["receptacle","recp","outlet"],
  // Voltage / freq references
  ["voltage","volts"],
  ["amp","amps","ampere"],
];
function _bcExpandToken(t){
  const low=t.toLowerCase();
  // DECISION(v1.19.798): Union ALL groups that contain this token, not just the first.
  // Many concepts overlap — "switch" is both in the SW group and historically the
  // SELECTOR group. Returning only the first match silently dropped the variants in
  // any later group. Now we union every group's variants when the token appears.
  const out=new Set([low]);
  for(const group of BC_SEARCH_SYNONYMS){
    if(group.includes(low))group.forEach(v=>out.add(v));
  }
  return Array.from(out);
}
async function bcSearchItems(query,{field="both",top=25,skip=0}={}){
  if(!query||query.trim().length<3)return{items:[],hasMore:false};
  // Auto-reacquire token if missing or recently cleared
  if(!_bcToken){_bcToken=await acquireBcToken(false)||null;}
  if(!_bcToken)return{items:[],hasMore:false};
  const compId=await bcGetCompanyId();
  if(!compId)return{items:[],hasMore:false};
  // DECISION(v1.19.592): Tokenize on whitespace OR comma so "DUCT COVER", "DUCT,COVER",
  // and "DUCT, COVER" all parse to two tokens.
  const rawTokens=query.trim().split(/[\s,]+/).map(t=>t.trim()).filter(t=>t.length>0);
  if(!rawTokens.length)return{items:[],hasMore:false};
  // DECISION(v1.19.803): Reverted v1.19.802's single cross-field query — BC OData's
  // /items endpoint does in fact reject `or` across distinct fields (the v1.19.592
  // comment was correct). Single-token "switch" returned 0 items because BC sent back
  // an error for `(contains(number,'switch') or contains(displayName,'switch'))`.
  // Back to two parallel queries that AND tokens within a single field, then merge.
  // Multi-token cases where words are split across fields are handled by an additional
  // per-token cross-field intersection pass below.
  const literalTokens=rawTokens.map(t=>t.replace(/'/g,"''"));
  function _andOn(fieldName){
    // DECISION(v1.19.806): No tolower() wrappers — BC SaaS items endpoint chokes on
    // tolower() in filter expressions (silent parser failure, returns 400 with confusing
    // "Blocked field" error pointing at *No*). BC's contains() is already case-insensitive
    // by default on this tenant's collation, so plain contains() works for mixed-case
    // descriptions ("Switch" matched by lowercase 'switch' returned 33 items in testing).
    return literalTokens.map(t=>`contains(${fieldName},'${t}')`).join(' and ');
  }
  try{
    if(field==="both"){
      // DECISION(v1.19.804): Pick the LONGEST token as the BC server-side filter (longer
      // tokens tend to be rarer, narrowing the candidate set). Fetch all items containing
      // that token in number OR displayName (two parallel queries since BC rejects
      // cross-field OR), then filter client-side for the remaining tokens. This guarantees
      // multi-token searches find items even when words are split across fields, and works
      // for any number of tokens without explosion of server queries.
      // DECISION(v1.19.807/808): Use ItemCard OData endpoint (not /items REST) so we can
      // search across Description, Description_2, Search_Description, No, Vendor_Item_No,
      // Common_Item_No, Manufacturer_Code — matching BC native's multi-field search.
      // DECISION(v1.19.808): BC's ItemCard rejects `OR` across distinct fields with
      //   501 "The 'OR' operator is not supported on distinct fields on an OData filter"
      // so we fire ONE QUERY PER FIELD in parallel and merge the unique numbers. This
      // costs N round-trips per primary token (one per searchable field) but BC SaaS
      // handles them cheaply in parallel. Fields that don't exist on this tenant's
      // ItemCard simply error out on their query and contribute 0 items — graceful
      // degradation, no need for a metadata probe.
      const primaryIdx=literalTokens.reduce((bestI,tok,i,arr)=>tok.length>arr[bestI].length?i:bestI,0);
      const primary=literalTokens[primaryIdx];
      const others=rawTokens.map(t=>t.toLowerCase()).filter((_,i)=>i!==primaryIdx);
      const PER_TOKEN_TOP=1000;
      const ITEM_CARD_FIELDS=["No","Description","Description_2","Search_Description","Vendor_Item_No","Common_Item_No","Manufacturer_Code"];
      const fetchedPerField=await Promise.all(
        ITEM_CARD_FIELDS.map(f=>_bcFetchItemsViaItemCard(`contains(${f},'${primary}')`,PER_TOKEN_TOP,0))
      );
      const candidates=new Map();
      for(const items of fetchedPerField){
        if(!items)continue;
        for(const it of items){if(it.number&&!candidates.has(it.number))candidates.set(it.number,it);}
      }
      // Filter client-side: every remaining token must appear in any text-bearing field.
      // DECISION(v1.19.807): Include Description_2, Search_Description, Vendor_Item_No,
      // Common_Item_No, Manufacturer_Code in the haystack so multi-token searches don't
      // miss items where one word lives in a different field than another.
      const merged=[];
      for(const item of candidates.values()){
        const haystack=[
          item.displayName||"",
          item.number||"",
          item._desc2||"",
          item._searchDesc||"",
          item._vendorItemNo||"",
          item._commonItemNo||"",
          item._mfrCode||""
        ].join(" \n ").toLowerCase();
        if(others.every(tok=>haystack.includes(tok)))merged.push(item);
      }
      // DECISION(v1.19.809): Sort matches BC native — alphabetical by item number,
      // ascending. Reverted v1.19.799 relevance ranking since users want ARC's
      // result order to mirror BC's items list exactly so they can compare side-by-side.
      merged.sort((a,b)=>(a.number||"").localeCompare(b.number||""));
      const hasMore=merged.length>top;
      console.log(`bcSearchItems: ${Math.min(merged.length,top)} items (literal AND of ${rawTokens.length} token${rawTokens.length>1?'s':''}, sorted by item number)`);
      return{items:merged.slice(0,top),hasMore};
    }
    const filter=field==="number"?_andOn('number'):_andOn('displayName');
    const all=await _bcFetchItems(compId,filter,top+1,skip);
    if(!all)return{items:[],hasMore:false};
    const hasMore=all.length>top;
    console.log("bcSearchItems results:",Math.min(all.length,top),"items");
    return{items:all.slice(0,top),hasMore};
  }catch(e){console.warn("bcSearchItems error:",e);return{items:[],hasMore:false};}
}

async function bcFuzzyLookup(partNumber){
  if(!_bcToken||!partNumber||!partNumber.trim())return{match:null,type:null,suggestions:[]};
  const pn=partNumber.trim();
  // 1. Exact match
  const exact=await bcLookupItem(pn);
  if(exact&&exact.unitCost!=null)return{match:exact,type:"exact",suggestions:[]};
  // 2. Stripped search — remove dashes, spaces, special chars
  const stripped=pn.replace(/[-\s\/\\.#_]+/g,"");
  if(stripped.length>=3){
    const r2=await bcSearchItems(stripped,{field:"number",top:10});
    if(r2.items.length===1)return{match:r2.items[0],type:"fuzzy",suggestions:[]};
    if(r2.items.length>1){
      const exactInResults=r2.items.find(it=>it.number.toUpperCase()===pn.toUpperCase());
      if(exactInResults)return{match:exactInResults,type:"exact",suggestions:[]};
      return{match:null,type:"fuzzy",suggestions:r2.items.slice(0,8)};
    }
  }
  // 3. Original as contains search
  if(pn.length>=3){
    const r3=await bcSearchItems(pn,{field:"number",top:10});
    if(r3.items.length===1)return{match:r3.items[0],type:"fuzzy",suggestions:[]};
    if(r3.items.length>1){
      const exactInResults=r3.items.find(it=>it.number.toUpperCase()===pn.toUpperCase());
      if(exactInResults)return{match:exactInResults,type:"exact",suggestions:[]};
      return{match:null,type:"fuzzy",suggestions:r3.items.slice(0,8)};
    }
  }
  // 4. Core substring — strip common prefixes/suffixes
  const core=pn.replace(/^(mtx|mat|mx|ms)[-\s]*/i,"").replace(/[-\s]*(rev[a-z0-9]*|v\d+)$/i,"").trim();
  if(core.length>=3&&core!==pn&&core!==stripped){
    const r4=await bcSearchItems(core,{field:"number",top:10});
    if(r4.items.length===1)return{match:r4.items[0],type:"fuzzy",suggestions:[]};
    if(r4.items.length>1)return{match:null,type:"fuzzy",suggestions:r4.items.slice(0,8)};
  }
  return{match:null,type:null,suggestions:[]};
}

async function bcCreateItem({number,displayName,unitCost,itemCategoryCode,baseUnitOfMeasureCode,vendorNo,genProdPostingGroup,inventoryPostingGroup,manufacturerCode}){
  if(!_bcToken)throw new Error("Not connected to Business Central");
  const compId=await bcGetCompanyId();
  if(!compId)throw new Error("Could not resolve BC company");
  const body={};
  if(number)body.number=number;
  if(displayName)body.displayName=displayName.slice(0,100);
  if(unitCost!=null&&unitCost!=="")body.unitCost=parseFloat(unitCost);
  if(itemCategoryCode)body.itemCategoryCode=itemCategoryCode;
  if(baseUnitOfMeasureCode)body.baseUnitOfMeasureCode=baseUnitOfMeasureCode;
  try{
    const r=await fetch(`${BC_API_BASE}/companies(${compId})/items`,{
      method:"POST",
      headers:{"Authorization":`Bearer ${_bcToken}`,"Content-Type":"application/json"},
      body:JSON.stringify(body)
    });
    if(r.status===401){_bcToken=null;throw new Error("BC session expired — please reconnect");}
    if(r.status===409||r.status===400){
      const txt=await r.text();
      if(/already exists|duplicate/i.test(txt))throw new Error(`Item "${number}" already exists in Business Central`);
      throw new Error(txt||`BC returned status ${r.status}`);
    }
    if(!r.ok){const txt=await r.text();throw new Error(txt||`BC returned status ${r.status}`);}
    const item=await r.json();
    // PATCH extra fields via OData ItemCard (v2.0 API doesn't expose these)
    if(item.number&&(vendorNo||genProdPostingGroup||inventoryPostingGroup||manufacturerCode)){
      const patch={};
      if(vendorNo)patch.Vendor_No=vendorNo;
      if(genProdPostingGroup)patch.Gen_Prod_Posting_Group=genProdPostingGroup;
      if(inventoryPostingGroup)patch.Inventory_Posting_Group=inventoryPostingGroup;
      if(manufacturerCode)patch.Manufacturer_Code=manufacturerCode.slice(0,10);
      // Also set Vendor_Item_No to the item number so BC knows the vendor's catalog number
      if(vendorNo)patch.Vendor_Item_No=item.number;
      // DECISION(v1.19.377): Wait 3s before first OData PATCH (newly created items need time to index).
      // Retry up to 3x with 4s delays. Previous 5x/2s pattern triggered BC rate limiter ("Too many error requests").
      let patchOk=false;
      await new Promise(r=>setTimeout(r,3000));
      for(let attempt=0;attempt<3;attempt++){
        if(attempt>0)await new Promise(r=>setTimeout(r,4000));
        try{await bcPatchItemOData(item.number,patch);patchOk=true;console.log("bcCreateItem: OData PATCH succeeded on attempt",attempt+1);break;}
        catch(ve){console.warn(`bcCreateItem: OData PATCH attempt ${attempt+1}/3:`,ve.message);}
      }
      if(!patchOk)console.error("bcCreateItem: OData PATCH failed after 3 attempts for",item.number);
    }
    return{number:item.number||"",displayName:item.displayName||"",unitCost:item.unitCost??null,unitPrice:item.unitPrice??null,inventory:item.inventory||0,lastModifiedDateTime:item.lastModifiedDateTime||"",vendorNo:vendorNo||""};
  }catch(e){
    if(e.message.includes("BC session expired")||e.message.includes("already exists"))throw e;
    console.warn("bcCreateItem error:",e);
    throw new Error("Failed to create item: "+e.message);
  }
}

// DECISION(v1.19.408): Validates data before pushing to BC — rejects empty part numbers,
// negative prices, and null values that could corrupt BC records.
async function bcPatchItemOData(itemNo,fields){
  if(!_bcToken||!itemNo?.trim()||!fields||!Object.keys(fields).length)return;
  // Validate fields before pushing
  if(fields.Unit_Cost!=null&&(isNaN(fields.Unit_Cost)||fields.Unit_Cost<0)){console.warn("bcPatchItemOData: rejected negative/NaN Unit_Cost for",itemNo);return;}
  if(fields.Unit_Price!=null&&(isNaN(fields.Unit_Price)||fields.Unit_Price<0)){console.warn("bcPatchItemOData: rejected negative/NaN Unit_Price for",itemNo);return;}
  // 1. GET the item from OData ItemCard to obtain ETag
  const filterUrl=`${BC_ODATA_BASE}/ItemCard?$filter=No eq '${encodeURIComponent(itemNo)}'`;
  const gr=await fetch(filterUrl,{headers:{"Authorization":`Bearer ${_bcToken}`}});
  if(!gr.ok){throw new Error(`OData ItemCard GET failed: ${gr.status}`);}
  const gd=await gr.json();
  const rec=(gd.value||[])[0];
  if(!rec){throw new Error(`Item not found via OData: ${itemNo}`);}
  const etag=rec["@odata.etag"];
  // 2. PATCH fields using the ETag
  const patchUrl=`${BC_ODATA_BASE}/ItemCard('${encodeURIComponent(itemNo)}')`;
  const pr=await fetch(patchUrl,{
    method:"PATCH",
    headers:{"Authorization":`Bearer ${_bcToken}`,"Content-Type":"application/json","If-Match":etag||"*"},
    body:JSON.stringify(fields)
  });
  if(!pr.ok){const txt=await pr.text();console.warn("OData PATCH failed:",pr.status,txt);throw new Error(`BC rejected: ${txt.slice(0,120)}`);}
  console.log("OData PATCH OK:",itemNo,"→",JSON.stringify(fields));
}

// Map short UoM codes to BC-standard codes
const BC_UOM_MAP={E:'EA',EA:'EA',PC:'PCS',PCS:'PCS',FT:'FT',M:'M',LB:'LB',KG:'KG',BX:'BOX',BOX:'BOX',RL:'ROLL',ROLL:'ROLL',PR:'PR',SET:'SET',PKG:'PKG',C:'C100',HR:'HOUR',HOUR:'HOUR'};
function bcNormalizeUom(uom){if(!uom)return'';const u=(uom||'').toUpperCase().trim();return BC_UOM_MAP[u]||u;}

// ── MANUFACTURER CODE MAP ──
// Maps free-text manufacturer names (from BOM AI extraction) → BC Manufacturer Code (Code[10])
// Add entries here as new manufacturers are encountered.
