// Reverse map: BC Manufacturer Code → display name (used for DigiKey MFR validation)
const BC_MFR_CODE_NAMES={
  'AB':'Allen-Bradley','SE':'Schneider Electric','SIEMENS':'Siemens','ABB':'ABB',
  'EATON':'Eaton','HOFFMAN':'Hoffman','RITTAL':'Rittal','HAMMOND':'Hammond',
  'SAGINAW':'Saginaw','PHX':'Phoenix Contact','WEIDMULLER':'Weidmuller',
  'TURCK':'Turck','OMRON':'Omron','PILZ':'Pilz','IDEC':'IDEC','PANDUIT':'Panduit',
  'BRADY':'Brady','HUBBELL':'Hubbell','LEVITON':'Leviton','BELDEN':'Belden',
  'LAPP':'Lapp','PF':'Pepperl+Fuchs','SICK':'Sick','KEYENCE':'Keyence',
  'AUTOMDIR':'Automation Direct','MURR':'Murr Elektronik','WAGO':'Wago',
  'LEUZE':'Leuze','COGNEX':'Cognex',
};

/**
 * Attempt to guess a BC Manufacturer Code from an item description.
 * More conservative than bcNormalizeMfrCode — only matches terms >= 4 chars
 * and only in the forward direction (description contains term).
 */
function bcGuessMfrFromDesc(desc){
  if(!desc||!desc.trim())return null;
  const s=desc.trim().toLowerCase();
  for(const entry of BC_MFR_MAP){
    for(const term of entry.terms){
      if(term.length>=4&&s.includes(term))return entry.code;
    }
  }
  return null;
}

/**
 * Fetch all BC items missing Manufacturer_Code, attempt to derive from Description,
 * and patch matching items via OData.
 * @param {function} progressCb - called with {phase, total, done, patched, skipped, errors}
 */
/**
 * Normalize a raw manufacturer string from BOM extraction to a BC Manufacturer Code.
 * Returns the Code[10] string, or null if no match found.
 * Unknown manufacturers are logged to Firestore for review.
 */
function bcNormalizeMfrCode(rawMfr,uid){
  if(!rawMfr||!rawMfr.trim())return null;
  const s=rawMfr.trim().toLowerCase();
  for(const entry of BC_MFR_MAP){
    for(const term of entry.terms){
      if(s.includes(term)||term.includes(s))return entry.code;
    }
  }
  // No match — log to Firestore review queue if uid available
  if(uid&&_appCtx?.uid){
    const path=`users/${_appCtx.uid}/config/unknownManufacturers`;
    fbDb.doc(path).set({records:firebase.firestore.FieldValue.arrayUnion({
      raw:rawMfr.trim(),firstSeen:Date.now()
    })},{merge:true}).catch(()=>{});
  }
  console.warn(`bcNormalizeMfrCode: no BC code for "${rawMfr}" — logged for review`);
  return null;
}

async function bcPushPurchasePrice(itemNo,vendorNo,unitCost,startingDate,uom){
  if(!_bcToken||!itemNo||!vendorNo)return{ok:true};
  try{
    const dateStr=startingDate?new Date(startingDate).toISOString().split('T')[0]:new Date().toISOString().split('T')[0];
    const bcUom=bcNormalizeUom(uom);
    // Discover the OData page name for Purchase Prices
    const allPages=await bcDiscoverODataPages();
    const ppPage=allPages.find(n=>/purchase.?price/i.test(n));
    if(!ppPage){console.warn("bcPushPurchasePrice: no PurchasePrices OData page found. Available pages:",allPages.join(', '));return{ok:false,reason:'no_page'};}
    const baseUrl=`${BC_ODATA_BASE}/${ppPage}`;
    // Check if record already exists for this item+vendor
    const filterUrl=`${baseUrl}?$filter=Item_No eq '${encodeURIComponent(itemNo)}' and Vendor_No eq '${encodeURIComponent(vendorNo)}'`;
    console.log("bcPushPurchasePrice: checking existing for",itemNo,vendorNo,"via",ppPage);
    const gr=await fetch(filterUrl,{headers:{"Authorization":`Bearer ${_bcToken}`,"Accept":"application/json"}});
    if(gr.ok){
      const gd=await gr.json();
      const existing=(gd.value||[])[0];
      if(existing){
        // DECISION(v1.19.634): Removed % sanity check. Per user: pricing decisions must be
        // driven by eligibility logic (only scrape when BC price is stale), not by ratio
        // heuristics that can be fooled by genuine price movements. The upstream fix is to
        // not call bcPushPurchasePrice with bad data in the first place — see runPricingOnPanel
        // eligibility filter which now respects BC PurchasePrices Starting_Date.
        // PATCH existing record
        const etag=existing["@odata.etag"];
        const patchBody={Direct_Unit_Cost:unitCost,Starting_Date:dateStr};
        if(bcUom)patchBody.Unit_of_Measure_Code=bcUom;
        const pr=await fetch(`${baseUrl}('${encodeURIComponent(existing.Item_No)}')`,{method:"PATCH",headers:{"Authorization":`Bearer ${_bcToken}`,"Content-Type":"application/json","If-Match":etag||"*"},body:JSON.stringify(patchBody)});
        if(pr.ok){console.log("bcPushPurchasePrice PATCH OK:",itemNo,vendorNo,unitCost,dateStr);return{ok:true};}
        const ptxt=await pr.text().catch(()=>"");
        console.warn("bcPushPurchasePrice PATCH failed:",pr.status,ptxt);
      }
    }
    // Create new record via OData POST
    const payload={Item_No:itemNo,Vendor_No:vendorNo,Starting_Date:dateStr,Direct_Unit_Cost:unitCost};
    if(bcUom)payload.Unit_of_Measure_Code=bcUom;
    console.log("bcPushPurchasePrice POST:",JSON.stringify(payload));
    const cr=await fetch(baseUrl,{method:"POST",headers:{"Authorization":`Bearer ${_bcToken}`,"Content-Type":"application/json"},body:JSON.stringify(payload)});
    if(cr.ok){console.log("bcPushPurchasePrice POST OK:",itemNo,vendorNo,unitCost,dateStr);return{ok:true};}
    const txt=await cr.text().catch(()=>"");
    console.warn("bcPushPurchasePrice POST failed:",cr.status,txt);
    // Detect "item not found" error
    if(txt.includes('cannot be found in the related table (Item)')){ return{ok:false,reason:'item_not_found',itemNo};}
    return{ok:false,reason:'post_failed'};
  }catch(e){console.warn("bcPushPurchasePrice error:",itemNo,e.message);return{ok:false,reason:'error'};}
}

// Batch-fetch Purchase Prices from BC for a list of part numbers
// Returns Map<partNumber, {vendorNo, directUnitCost, startingDate, uom}>
async function bcFetchPurchasePrices(partNumbers){
  if(!_bcToken||!partNumbers.length)return new Map();
  const allPages=await bcDiscoverODataPages();
  const ppPage=allPages.find(n=>/purchase.?price/i.test(n));
  if(!ppPage){console.warn("bcFetchPurchasePrices: no PurchasePrices OData page");return new Map();}
  const baseUrl=`${BC_ODATA_BASE}/${ppPage}`;
  const results=new Map();
  // Batch 30 items per request to stay within URL length limits
  const BATCH=30;
  for(let i=0;i<partNumbers.length;i+=BATCH){
    const batch=partNumbers.slice(i,i+BATCH);
    const filterClauses=batch.map(pn=>`Item_No eq '${pn.replace(/'/g,"''")}'`).join(' or ');
    const url=`${baseUrl}?$filter=${encodeURIComponent(filterClauses)}&$select=Item_No,Vendor_No,Direct_Unit_Cost,Starting_Date,Unit_of_Measure_Code`;
    try{
      const r=await fetch(url,{headers:{"Authorization":`Bearer ${_bcToken}`,"Accept":"application/json"}});
      if(!r.ok){console.warn("bcFetchPurchasePrices batch failed:",r.status);continue;}
      const d=await r.json();
      (d.value||[]).forEach(rec=>{
        const pn=rec.Item_No||'';
        const sd=rec.Starting_Date?new Date(rec.Starting_Date).getTime():0;
        const existing=results.get(pn);
        // Keep the record with the most recent Starting_Date
        if(!existing||sd>(existing.startingDate||0)){
          results.set(pn,{vendorNo:rec.Vendor_No||'',directUnitCost:rec.Direct_Unit_Cost||0,startingDate:sd||null,uom:rec.Unit_of_Measure_Code||''});
        }
      });
    }catch(e){console.warn("bcFetchPurchasePrices batch error:",e);}
  }
  console.log("[BC] Fetched Purchase Prices for",results.size,"of",partNumbers.length,"items");
  return results;
}

let _odataPageCache=null;
let _odataPagePromise=null;
async function bcDiscoverODataPages(){
  if(_odataPageCache)return _odataPageCache;
  if(_odataPagePromise)return _odataPagePromise;
  _odataPagePromise=_bcDiscoverODataPagesImpl();
  try{const r=await _odataPagePromise;if(r.length)_odataPageCache=r;return r;}
  finally{_odataPagePromise=null;}
}
async function _bcDiscoverODataPagesImpl(){
  if(!_bcToken)return[];
  const headers={"Authorization":`Bearer ${_bcToken}`,"Accept":"application/json"};
  const urls=[`${BC_ODATA_BASE}/`,`https://api.businesscentral.dynamics.com/v2.0/${BC_TENANT}/${BC_ENV}/ODataV4/`];
  for(const url of urls){
    try{
      const r=await fetch(url,{headers});
      if(!r.ok){console.warn("bcDiscoverODataPages",url,"→",r.status);continue;}
      const txt=await r.text();
      try{
        const d=JSON.parse(txt);
        const names=(d.value||[]).map(e=>e.name||e.url||"").filter(Boolean);
        if(names.length){
          console.log("bcDiscoverODataPages found at",url,":",names.join(", "));
          return names;
        }
        console.warn("bcDiscoverODataPages",url,"→ empty list, trying next");
      }catch(pe){console.warn("bcDiscoverODataPages JSON parse error at",url,":",pe.message);}
    }catch(e){console.warn("bcDiscoverODataPages error at",url,":",e.message);}
  }
  console.warn("bcDiscoverODataPages: all URLs returned empty");
  return[];
}

// Cache planning page metadata so repeated margin changes don't re-discover every time
let _planPageCache=null; // {planPage, FP_NO, FP_TASK_NO}
async function bcGetPlanPageMeta(){
  if(_planPageCache)return _planPageCache;
  const allPages=await bcDiscoverODataPages();
  const planPage=allPages.find(p=>/^project.?planning/i.test(p))||allPages.find(p=>/job.?planning/i.test(p))||null;
  if(!planPage)return null;
  let FP_NO="Project_No",FP_TASK_NO="Project_Task_No";
  try{
    const pr=await fetch(`${BC_ODATA_BASE}/${planPage}?$top=1`,{headers:{"Authorization":`Bearer ${_bcToken}`}});
    if(pr.ok){const pd=await pr.json();const rec=(pd.value||[])[0];if(rec&&"Job_No"in rec&&!("Project_No"in rec)){FP_NO="Job_No";FP_TASK_NO="Job_Task_No";}}
  }catch(e){}
  _planPageCache={planPage,FP_NO,FP_TASK_NO};
  return _planPageCache;
}

async function bcPatchProgressBillingLine(projectNumber,taskNo,unitPrice){
  if(!_bcToken||!projectNumber||!taskNo)return;
  const meta=await bcGetPlanPageMeta();
  if(!meta)return;
  const {planPage,FP_NO,FP_TASK_NO}=meta;
  const lineUrl=`${BC_ODATA_BASE}/${planPage}(${FP_NO}='${encodeURIComponent(projectNumber)}',${FP_TASK_NO}='${encodeURIComponent(taskNo)}',Line_No=10000)`;
  const gr=await fetch(lineUrl,{headers:{"Authorization":`Bearer ${_bcToken}`}});
  if(!gr.ok){console.warn("bcPatchProgressBilling: GET failed",gr.status);return;}
  const rec=await gr.json();
  const etag=rec["@odata.etag"];
  const pr=await fetch(lineUrl,{
    method:"PATCH",
    headers:{"Authorization":`Bearer ${_bcToken}`,"Content-Type":"application/json","If-Match":etag||"*"},
    body:JSON.stringify({Unit_Price:unitPrice})
  });
  if(!pr.ok){const t=await pr.text();console.warn("bcPatchProgressBilling: PATCH failed",pr.status,t);}
  else console.log("bcPatchProgressBilling: Unit_Price updated →",unitPrice,"for task",taskNo);
}

// DECISION(v1.19.446): Patch individual labor planning lines (CUT/LAYOUT/WIRE) in BC
// when user changes labor overrides in Panel Summary. Avoids full sync round-trip.
async function bcPatchLaborPlanningLines(projectNumber,panelIndex,panel){
  if(!_bcToken||!projectNumber||!panelIndex)return;
  const meta=await bcGetPlanPageMeta();
  if(!meta)return;
  const {planPage,FP_NO,FP_TASK_NO}=meta;
  const taskNo=String(20000+panelIndex*100+10);
  const lineQty=panel.lineQty??1;
  const laborEst=computeLaborEstimate(panel);
  const cutHrs=laborEst.lines.filter(l=>["Panel Holes","Side-Mounted Components"].includes(l.category)).reduce((s,l)=>s+l.hours,0);
  const layoutHrs=laborEst.lines.filter(l=>["Device Mounting","Duct & DIN Rail","Labels"].includes(l.category)).reduce((s,l)=>s+l.hours,0);
  const wireHrs=laborEst.lines.filter(l=>["Wire Time","Door Wiring"].includes(l.category)).reduce((s,l)=>s+l.hours,0);
  const patches=[
    {lineNo:30000,qty:Math.ceil(cutHrs)*lineQty,label:"CUT"},
    {lineNo:40000,qty:Math.ceil(layoutHrs)*lineQty,label:"LAYOUT"},
    {lineNo:50000,qty:Math.ceil(wireHrs)*lineQty,label:"WIRE"},
  ];
  for(const {lineNo,qty,label} of patches){
    try{
      const lineUrl=`${BC_ODATA_BASE}/${planPage}(${FP_NO}='${encodeURIComponent(projectNumber)}',${FP_TASK_NO}='${encodeURIComponent(taskNo)}',Line_No=${lineNo})`;
      const gr=await fetch(lineUrl,{headers:{"Authorization":`Bearer ${_bcToken}`}});
      if(!gr.ok){console.warn(`bcPatchLabor ${label}: GET failed`,gr.status);continue;}
      const rec=await gr.json();
      if(rec.Quantity===qty){console.log(`bcPatchLabor ${label}: already ${qty}, skip`);continue;}
      const etag=rec["@odata.etag"];
      const pr=await fetch(lineUrl,{
        method:"PATCH",
        headers:{"Authorization":`Bearer ${_bcToken}`,"Content-Type":"application/json","If-Match":etag||"*"},
        body:JSON.stringify({Quantity:qty})
      });
      if(!pr.ok){const t=await pr.text();console.warn(`bcPatchLabor ${label}: PATCH failed`,pr.status,t);}
      else console.log(`bcPatchLabor ${label}: Qty updated → ${qty} for task ${taskNo}`);
    }catch(e){console.warn(`bcPatchLabor ${label}: error`,e.message);}
  }
  // Also update Progress Billing sell price (line 10000) since labor cost changed
  const sellPrice=computePanelSellPrice(panel);
  await bcPatchProgressBillingLine(projectNumber,taskNo,sellPrice).catch(()=>{});
}

