async function bcPatchJobOData(jobNo,fields){
  if(!_bcToken||!jobNo?.trim()||!fields||!Object.keys(fields).length)return;
  // Discover published OData pages and find a project-related one
  const allPages=await bcDiscoverODataPages();
  // Match project card/header pages — common names: ProjectCard, JobCard, Project, Job
  const projectPage=allPages.find(n=>/^(project(card)?|job(card)?)$/i.test(n))||null;
  if(!projectPage){
    console.warn("BC OData published pages available:",allPages.join(", ")||"(none)");
    console.warn("bcPatchJobOData: No project OData page found — skipping defaults patch. Publish page 88 as 'ProjectCard' in BC Web Services (Settings → Web Services → New → Object Type: Page, Object ID: 88, Service Name: ProjectCard).");
    return; // non-fatal: project was already created, defaults can be set manually in BC
  }
  const pages=[projectPage];
  for(const page of pages){
    const filterUrl=`${BC_ODATA_BASE}/${page}?$filter=No eq '${encodeURIComponent(jobNo)}'`;
    const gr=await fetch(filterUrl,{headers:{"Authorization":`Bearer ${_bcToken}`}});
    if(gr.status===404)continue;
    if(!gr.ok){const txt=await gr.text();throw new Error(`OData ${page} GET failed (${gr.status}): ${txt}`);}
    const gd=await gr.json();
    const rec=(gd.value||[])[0];
    if(!rec)throw new Error(`Project '${jobNo}' not found in OData page '${page}'`);
    const etag=rec["@odata.etag"];
    const patchUrl=`${BC_ODATA_BASE}/${page}('${encodeURIComponent(jobNo)}')`;
    const pr=await fetch(patchUrl,{
      method:"PATCH",
      headers:{"Authorization":`Bearer ${_bcToken}`,"Content-Type":"application/json","If-Match":etag||"*"},
      body:JSON.stringify(fields)
    });
    if(!pr.ok){const txt=await pr.text();throw new Error(`OData ${page} PATCH failed (${pr.status}): ${txt}`);}
    console.log("OData PATCH on project",jobNo,"via",page,"→",JSON.stringify(fields));
    return;
  }
  throw new Error("Could not reach ProjectCard or Project OData page in Business Central.");
}

