async function bcCreatePurchaseQuote(vendorNo,vendorName,items){
  if(!_bcToken){
    bcEnqueue('createPurchaseQuote',{vendorNo,vendorName,items},`Create BC purchase quote for ${vendorName}`);
    return null;
  }
  try{
    // Discover OData pages for Purchase Quote Header and Lines
    const allPages=await bcDiscoverODataPages();
    console.log('BC PQ: available OData pages:',allPages.join(', '));
    const headerPage=allPages.find(n=>/purchase.?quote.?header|purch.?quote.?header/i.test(n))
      ||allPages.find(n=>/purchase.?quote/i.test(n)&&!/line/i.test(n))||null;
    const linePage=allPages.find(n=>/purchase.?quote.?line|purch.?quote.?line/i.test(n))||null;
    if(!headerPage){
      console.warn('BC PQ: No Purchase Quote OData page found. Publish BC web service: Page 49 as "PurchaseQuote" or Page 42 header/lines. Available pages:',allPages.join(', '));
      // Fall back to v2.0 API as last resort
      const compId=await bcGetCompanyId();
      if(!compId)return null;
      const quoteBody={buyFromVendorName:vendorName};
      if(vendorNo)quoteBody.vendorNumber=vendorNo;
      console.log('BC PQ: Trying v2.0 API fallback, body:',JSON.stringify(quoteBody));
      const qr=await fetch(`${BC_API_BASE}/companies(${compId})/purchaseQuotes`,{
        method:"POST",
        headers:{"Authorization":`Bearer ${_bcToken}`,"Content-Type":"application/json"},
        body:JSON.stringify(quoteBody)
      });
      if(!qr.ok){const errText=await qr.text();console.warn("BC PQ v2.0 create failed:",qr.status,errText);return null;}
      const quote=await qr.json();
      console.log('BC PQ: v2.0 created, number:',quote.number);
      return quote.number;
    }
    console.log('BC PQ: Using OData pages — header:',headerPage,'lines:',linePage||'(none)');
    // Probe header fields
    const probeR=await fetch(`${BC_ODATA_BASE}/${headerPage}?$top=1`,{headers:{"Authorization":`Bearer ${_bcToken}`,"Accept":"application/json"}});
    let headerFields=[];
    if(probeR.ok){const pd=await probeR.json();const rec=(pd.value||[])[0];if(rec)headerFields=Object.keys(rec);console.log('BC PQ: header fields:',headerFields.join(', '));}
    // Build header body — try common field names
    const hBody={};
    const vnField=headerFields.find(f=>/^Buy_from_Vendor_No$/i.test(f))||headerFields.find(f=>/vendor.*no/i.test(f))||'Buy_from_Vendor_No';
    if(vendorNo)hBody[vnField]=vendorNo;
    else if(vendorName){
      const vnameField=headerFields.find(f=>/^Buy_from_Vendor_Name$/i.test(f))||headerFields.find(f=>/vendor.*name/i.test(f));
      if(vnameField)hBody[vnameField]=vendorName;
    }
    console.log('BC PQ: POST',headerPage,'body:',JSON.stringify(hBody));
    const hr=await fetch(`${BC_ODATA_BASE}/${headerPage}`,{
      method:"POST",
      headers:{"Authorization":`Bearer ${_bcToken}`,"Content-Type":"application/json"},
      body:JSON.stringify(hBody)
    });
    if(!hr.ok){const errText=await hr.text();console.warn('BC PQ: header POST failed:',hr.status,errText);return null;}
    const header=await hr.json();
    const docNo=header.No||header.Document_No||header.no||header.number||null;
    console.log('BC PQ: Created header, Doc No:',docNo,'full response keys:',Object.keys(header).join(', '));
    if(!docNo){console.warn('BC PQ: header created but no document number found in response');return null;}
    // Add line items — try multiple approaches to discover the right field names
    if(items&&items.length>0){
      let lineFields=[];
      let linesAdded=false;
      // Approach 1: If we have a dedicated lines page, probe its fields
      if(linePage){
        // Try fetching metadata from root OData to discover entity fields
        try{
          const metaUrl=`https://api.businesscentral.dynamics.com/v2.0/${BC_TENANT}/${BC_ENV}/ODataV4/$metadata`;
          const metaR=await fetch(metaUrl,{headers:{"Authorization":`Bearer ${_bcToken}`}});
          if(metaR.ok){
            const metaText=await metaR.text();
            const entityMatch=metaText.match(new RegExp('EntityType Name="'+linePage+'"[\\s\\S]*?</EntityType>'));
            if(entityMatch){
              const propMatches=entityMatch[0].match(/Property Name="([^"]+)"/g)||[];
              lineFields=propMatches.map(function(m){return m.replace('Property Name="','').replace('"','')});
              console.log('BC PQ: line fields from $metadata:',lineFields.join(', '));
            }
          }else{console.log('BC PQ: $metadata returned',metaR.status,'- will try probe');}
        }catch(me){console.log('BC PQ: $metadata fetch failed:',me.message);}
        // Fallback: probe with $top=1
        if(!lineFields.length){
          const lineProbe=await fetch(`${BC_ODATA_BASE}/${linePage}?$top=1`,{headers:{"Authorization":`Bearer ${_bcToken}`,"Accept":"application/json"}}).catch(()=>null);
          if(lineProbe&&lineProbe.ok){const ld=await lineProbe.json();const rec=(ld.value||[])[0];if(rec){lineFields=Object.keys(rec);console.log('BC PQ: line fields from probe:',lineFields.join(', '));}}
          if(!lineFields.length)console.log('BC PQ: probe returned no records, no fields discovered');
        }
        if(lineFields.length){
          const docNoField=lineFields.find(f=>/^Document_No$/i.test(f));
          const docTypeField=lineFields.find(f=>/^Document_Type$/i.test(f));
          const typeField=lineFields.find(f=>/^Type$/i.test(f))||'Type';
          const noField=lineFields.find(f=>/^No$/i.test(f)&&!/line|doc/i.test(f))||'No';
          const qtyField=lineFields.find(f=>/^Quantity$/i.test(f))||'Quantity';
          const descField=lineFields.find(f=>/^Description$/i.test(f))||'Description';
          console.log('BC PQ: resolved line field names:',{docNoField,docTypeField,typeField,noField,qtyField,descField});
          for(const item of items){
            const lBody={[typeField]:'Item',[descField]:item.description||item.partNumber||'',[qtyField]:Number(item.qty)||1};
            if(docNoField)lBody[docNoField]=docNo;
            if(docTypeField)lBody[docTypeField]='Quote';
            if(item.partNumber)lBody[noField]=item.partNumber;
            console.log('BC PQ line POST body:',JSON.stringify(lBody));
            const lr=await fetch(`${BC_ODATA_BASE}/${linePage}`,{
              method:"POST",
              headers:{"Authorization":`Bearer ${_bcToken}`,"Content-Type":"application/json"},
              body:JSON.stringify(lBody)
            }).catch(e=>{console.warn('BC PQ line POST error:',e);return null;});
            if(lr&&!lr.ok){const t=await lr.text();console.warn('BC PQ line failed:',lr.status,t.slice(0,300));}
            else if(lr){console.log('BC PQ line added:',item.partNumber);linesAdded=true;}
          }
        }else{
          // No fields discovered — try minimal POST without doc fields (subform may auto-link)
          console.log('BC PQ: No fields discovered, trying minimal POST to',linePage);
          for(const item of items){
            const lBody={Type:'Item',Description:item.description||item.partNumber||'',Quantity:Number(item.qty)||1};
            if(item.partNumber)lBody.No=item.partNumber;
            const lr=await fetch(`${BC_ODATA_BASE}/${linePage}`,{
              method:"POST",
              headers:{"Authorization":`Bearer ${_bcToken}`,"Content-Type":"application/json"},
              body:JSON.stringify(lBody)
            }).catch(e=>{console.warn('BC PQ line minimal POST error:',e);return null;});
            if(lr&&!lr.ok){const t=await lr.text();console.warn('BC PQ line minimal failed:',lr.status,t.slice(0,300));}
            else if(lr){console.log('BC PQ line added (minimal):',item.partNumber);linesAdded=true;}
          }
        }
      }
      if(!linesAdded){console.log('BC PQ: Lines not added via OData, quote',docNo,'created as header only');}
    }
    return docNo;
  }catch(e){
    console.warn("bcCreatePurchaseQuote error:",e);
    if(!_bcToken){
      bcEnqueue('createPurchaseQuote',{vendorNo,vendorName,items},`Create BC purchase quote for ${vendorName}`);
    }
    return null;
  }
}

// ── BC OFFLINE QUEUE ──
const _BC_QUEUE_KEY='_arc_bc_queue';
function _bcQGet(){try{return JSON.parse(localStorage.getItem(_BC_QUEUE_KEY)||'[]');}catch(e){return[];}}
function _bcQSet(q){try{localStorage.setItem(_BC_QUEUE_KEY,JSON.stringify(q));}catch(e){}}
let _bcQueueCountSetter=null; // injected by React to update badge

function bcEnqueue(type,params,description){
  const q=_bcQGet();
  q.push({id:`${Date.now()}-${Math.random().toString(36).slice(2,7)}`,type,params,description,enqueuedAt:Date.now(),attempts:0});
  _bcQSet(q);
  console.log(`[BC Queue] Enqueued: ${description}`);
  if(_bcQueueCountSetter)_bcQueueCountSetter(q.length);
}

async function bcProcessQueue(){
  if(!_bcToken)return;
  const q=_bcQGet();
  if(!q.length)return;
  console.log(`[BC Queue] Processing ${q.length} pending item(s)…`);
  const remaining=[];
  for(const item of q){
    try{
      await _bcQueueExecute(item);
      console.log(`[BC Queue] Done: ${item.description}`);
    }catch(e){
      console.warn(`[BC Queue] Failed (attempt ${(item.attempts||0)+1}): ${item.description}`,e.message);
      const updated={...item,attempts:(item.attempts||0)+1,lastError:String(e.message||e)};
      if(updated.attempts<5)remaining.push(updated);
      else console.warn(`[BC Queue] Dropped after 5 attempts: ${item.description}`);
    }
  }
  _bcQSet(remaining);
  if(_bcQueueCountSetter)_bcQueueCountSetter(remaining.length);
}

async function _bcQueueExecute(item){
  switch(item.type){
    case 'createPurchaseQuote':{
      const{vendorNo,vendorName,items}=item.params;
      const num=await bcCreatePurchaseQuote(vendorNo,vendorName,items);
      console.log(`[BC Queue] Purchase quote created: ${num}`);
      break;
    }
    case 'attachPdf':{
      const{jobNumber,fileName,pdfBase64}=item.params;
      const arr=Uint8Array.from(atob(pdfBase64),c=>c.charCodeAt(0)).buffer;
      await bcAttachPdfToJob(jobNumber,fileName,arr);
      break;
    }
    case 'patchJob':{
      const{projectNumber,fields}=item.params;
      await bcPatchJobOData(projectNumber,fields);
      break;
    }
    case 'syncTaskDescs':{
      const{projectNumber,taskDescs}=item.params;
      await bcSyncPanelTaskDescriptions(projectNumber,taskDescs);
      break;
    }
    default:
      throw new Error(`Unknown queue type: ${item.type}`);
  }
}

const RFQ_STALE_MS=60*24*60*60*1000; // 60 days
async function buildRfqSupplierGroups(bom){
  const now=Date.now();
  const RFQ_EXCLUDE_ITEMS=/job\s*buy.?off|crating|^crate$/i;
  const RFQ_SENT_COOLDOWN=30*24*60*60*1000; // 30 days — don't re-send within this window
  // DECISION(v1.19.699): Track WHY each row was included so we can auto-enable the
  // "Lead Times Only" checkbox per vendor when the only issue is missing lead times.
  // Reasons: "missingPrice" | "stalePrice" | "missingLeadTime"
  function _eligibilityReason(r){
    if(r.isLaborRow||r.priceSource==="manual")return null;
    if(r.isContingency||CONTINGENCY_PNS.has((r.partNumber||"").trim().toUpperCase()))return null;
    if(RFQ_EXCLUDE_ITEMS.test(r.description||"")||RFQ_EXCLUDE_ITEMS.test(r.partNumber||""))return null;
    // DECISION(v1.19.704): 30-day RFQ cooldown applies ONLY to price-based inclusion.
    // Missing lead times are independent — a vendor may have recently quoted prices but
    // never returned lead times, or we may be iterating on RFQs during setup/testing.
    // Always allow missingLeadTime rows through regardless of rfqSentDate.
    const inCooldown=r.rfqSentDate&&(now-r.rfqSentDate)<RFQ_SENT_COOLDOWN;
    if(!inCooldown){
      if(!r.unitPrice||r.unitPrice===0)return "missingPrice";
      const isBC=r.priceSource==="bc"&&"bcPoDate"in r;
      const displayDate=isBC?r.bcPoDate:r.priceDate;
      if(!displayDate||displayDate<now-RFQ_STALE_MS)return "stalePrice";
    }
    // Lead-time-based inclusion — ALWAYS evaluated, regardless of cooldown.
    // DECISION(v1.19.815): AI-estimated lead times (leadTimeSource==="ai") are treated
    // as NOT FIRM and included in lead-time RFQs for supplier confirmation. Previously
    // only completely-null lead times were flagged. Real-world: a vendor's RFQ would
    // pull just the 1 row with no AI estimate at all, even though the other 7 rows had
    // unverified AI estimates that the supplier should also confirm. Firm sources are
    // the only ones we trust without re-asking: BC (bc_item / bc_vendor), Supplier
    // portal submission, manual entry, web scraper.
    const isFirmLT=r.leadTimeDays!=null&&r.leadTimeSource&&r.leadTimeSource!=="ai";
    if(!isFirmLT)return "missingLeadTime";
    return null;
  }
  const eligibleWithReasons=[];
  for(const r of bom){
    const reason=_eligibilityReason(r);
    if(reason){eligibleWithReasons.push({row:r,reason});}
  }
  if(!eligibleWithReasons.length)return{groups:[],noItems:true};
  // Group by vendor — use user-assigned bcVendorName first, then BC lookup
  const groupMap={};
  for(const {row:item,reason} of eligibleWithReasons){
    let vendorName=item.bcVendorName||"";
    let vendorNo=item.bcVendorNo||"";
    if(!vendorName&&_bcToken){
      const pn=(item.partNumber||"").trim();
      if(pn){vendorNo=vendorNo||await bcGetItemVendorNo(pn);vendorName=vendorNo?await bcGetVendorName(vendorNo):"";}
    }
    if(!vendorName)vendorName="Unknown Supplier";
    if(!groupMap[vendorName]){
      groupMap[vendorName]={vendorName,vendorNo,items:[],itemsMissingPrice:0,itemsMissingLeadTime:0,itemsStalePrice:0};
    }
    const grp=groupMap[vendorName];
    grp.items.push({...item,_rfqReason:reason});
    if(reason==="missingPrice")grp.itemsMissingPrice++;
    else if(reason==="stalePrice")grp.itemsStalePrice++;
    else if(reason==="missingLeadTime")grp.itemsMissingLeadTime++;
  }
  // DECISION(v1.19.699): For each group, compute whether it's a "lead-time-only" group
  // (every row is in because of missingLeadTime — no price issues). Pre-populates the
  // per-vendor "Request Lead Times Only" checkbox.
  for(const g of Object.values(groupMap)){
    g.defaultLeadTimeOnly=(g.itemsMissingPrice===0&&g.itemsStalePrice===0&&g.itemsMissingLeadTime>0);
  }
  const RFQ_EXCLUDE_VENDORS=/^matrix\s*systems|crate|job\s*buyoff|job\s*buy.?off/i;
  const filtered=Object.values(groupMap).filter(g=>!RFQ_EXCLUDE_VENDORS.test(g.vendorName));
  return{groups:filtered.sort((a,b)=>a.vendorName.localeCompare(b.vendorName)),noItems:!filtered.length};
}

function vendorCode(vendorName){
  // Derives a 3-letter supplier code from the vendor name.
  // Single word → first 3 letters (Royal→ROY, Siemens→SIE, Wago→WAG).
  // Two words   → first 2 of word1 + first of word2 (Allen Bradley→ALB, Phoenix Contact→PHC).
  // 3+ words    → first letter of each of first 3 words (Automation Direct Inc→ADI).
  const skip=/^(inc|llc|corp|co|ltd|the|and|&)$/i;
  const words=(vendorName||'').trim().split(/[\s\-,&]+/).filter(w=>w.length>0&&!skip.test(w));
  if(words.length===0)return'SUP';
  if(words.length===1)return words[0].slice(0,3).toUpperCase().padEnd(3,'X');
  if(words.length===2)return(words[0].slice(0,2)+words[1].slice(0,1)).toUpperCase().padEnd(3,'X');
  return words.slice(0,3).map(w=>w[0]).join('').toUpperCase();
}

