function detectSheetMm(w,h){
  // Identify ANSI engineering sheet size from pixel dimensions.
  // Uses pixel area + aspect to select the closest standard size regardless of scan DPI.
  const landscape=w>=h;
  const [lw,lh]=landscape?[w,h]:[h,w];
  const area=lw*lh;
  // Pixel-area thresholds calibrated so any reasonable scan DPI (72–300) maps to the right size.
  // ANSI: A=8.5×11, B=11×17, C=17×22, D=22×34, E=34×44 inches → mm × 25.4
  let mmL,mmS;
  if(area>20000000){mmL=1117.6;mmS=863.6;}       // E 44×34"
  else if(area>8000000){mmL=863.6;mmS=558.8;}     // D 34×22"
  else if(area>3500000){mmL=558.8;mmS=431.8;}     // C 22×17"
  else if(area>1500000){mmL=431.8;mmS=279.4;}     // B 17×11"
  else{mmL=279.4;mmS=215.9;}                       // A 11×8.5"
  return landscape?{mmW:mmL,mmH:mmS}:{mmW:mmS,mmH:mmL};
}

async function buildCoverPage(doc,panel,bcProjectNumber,quoteData,lineIdx,W,H,opts={}){
  // W/H passed in from caller to match drawing page size; fall back to 11x17 landscape
  if(!W||!H){W=431.8;H=279.4;}
  const sc=Math.min(W/431.8,H/279.4);
  const m=v=>v*sc;
  const fs=v=>Math.max(4,Math.round(v*sc*10)/10);
  const margin=m(12);

  const q=quoteData||{};
  const black=[0,0,0];
  const dark=[30,30,30];
  const mid=[80,80,80];
  const generated=new Date().toLocaleDateString("en-US",{month:"short",day:"numeric",year:"numeric"});
  const scannedDate=new Date().toLocaleDateString("en-US",{month:"2-digit",day:"2-digit",year:"numeric"});
  const lineSuffix=String((lineIdx+1)*100);
  const isProduction=opts.mode==="production";
  const poNumber=opts.poNumber||"";
  const dueDate=opts.dueDate||"";
  const poReceivedDate=opts.poReceivedDate||generated;

  // ── Header bar — black border box ──
  const hdrH=m(24);
  doc.setDrawColor(...black);doc.setLineWidth(m(0.8));
  doc.rect(0,m(1),W,hdrH);
  doc.setFontSize(fs(17));doc.setFont("helvetica","bold");doc.setTextColor(...black);
  doc.text("Matrix Systems, Inc.",margin,m(16));
  doc.setFontSize(fs(12));doc.setFont("helvetica","bold");doc.setTextColor(...mid);
  doc.text(isProduction?"APPROVED TO PRODUCE":"PANEL PRODUCTION TRAVELER",W-margin,m(16),{align:"right"});

  // ── Title block ──
  const projectNum=q.projectNumber||bcProjectNumber||"—";
  doc.setFontSize(fs(30));doc.setFont("helvetica","bold");doc.setTextColor(...black);
  doc.text(projectNum,margin,m(34));
  const dwgTitle=[panel.drawingNo,panel.drawingRev?"Rev "+panel.drawingRev:""].filter(Boolean).join("  ·  ");
  doc.setFontSize(fs(18));doc.setFont("helvetica","bold");doc.setTextColor(...mid);
  doc.text(dwgTitle,margin,m(42));
  let descEndY=m(42);
  if(panel.drawingDesc){
    doc.setFontSize(fs(11));doc.setFont("helvetica","normal");doc.setTextColor(...mid);
    doc.text(panel.drawingDesc,margin,m(49),{maxWidth:W-margin*2});
    descEndY=m(49);
  }

  // ── Info grid: 4 columns — black borders ──
  const infoY=descEndY+m(6);
  const rowH=m(12);
  const fields=isProduction?[
    ["MATRIX PROJECT #",bcProjectNumber||"—"],
    ["QUOTE LINE #","Line "+(lineIdx+1)+" ("+lineSuffix+")"],
    ["DWG #",panel.drawingNo||"—"],
    ["REV",panel.drawingRev||"—"],
    ["PO #",poNumber||"—"],
    ["PO RECEIVED",poReceivedDate],
    ["DUE DATE",dueDate||panel.requestedShipDate||"—"],
    ["SALESPERSON",q.salesperson||"—"],
    ["GENERATED",generated],
    ["SCANNED DATE",scannedDate],
    ["STATUS","APPROVED"],
    ["",""]]
  :[
    ["MATRIX PROJECT #",bcProjectNumber||"—"],
    ["QUOTE LINE #","Line "+(lineIdx+1)+" ("+lineSuffix+")"],
    ["DWG #",panel.drawingNo||"—"],
    ["REV",panel.drawingRev||"—"],
    ["REQUESTED SHIP DATE",panel.requestedShipDate||q.requestedShipDate||"—"],
    ["SALESPERSON",q.salesperson||"—"],
    ["GENERATED",generated],
    ["SCANNED DATE",scannedDate],
    ["STATUS",(panel.status||"draft").toUpperCase()],
  ];
  const cols=4;
  const cellW=(W-margin*2)/cols;
  fields.forEach(([lbl,val],i)=>{
    const col=i%cols;
    const row=Math.floor(i/cols);
    const x=margin+col*cellW;
    const y=infoY+row*rowH;
    doc.setDrawColor(...black);doc.setLineWidth(m(0.3));
    doc.rect(x,y-m(4),cellW-m(1),rowH-m(1));
    doc.setFontSize(fs(7));doc.setFont("helvetica","normal");doc.setTextColor(...mid);
    doc.text(lbl,x+m(2),y);
    doc.setFontSize(fs(11));doc.setFont("helvetica","bold");doc.setTextColor(...black);
    doc.text(String(val).slice(0,28),x+m(2),y+m(6));
  });

  // Divider
  const gridRows=Math.ceil(fields.length/cols);
  const divY=infoY+gridRows*rowH+m(2);
  doc.setDrawColor(...black);doc.setLineWidth(m(0.5));doc.line(margin,divY,W-margin,divY);

  // ── Labor summary — B&W ──
  const laborEst=computeLaborEstimate(panel);
  const LABOR_GROUPS=[
    {label:"CUT",   cats:new Set(["Panel Holes","Side-Mounted Components"])},
    {label:"LAYOUT", cats:new Set(["Device Mounting","Duct & DIN Rail","Labels"])},
    {label:"WIRE",  cats:new Set(["Wire Time","Door Wiring"])},
  ];
  const groupHrs=LABOR_GROUPS.map(g=>({
    label:g.label,
    hrs:laborEst.lines.filter(l=>g.cats.has(l.category)).reduce((s,l)=>s+l.hours,0),
  }));
  const otherHrs=laborEst.lines.filter(l=>!LABOR_GROUPS.some(g=>g.cats.has(l.category))).reduce((s,l)=>s+l.hours,0);
  const laborY=divY+m(6);

  // Section header
  doc.setFontSize(fs(9));doc.setFont("helvetica","bold");doc.setTextColor(...black);
  doc.text("LABOR ESTIMATE",margin,laborY);

  const laborRows=[
    ...groupHrs,
    {label:"OTHER",hrs:otherHrs},
    {label:"TOTAL",hrs:laborEst.totalHours},
  ];
  const lrH=m(8);
  const lrY=laborY+m(6);
  const hrsColX=margin+m(52);
  const rowW=hrsColX-margin+m(10);

  laborRows.forEach((g,i)=>{
    const y=lrY+i*lrH;
    const isTotal=g.label==="TOTAL";
    doc.setDrawColor(...black);doc.setLineWidth(m(0.2));
    doc.rect(margin,y-m(5),rowW,lrH);
    if(isTotal){doc.setFillColor(220,220,220);doc.rect(margin,y-m(5),rowW,lrH,"F");doc.rect(margin,y-m(5),rowW,lrH);}
    doc.setFontSize(fs(isTotal?11:10));doc.setFont("helvetica",isTotal?"bold":"normal");doc.setTextColor(...black);
    doc.text(g.label,margin+m(2),y);
    doc.setFont("helvetica","bold");
    doc.text(`${Math.ceil(g.hrs)} hrs`,hrsColX,y,{align:"right"});
  });

  const laborDivY=lrY+laborRows.length*lrH+m(4);
  doc.setDrawColor(...black);doc.setLineWidth(m(0.3));doc.line(margin,laborDivY,W-margin,laborDivY);

  // ── BOM section label ──
  doc.setFontSize(fs(9));doc.setFont("helvetica","bold");doc.setTextColor(...black);
  doc.text("BILL OF MATERIALS",margin,laborDivY+m(7));
  const bom=(panel.bom||[]).filter(r=>!r.isLaborRow).slice().sort((a,b)=>{
    if(!a.itemNo&&!b.itemNo)return 0;
    if(!a.itemNo)return 1;
    if(!b.itemNo)return -1;
    const an=parseFloat(a.itemNo),bn=parseFloat(b.itemNo);
    if(!isNaN(an)&&!isNaN(bn))return an-bn;
    return(a.itemNo||"").localeCompare(b.itemNo||"");
  });
  const hasCrosses=bom.some(r=>r.isCrossed&&r.crossedFrom&&normPart(r.crossedFrom)!==normPart(r.partNumber));
  doc.setFontSize(fs(8));doc.setFont("helvetica","normal");doc.setTextColor(...mid);
  doc.text(`${bom.length} items${hasCrosses?` · ${bom.filter(r=>r.isCrossed).length} crossed`:""}`,W-margin,laborDivY+m(7),{align:"right"});
  const accent=[0,0,0]; // B&W mode — used by autoTable

  // ── BOM table — starts on cover page, continues to page 2+ as needed ──
  const tableStart=laborDivY+m(10);
  const baseFontSize=fs(8);
  const fontSize=baseFontSize;
  const cellPad=m(1.8);

  // DECISION(v1.19.671): Auto-size columns so long part numbers (especially the
  // "Original Part #" column) aren't truncated with an ellipsis. Minimum widths keep
  // narrow columns (#, Qty) compact; the rest expand to fit the widest value on each.
  // Text that still exceeds will wrap via overflow:"linebreak" rather than truncate.
  const colStyles=hasCrosses?{
    0:{cellWidth:m(7),halign:"center"},           // #
    1:{cellWidth:m(11),halign:"center"},          // Qty
    2:{cellWidth:'auto',minCellWidth:m(30)},      // Part # (replacement)
    3:{cellWidth:'auto',minCellWidth:m(30)},      // Original Part #
    4:{cellWidth:'auto',minCellWidth:m(60)},      // Description — expands
    5:{cellWidth:'auto',minCellWidth:m(24)},      // MFR
    6:{cellWidth:'auto',minCellWidth:m(28)},      // Supplier
  }:{
    0:{cellWidth:m(8),halign:"center"},           // #
    1:{cellWidth:m(13),halign:"center"},          // Qty
    2:{cellWidth:'auto',minCellWidth:m(32)},      // Part #
    3:{cellWidth:'auto',minCellWidth:m(60)},      // Description — expands
    4:{cellWidth:'auto',minCellWidth:m(28)},      // MFR
    5:{cellWidth:'auto',minCellWidth:m(30)},      // Supplier
  };
  const head=hasCrosses
    ?[["#","Qty","Part #","Original Part #","Description","MFR","Supplier"]]
    :[["#","Qty","Part #","Description","MFR","Supplier"]];
  const body=bom.map((r,i)=>hasCrosses
    ?[i+1,r.qty||1,r.partNumber||"—",r.isCrossed?(r.crossedFrom||"—"):"",r.description||"—",r.manufacturer||"—",r.bcVendorName||"—"]
    :[i+1,r.qty||1,r.partNumber||"—",r.description||"—",r.manufacturer||"—",r.bcVendorName||"—"]
  );

  let coverPageCount=0;
  doc.autoTable({
    startY:tableStart,
    margin:{left:margin,right:margin,bottom:m(12)},
    tableWidth:"auto",
    headStyles:{fillColor:[220,220,220],textColor:[0,0,0],fontStyle:"bold",fontSize:fontSize+m(0.5),cellPadding:cellPad,lineWidth:m(0.2),lineColor:[0,0,0]},
    bodyStyles:{fontSize,cellPadding:cellPad,lineWidth:m(0.1),lineColor:[180,180,180],textColor:[0,0,0]},
    alternateRowStyles:{fillColor:[245,245,245]},
    styles:{overflow:"linebreak"},
    columnStyles:colStyles,
    head,
    body,
    didParseCell:(data)=>{
      if(hasCrosses&&data.section==="body"){
        const row=bom[data.row.index];
        if(row&&row.isCrossed){
          data.cell.styles.fontStyle="bold";
          if(data.column.index===3){data.cell.styles.fontStyle="bolditalic";}
        }
      }
    },
    didDrawPage:(data)=>{
      coverPageCount++;
      doc.setFontSize(fs(7.5));doc.setFont("helvetica","normal");doc.setTextColor(100,100,100);
      const ph=doc.internal.pageSize.getHeight();
      doc.text(`${panel.drawingNo||bcProjectNumber}  ·  ${bom.length} items  ·  ${generated}`,margin,ph-m(5));
      doc.text(`Cover ${data.pageNumber}`,W-margin,ph-m(5),{align:"right"});
    }
  });
}

async function buildRfqPdf(group,projectName,rfqNum,rfqDate,responseBy,companyInfo=null,opts={}){
  // DECISION(v1.19.692): opts.leadTimeOnly — when true, render LEAD TIME REQUEST ONLY
  // banner + Current Price reference column + Lead Time highlighted.
  const leadTimeOnly=!!(opts&&opts.leadTimeOnly);
  const JsPDF=await ensureJsPDF();
  const doc=new JsPDF({format:"letter",unit:"mm"});
  const W=doc.internal.pageSize.getWidth();
  const slate=r=>[r>>16&255,r>>8&255,r&255];
  // Header — company name/logo
  const co=companyInfo||{};
  // "Request For Quote from" / "Lead Time Request from" label
  doc.setFontSize(11);doc.setFont("helvetica","bold");doc.setTextColor(30,41,59);
  doc.text(leadTimeOnly?"Lead Time Request from":"Request For Quote from",14,12);
  if(co.logoUrl){
    try{
      const imgData=await new Promise((res,rej)=>{const img=new Image();img.crossOrigin="anonymous";img.onload=()=>{const c=document.createElement("canvas");c.width=img.naturalWidth;c.height=img.naturalHeight;c.getContext("2d").drawImage(img,0,0);res(c.toDataURL("image/png"));};img.onerror=rej;img.src=co.logoUrl;});
      const logoH=14;const logoW=logoH*3;
      doc.addImage(imgData,"PNG",14,17,Math.min(logoW,60),logoH);
    }catch(e){doc.setFontSize(18);doc.setFont("helvetica","bold");doc.setTextColor(37,99,235);doc.text(co.name||"Company",14,19);}
  }else{
    doc.setFontSize(18);doc.setFont("helvetica","bold");doc.setTextColor(37,99,235);
    doc.text(co.name||"Matrix Systems, Inc.",14,19);
  }
  if(co.address||co.phone){
    doc.setFontSize(9);doc.setFont("helvetica","normal");doc.setTextColor(100,116,139);
    doc.text([co.address,co.phone].filter(Boolean).join("  \u00b7  "),14,26);
  }
  // RFQ label — right
  doc.setFontSize(9);doc.setTextColor(100,116,139);
  doc.text(leadTimeOnly?"LEAD TIME REQUEST":"REQUEST FOR QUOTE",W-14,18,{align:"right"});
  doc.setFontSize(15);doc.setFont("helvetica","bold");doc.setTextColor(30,41,59);
  doc.text(rfqNum,W-14,25,{align:"right"});
  // Divider
  doc.setDrawColor(203,213,225);doc.setLineWidth(0.3);doc.line(14,29,W-14,29);
  // DECISION(v1.19.692): Lead-time-only banner — yellow callout explaining that only
  // lead times are being requested and pricing is on file.
  let bannerEnd=0;
  if(leadTimeOnly){
    doc.setFillColor(254,249,195);doc.setDrawColor(252,211,77);doc.setLineWidth(0.5);
    doc.rect(14,32,W-28,14,"FD");
    doc.setFontSize(9);doc.setFont("helvetica","bold");doc.setTextColor(120,53,15);
    doc.text("LEAD TIME REQUEST ONLY",17,37);
    doc.setFont("helvetica","normal");doc.setFontSize(8);
    doc.text("We have pricing on file. Please confirm current lead times in days ARO. No need to re-quote.",17,41.5);
    bannerEnd=14;
  }
  // Info block
  const iy=36+bannerEnd;doc.setFontSize(10);
  const infoRows=[["To:",group.vendorName],["Project:",projectName||"—"],["RFQ Date:",rfqDate],["Response By:",responseBy]];
  infoRows.forEach(([lbl,val],i)=>{
    doc.setFont("helvetica","normal");doc.setTextColor(100,116,139);doc.text(lbl,14,iy+i*6);
    doc.setFont("helvetica","bold");doc.setTextColor(30,41,59);doc.text(val,42,iy+i*6);
  });
  // Items table — header + body adjust when leadTimeOnly mode is active
  const priceHeader=leadTimeOnly?"Current Price (ref)":"Unit Price";
  const ltHeader=leadTimeOnly?"Lead Time (days) ↓":"Lead Time";
  doc.autoTable({
    startY:iy+infoRows.length*6+4,
    head:[["#","Part Number","Description","Manufacturer","Qty",priceHeader,ltHeader]],
    body:group.items.map((item,i)=>{
      const refP=(leadTimeOnly&&item.unitPrice!=null)?`$${Number(item.unitPrice).toFixed(2)}`:"";
      return [i+1,item.partNumber||"—",item.description||"—",item.manufacturer||"—",item.qty||1,refP,""];
    }),
    styles:{fontSize:9,cellPadding:2.5,textColor:[30,41,59]},
    headStyles:{fillColor:[241,245,249],textColor:[30,41,59],fontStyle:"bold",lineColor:[203,213,225],lineWidth:0.3},
    columnStyles:{0:{cellWidth:10,halign:"center"},1:{cellWidth:32,fontStyle:"bold"},2:{cellWidth:"auto"},3:{cellWidth:34},4:{cellWidth:12,halign:"center"},5:{cellWidth:26,halign:"right"},6:{cellWidth:26,halign:"center",...(leadTimeOnly?{fillColor:[254,249,195]}:{})}},
    theme:"grid",tableLineColor:[203,213,225],tableLineWidth:0.3
  });
  // Footer
  const fy=doc.lastAutoTable.finalY||180;
  doc.setFontSize(9);doc.setFont("helvetica","normal");doc.setTextColor(100,116,139);
  doc.text("Please return completed RFQ to purchasing@matrixpci.com",14,fy+10);
  doc.setDrawColor(226,232,240);doc.line(14,doc.internal.pageSize.getHeight()-16,W-14,doc.internal.pageSize.getHeight()-16);
  doc.setFontSize(8);doc.text(`${rfqNum}  \u00b7  ${projectName||""}  \u00b7  ${co.name||"Matrix Systems, Inc."}  \u00b7  Confidential`,14,doc.internal.pageSize.getHeight()-10);
  return doc.output("datauristring").split(",")[1];
}

async function sendGraphEmail(graphToken,to,subject,htmlBody,pdfBase64,pdfFilename){
  const msg={
    subject,
    body:{contentType:"HTML",content:htmlBody},
    toRecipients:to.split(/[,;]\s*/).filter(e=>e.trim()).map(e=>({emailAddress:{address:e.trim()}}))
  };
  if(pdfBase64){
    msg.attachments=[{"@odata.type":"#microsoft.graph.fileAttachment",name:pdfFilename||"RFQ.pdf",contentType:"application/pdf",contentBytes:pdfBase64}];
  }
  const r=await fetch("https://graph.microsoft.com/v1.0/me/sendMail",{
    method:"POST",
    headers:{"Authorization":`Bearer ${graphToken}`,"Content-Type":"application/json"},
    body:JSON.stringify({message:msg,saveToSentItems:true})
  });
  if(!r.ok){const err=await r.text();throw new Error(err);}
}

// DECISION(v1.19.338): Search Outlook for recent email threads with a customer so user can reply
// to an existing conversation instead of starting a new one. Used in Send Quote modal.
async function graphSearchEmails(graphToken,query,top=15){
  if(!graphToken||!query)return[];
  try{
    // NOTE: Graph API $search cannot be combined with $orderby — results come back in relevance order.
    // The $search value must be quoted. ConsistencyLevel:eventual header is required for $search.
    const q=encodeURIComponent('"'+query.replace(/"/g,'')+'"');
    const r=await fetch(`https://graph.microsoft.com/v1.0/me/messages?$search=${q}&$top=${top}&$select=id,subject,from,toRecipients,receivedDateTime,bodyPreview,conversationId,isRead`,{
      headers:{"Authorization":`Bearer ${graphToken}`,"ConsistencyLevel":"eventual"}
    });
    if(!r.ok){const errTxt=await r.text().catch(()=>"");console.warn("Graph email search failed:",r.status,errTxt.slice(0,200));return[];}
    const d=await r.json();
    return(d.value||[]).map(m=>({
      id:m.id,
      subject:m.subject||"(No Subject)",
      from:m.from?.emailAddress?.name||m.from?.emailAddress?.address||"Unknown",
      fromEmail:m.from?.emailAddress?.address||"",
      to:(m.toRecipients||[]).map(t=>t.emailAddress?.name||t.emailAddress?.address).join(", "),
      date:m.receivedDateTime,
      preview:(m.bodyPreview||"").slice(0,120),
      conversationId:m.conversationId,
      isRead:m.isRead
    }));
  }catch(e){console.warn("graphSearchEmails error:",e);return[];}
}

// DECISION(v1.19.588): Fetch an Outlook attachment via Microsoft Graph given the Office.js drag JSON.
// Modern "New Outlook" and Outlook on the Web use an Office.js drag protocol where the attachment
// never reaches dataTransfer.files — only a JSON descriptor. This helper parses that descriptor,
// searches the user's mailbox by attachment name, matches by (name + size), and downloads the
// raw bytes to produce a File object that can be fed into the normal addFiles() pipeline.
// Returns { ok: boolean, file?: File, reason?: string, status?: number, error?: string }.
async function fetchOutlookAttachment(attachmentJsonStr){
  let payload;
  try{payload=JSON.parse(attachmentJsonStr);}
  catch(e){return{ok:false,reason:"parse-failed",error:e.message};}
  const att=payload&&payload.attachmentFiles&&payload.attachmentFiles[0];
  if(!att||!att.name)return{ok:false,reason:"no-attachment"};
  const name=att.name,size=att.size,contentType=att.ContentType||"application/octet-stream";
  // Silent token — don't prompt; if user hasn't granted Mail.Read, fall back to Path A message.
  const tok=(typeof tryGraphTokenSilent==="function")?await tryGraphTokenSilent().catch(()=>null):null;
  if(!tok)return{ok:false,reason:"no-graph-token",attachmentName:name};
  // Sanitize filename for $search: strip double-quotes and backslashes.
  const searchName=name.replace(/["\\]/g," ");
  try{
    const searchUrl=`https://graph.microsoft.com/v1.0/me/messages?$search=${encodeURIComponent('"'+searchName+'"')}&$top=20&$select=id,subject&$expand=attachments($select=id,name,size,contentType)`;
    const r=await fetch(searchUrl,{headers:{"Authorization":"Bearer "+tok,"ConsistencyLevel":"eventual"}});
    if(!r.ok)return{ok:false,reason:"search-failed",status:r.status,attachmentName:name};
    const data=await r.json();
    // Primary match: name + size exactly
    let msgId=null,attId=null,actualContentType=contentType;
    for(const msg of(data.value||[])){
      for(const a of(msg.attachments||[])){
        if(a.name===name&&a.size===size){msgId=msg.id;attId=a.id;if(a.contentType)actualContentType=a.contentType;break;}
      }
      if(msgId)break;
    }
    // Fallback: name-only match (size occasionally differs between Office.js and Graph by a small amount)
    if(!msgId){
      for(const msg of(data.value||[])){
        for(const a of(msg.attachments||[])){
          if(a.name===name){msgId=msg.id;attId=a.id;if(a.contentType)actualContentType=a.contentType;break;}
        }
        if(msgId)break;
      }
    }
    if(!msgId)return{ok:false,reason:"not-found",attachmentName:name};
    // Download bytes
    const dlUrl=`https://graph.microsoft.com/v1.0/me/messages/${encodeURIComponent(msgId)}/attachments/${encodeURIComponent(attId)}/$value`;
    const dlResp=await fetch(dlUrl,{headers:{"Authorization":"Bearer "+tok}});
    if(!dlResp.ok)return{ok:false,reason:"download-failed",status:dlResp.status,attachmentName:name};
    const buf=await dlResp.arrayBuffer();
    const file=new File([buf],name,{type:actualContentType});
    return{ok:true,file};
  }catch(e){return{ok:false,reason:"fetch-error",error:e.message,attachmentName:name};}
}

// DECISION(v1.19.344): Uses createReplyAll (not createReply) so the response goes to ALL
// original recipients (To + Cc), not just the sender. Quote replies typically need to include
// the full team (customer contacts, internal stakeholders) from the original conversation.
// DECISION(v1.19.366): Uses the /replyAll action endpoint which sends immediately and supports
// attachments in the message body. Previous draft-based approach (createReplyAll → PATCH → POST attachment → send)
// was not attaching the PDF reliably. This single-call approach mirrors how sendGraphEmail works.
async function graphReplyToMessage(graphToken,messageId,htmlBody,pdfBase64,pdfFilename){
  if(!graphToken||!messageId)throw new Error("Missing token or messageId");
  const replyBody={
    message:{
      body:{contentType:"HTML",content:htmlBody}
    }
  };
  if(pdfBase64){
    replyBody.message.attachments=[{"@odata.type":"#microsoft.graph.fileAttachment",name:pdfFilename||"Quote.pdf",contentType:"application/pdf",contentBytes:pdfBase64}];
    console.log("[REPLY] Sending reply-all with attachment:",pdfFilename,"~",Math.round(pdfBase64.length*3/4/1024),"KB");
  }
  const r=await fetch(`https://graph.microsoft.com/v1.0/me/messages/${messageId}/replyAll`,{
    method:"POST",
    headers:{"Authorization":`Bearer ${graphToken}`,"Content-Type":"application/json"},
    body:JSON.stringify(replyBody)
  });
  if(!r.ok){const t=await r.text();console.error("[REPLY] replyAll failed:",r.status,t);throw new Error(`Reply failed (${r.status}): ${t}`);}
  console.log("[REPLY] Reply-all sent OK");
}

async function bcClearAssemblyBOMLines(parentItemNo,bomPage){
  const getUrl=`${BC_ODATA_BASE}/${bomPage}?$filter=Parent_Item_No eq '${encodeURIComponent(parentItemNo)}'`;
  const gr=await fetch(getUrl,{headers:{"Authorization":`Bearer ${_bcToken}`}});
  if(!gr.ok)throw new Error(`Failed to read existing BOM lines: ${gr.status}`);
  const lines=(await gr.json()).value||[];
  let deleted=0;const errors=[];
  for(const line of lines){
    const lineNo=line.Line_No;
    const etag=line["@odata.etag"];
    const delUrl=`${BC_ODATA_BASE}/${bomPage}(Parent_Item_No='${encodeURIComponent(parentItemNo)}',Line_No=${lineNo})`;
    const dr=await fetch(delUrl,{method:"DELETE",headers:{"Authorization":`Bearer ${_bcToken}`,"If-Match":etag||"*"}});
    if(dr.ok||dr.status===204){deleted++;}
    else{const t=await dr.text();errors.push(`Line ${lineNo}: ${t.slice(0,80)}`);}
  }
  return{deleted,total:lines.length,errors};
}

async function bcReplaceAssemblyBOMLines(parentItemNo,bomRows,onProgress){
  const result={deleted:0,added:0,skipped:0,errors:[],warning:""};
  const allPages=await bcDiscoverODataPages();
  const bomPage=allPages.find(n=>/assembly.*bom|bom.*comp/i.test(n))||null;
  if(!bomPage){
    result.warning="No Assembly BOM OData page found. In BC, go to Web Services → New → Object Type: Page, Object ID: 36, Service Name: AssemblyBOM, Published: true.";
    return result;
  }
  if(onProgress)onProgress(-1,bomRows.length,"Clearing existing BOM lines…");
  try{
    const clear=await bcClearAssemblyBOMLines(parentItemNo,bomPage);
    result.deleted=clear.deleted;
    if(clear.errors.length)result.errors.push(...clear.errors.map(e=>"[clear] "+e));
  }catch(ce){result.errors.push("[clear] "+ce.message);}
  const addResult=await bcAddAssemblyBOMLines(parentItemNo,bomRows,onProgress,bomPage);
  result.added=addResult.added;
  result.skipped=addResult.skipped;
  result.errors.push(...addResult.errors);
  result.warning=addResult.warning;
  return result;
}

async function bcAddAssemblyBOMLines(parentItemNo,bomRows,onProgress,_bomPage){
  const result={added:0,skipped:0,errors:[],warning:""};
  if(!bomRows||!bomRows.length)return result;
  let bomPage=_bomPage||null;
  if(!bomPage){
    const allPages=await bcDiscoverODataPages();
    bomPage=allPages.find(n=>/assembly.*bom|bom.*comp/i.test(n))||null;
  }
  if(!bomPage){
    result.warning="No Assembly BOM OData page found. In BC, go to Web Services → New → Object Type: Page, Object ID: 36, Service Name: AssemblyBOM, Published: true.";
    return result;
  }
  for(let i=0;i<bomRows.length;i++){
    const row=bomRows[i];
    const pn=(row.partNumber||"").trim();
    if(!pn){result.skipped++;continue;}
    if(onProgress)onProgress(i,bomRows.length,pn);
    try{
      const r=await fetch(`${BC_ODATA_BASE}/${bomPage}`,{
        method:"POST",
        headers:{"Authorization":`Bearer ${_bcToken}`,"Content-Type":"application/json"},
        body:JSON.stringify({Parent_Item_No:parentItemNo,Type:"Item",No:pn,Quantity_per:+(row.qty||1)})
      });
      if(r.ok){result.added++;}
      else{const t=await r.text();result.errors.push(`${pn}: ${t.slice(0,120)}`);result.skipped++;}
    }catch(e){result.errors.push(`${pn}: ${e.message}`);result.skipped++;}
  }
  return result;
}

// ── SUPPLIER QUOTE IMPORT ──
function sqExtractMfr(raw){
  if(!raw||typeof raw!=='string')return{mfr:'',partNumber:raw||''};
  const t=raw.trim(),parts=t.split(/\s+/),p=parts[0]||'';
  // DECISION(v1.19.726): Allow hyphenated mfr prefixes like "A-B" (Allen-Bradley),
  // "PHX-CT" (Phoenix Contact), "SQ-D" (Square D). Pattern: 1-4 letters, optional
  // -letters segment, must contain at least one letter total. Bare digits not allowed.
  if(/^[A-Z]{1,4}(-[A-Z]{1,4})?$/i.test(p)){
    return{mfr:p.toUpperCase(),partNumber:parts.slice(1).join(' ').trim()};
  }
  return{mfr:'',partNumber:t};
}
const SQ_NOTES=[
  {p:/CANCEL/i,n:'CANCEL ON ORDER'},{p:/NEVER ORDERED/i,n:'NEVER ORDERED'},
  {p:/NOT SUPPLY/i,n:'NOT SUPPLYING'},{p:/IN HOUSE/i,n:'MAKE IN HOUSE'},
  {p:/TBD/i,n:'TBD'},{p:/ON HOLD/i,n:'ON HOLD'},
];
function sqNormalize(raw){
  const{mfr,partNumber}=sqExtractMfr(raw.rawPartNumber||'');
  const isPriced=raw.qty!=null&&raw.price!=null&&!isNaN(raw.qty)&&!isNaN(raw.price);
  let notes='';for(const{p,n}of SQ_NOTES){if(p.test(raw.description||'')){notes=n;break;}}
  // DECISION(v1.19.703): Carry leadTimeDays through the SQ pipeline so it can be pushed
  // to BC ItemVendorCatalog alongside prices.
  const ltRaw=raw.leadTimeDays;
  const leadTimeDays=(ltRaw==null||isNaN(+ltRaw)||+ltRaw<=0)?null:Math.round(+ltRaw);
  // DECISION(v1.19.725): Carry supplierStockQty/Source so the Lead column tooltip can
  // show the snapshot (e.g. Codale "24 IN SLC" → 24 in stock at Codale SLC).
  const stkRaw=raw.supplierStockQty;
  const supplierStockQty=(stkRaw==null||isNaN(+stkRaw)||+stkRaw<0)?null:Math.round(+stkRaw);
  const supplierStockSource=raw.supplierStockSource||null;
  return{ln:raw.ln??null,mfr,partNumber,rawPartNumber:raw.rawPartNumber||'',description:raw.description||'',
    qty:isPriced?Number(raw.qty):null,price:isPriced?Number(raw.price):null,uom:raw.uom||'',
    extPrice:isPriced?Math.round(raw.qty*raw.price*100)/100:null,notes,isPriced,
    extractionWarning:raw.extractionWarning||null,leadTimeDays,supplierStockQty,supplierStockSource,
    bcItemId:null,bcItemDescription:null,bcCurrentCost:null,matchStatus:'unmatched',priceUpdateStatus:null,approved:true};
}
function sqValidateLineItems(items){
  const dupeLines=[],dupeParts=[];
  const lnMap={},pnMap={};
  items.forEach((item,i)=>{
    if(item.ln!=null){const k=String(item.ln);(lnMap[k]=lnMap[k]||[]).push(i);}
    if(item.rawPartNumber){const k=(item.rawPartNumber||'').toLowerCase().trim();(pnMap[k]=pnMap[k]||[]).push(i);}
  });
  Object.entries(lnMap).filter(([,a])=>a.length>1).forEach(([ln,idxs])=>dupeLines.push({ln:Number(ln),rows:idxs}));
  Object.entries(pnMap).filter(([,a])=>a.length>1).forEach(([,idxs])=>dupeParts.push({pn:items[idxs[0]].rawPartNumber,rows:idxs}));
  const missingLn=items.filter(item=>item.ln==null).length;
  return{dupeLines,dupeParts,missingLn,hasIssues:dupeLines.length>0||dupeParts.length>0};
}
async function saveSupplierQuoteToFirestore(quoteData,userId,{supersedes=null,projectId=null,bcProjectNumber=null}={}){
  const ref=fbDb.collection('supplierQuotes').doc();
  const lineItems=(quoteData.lineItems||[]).map(sqNormalize);
  const total=lineItems.reduce((s,i)=>s+(i.extPrice||0),0);
  // Build search tokens for array-contains queries (supplier, quote#, job name, contact)
  const tokenize=s=>(s||'').toLowerCase().replace(/[^a-z0-9\s]/g,' ').split(/\s+/).filter(w=>w.length>1);
  const searchTokens=[...new Set([
    ...tokenize(quoteData.supplier),
    ...tokenize(quoteData.quoteId),
    ...tokenize(quoteData.jobName),
    ...tokenize(quoteData.contactName),
  ])];
  // DECISION(v1.19.721): Populate `userId` and `companyId` to satisfy firestore.rules
  // for supplierQuotes update permission. Previously only `importedBy` was set, which
  // didn't match either rule condition (userId == auth.uid OR companyId member exists),
  // so subsequent updates from handlePush would fail with permission-denied.
  const cid=(typeof _appCtx!=="undefined"&&_appCtx?.companyId)||null;
  await ref.set({quoteId:quoteData.quoteId||'',revision:quoteData.revision||'',supplier:quoteData.supplier||'',
    supplierLower:(quoteData.supplier||'').toLowerCase(),
    jobName:quoteData.jobName||'',contactName:quoteData.contactName||'',quoteDate:quoteData.quoteDate||null,
    expiresOn:quoteData.expiresOn||null,fob:quoteData.fob||'',freight:quoteData.freight||'',
    status:'pending_review',merchandiseTotal:Math.round(total*100)/100,lineItems,searchTokens,
    pdfUrl:null,fileName:'',supersedes:supersedes||null,supersededBy:null,
    projectId:projectId||null,bcProjectNumber:bcProjectNumber||null,
    userId,companyId:cid,
    importedAt:firebase.firestore.FieldValue.serverTimestamp(),importedBy:userId});
  if(supersedes){
    fbDb.collection('supplierQuotes').doc(supersedes)
      .update({supersededBy:ref.id,status:'superseded'}).catch(()=>{});
  }
  return{docId:ref.id,lineItems};
}
async function bcLookupItemForQuote(partNumber){
  if(!_bcToken||!partNumber)return null;
  const compId=await bcGetCompanyId();if(!compId)return null;
  const pn=partNumber.trim().replace(/'/g,"''");
  try{
    for(const filter of[`number eq '${pn}'`,`vendorItemNo eq '${pn}'`]){
      const r=await fetch(`${BC_API_BASE}/companies(${compId})/items?$filter=${filter}`,{headers:{"Authorization":`Bearer ${_bcToken}`}});
      if(r.ok){const d=await r.json();const item=(d.value||[])[0];
        if(item)return{id:item.id,number:item.number,displayName:item.displayName||'',unitCost:item.unitCost??null};}
    }
  }catch(e){console.warn("bcLookupItemForQuote:",e);}
  return null;
}
async function bcUpdateItemCost(itemId,newCost){
  if(!_bcToken)return false;
  const compId=await bcGetCompanyId();if(!compId)return false;
  try{
    const r=await fetch(`${BC_API_BASE}/companies(${compId})/items(${itemId})`,{
      method:"PATCH",headers:{"Authorization":`Bearer ${_bcToken}`,"Content-Type":"application/json","If-Match":"*"},
      body:JSON.stringify({unitCost:newCost})});
    return r.ok;
  }catch(e){console.warn("bcUpdateItemCost:",e);return false;}
}
async function sqSavePushAudit(quoteDocId,supplier,quoteId,userId,auditItems){
  if(!auditItems.length)return;
  await fbDb.collection('bcPriceUpdates').add({quoteId,supplier,quoteDocId,
    pushedAt:firebase.firestore.FieldValue.serverTimestamp(),pushedBy:userId,items:auditItems});
}
// Supplier quote part-number crossings — maps supplier PN → BC item
// Path: users/{uid}/config/sqCrossings
async function sqGetCrossings(uid){
  try{const snap=await fbDb.doc(`users/${uid}/config/sqCrossings`).get();return snap.exists?snap.data():{};
  }catch(e){return{};}
}
