// Adaptive AI parse time learning — stored in Firestore users/{uid}/config/sqLearning
async function sqGetAiPrior(uid){
  try{
    const snap=await fbDb.collection('users').doc(uid).collection('config').doc('sqLearning').get();
    if(!snap.exists)return 22;
    const arr=snap.data().aiParseTimes||[];
    if(!arr.length)return 22;
    const recent=arr.slice(-8);
    const avg=recent.reduce((a,b)=>a+b,0)/recent.length;
    return Math.max(10,Math.round(avg*1.15)); // rolling avg + 15% buffer
  }catch{return 22;}
}
async function sqRecordAiTime(uid,seconds){
  try{
    const ref=fbDb.collection('users').doc(uid).collection('config').doc('sqLearning');
    const snap=await ref.get();
    const arr=snap.exists?(snap.data().aiParseTimes||[]):[];
    arr.push(Math.round(seconds));
    await ref.set({aiParseTimes:arr.slice(-10)},{merge:true});
  }catch(e){console.warn('sqRecordAiTime:',e);}
}
// Vendor fuzzy matching for supplier → BC vendor auto-population
// First word of supplier name is heavily weighted — e.g. "Royal - Salt Lake City" → "Royal Wholesale"
// DECISION(v1.19.727): Fuzzy match an AI-extracted MFR code (e.g. "A-B", "HOFF",
// "PHX-CT") against the BC Manufacturers list. Strips hyphens / spaces, tries
// exact-on-Code first, then prefix-match on Name (e.g. "A-B" → "ALLEN BRADLEY"
// hits because "AB" is a prefix of "ALLEN").
function sqFuzzyMatchManufacturer(mfrCode,manufacturers){
  if(!mfrCode||!Array.isArray(manufacturers)||!manufacturers.length)return null;
  const norm=s=>String(s||'').toUpperCase().replace(/[^A-Z0-9]/g,'');
  const want=norm(mfrCode);
  if(!want)return null;
  // 1. Exact normalized Code match
  let hit=manufacturers.find(m=>norm(m.Code)===want);
  if(hit)return hit;
  // 2. Code starts with the wanted code or vice versa
  hit=manufacturers.find(m=>{const c=norm(m.Code);return c.startsWith(want)||want.startsWith(c);});
  if(hit)return hit;
  // 3. Name initials match the wanted code (e.g. "AB" matches "ALLEN BRADLEY" → "AB")
  hit=manufacturers.find(m=>{
    const initials=String(m.Name||'').split(/\s+/).filter(Boolean).map(w=>w[0]).join('').toUpperCase();
    return initials===want||initials.startsWith(want);
  });
  if(hit)return hit;
  // 4. First word of Name starts with the wanted code (e.g. "HOFF" → "HOFFMAN")
  hit=manufacturers.find(m=>{
    const first=String(m.Name||'').split(/\s+/)[0]?.toUpperCase()||'';
    return first.startsWith(want)||want.startsWith(first);
  });
  return hit||null;
}
function sqFuzzyMatchVendor(supplierName,vendors){
  if(!supplierName||!vendors.length)return null;
  const norm=s=>s.toLowerCase().replace(/[^a-z0-9\s]/g,' ').replace(/\b(inc|llc|ltd|corp|co|company|the|and)\b/g,' ').replace(/\s+/g,' ').trim();
  const srcWords=norm(supplierName).split(' ').filter(w=>w.length>1);
  if(!srcWords.length)return null;
  const srcFirst=srcWords[0];
  let best=null,bestScore=0;
  for(const v of vendors){
    const vWords=norm(v.displayName).split(' ').filter(w=>w.length>1);
    if(!vWords.length)continue;
    // If first words match exactly, score gets a strong 0.6 base boost
    const firstMatch=srcFirst&&vWords[0]===srcFirst;
    const overlapMatched=srcWords.filter(sw=>vWords.some(vw=>vw===sw||vw.includes(sw)||sw.includes(vw)));
    const overlapScore=overlapMatched.length/Math.max(srcWords.length,vWords.length);
    const score=firstMatch?Math.max(0.6+overlapScore*0.4,overlapScore):overlapScore;
    if(score>bestScore){bestScore=score;best=v;}
  }
  return bestScore>=0.25?best:null;
}
