// ── IMAGE RESIZE ──
function resizeImage(dataUrl,maxW=2800){
  return new Promise((res,rej)=>{
    if(!dataUrl){return rej(new Error("resizeImage: empty dataUrl"));}
    const img=new Image();
    img.onload=()=>{
      let w=img.width,h=img.height;
      if(w>maxW){h=Math.round(h*(maxW/w));w=maxW;}
      const c=document.createElement("canvas");c.width=w;c.height=h;
      c.getContext("2d").drawImage(img,0,0,w,h);
      res(c.toDataURL("image/jpeg",0.95));c.width=0;c.height=0;
    };
    img.onerror=()=>rej(new Error("resizeImage: failed to load image"));
    img.src=dataUrl;
  });
}
// Resize specifically for AI API calls — Claude internally caps at 1568px, so sending larger is wasted bandwidth
function resizeForAnalysis(dataUrl,maxW=1568){return resizeImage(dataUrl,maxW);}

// ── QUOTE REVISION — hash BOM state to detect changes after printing ──
function computeBomHash(panels){
  const data=(panels||[]).map(p=>(p.bom||[]).filter(r=>!r.isLaborRow).map(r=>({pn:(r.partNumber||'').trim(),q:r.qty||0,up:r.unitPrice||0})));
  const str=JSON.stringify(data);
  let h=5381;
  for(let i=0;i<str.length;i++){h=((h<<5)+h)+str.charCodeAt(i);h=h&h;}
  return String(h);
}
// DECISION(v1.19.487): Per-panel BOM hash — tracks whether BC sync is needed.
function computePanelBomHash(panel){
  const data=(panel.bom||[]).filter(r=>!r.isLaborRow).map(r=>({pn:(r.partNumber||'').trim(),q:r.qty||0,up:r.unitPrice||0}));
  const str=JSON.stringify(data);
  let h=5381;
  for(let i=0;i<str.length;i++){h=((h<<5)+h)+str.charCodeAt(i);h=h&h;}
  return String(h);
}
// DECISION(v1.19.743): Per-panel "Drawing Version" — bumps each time the BOM is mutated
// from its prior saved state. Initial extraction sets v.1; manual edits, re-extraction
// with changed output, supplier-apply, scraper-apply all bump. Re-saves with no actual
// BOM-hash change leave the version untouched. Existing pre-v1.19.743 panels with no
// `bomVersion` field are NOT backfilled — first mutation under the new code assigns the
// version going forward (treated as v.1+1=v.2 per "any change from original = v.2").
// Returns a (possibly) updated panel; safe to use in any save path.
function _bumpBomVersionIfChanged(newPanel,existingPanel){
  if(!newPanel)return newPanel;
  const newCount=(newPanel.bom||[]).filter(r=>!r.isLaborRow).length;
  const oldCount=existingPanel?(existingPanel.bom||[]).filter(r=>!r.isLaborRow).length:0;
  // Case A — first BOM ever for this panel (initial extraction). v.1.
  if(oldCount===0&&newCount>0&&newPanel.bomVersion==null){
    return{...newPanel,bomVersion:1};
  }
  // Case B — BOM hash changed AND there was a prior BOM. Bump.
  if(oldCount>0){
    const oldHash=computePanelBomHash(existingPanel);
    const newHash=computePanelBomHash(newPanel);
    if(oldHash!==newHash){
      const next=(existingPanel.bomVersion??1)+1;
      return{...newPanel,bomVersion:next};
    }
  }
  // Case C — no change, or no prior BOM and incoming is empty. Leave alone (no backfill).
  return newPanel;
}
if(typeof window!=="undefined"){window._bumpBomVersionIfChanged=_bumpBomVersionIfChanged;}

// DECISION(v1.19.744): Quote-relevant content hash — used to detect any change that
// should bump the project-level Quote Rev. Covers everything that appears on the printed
// quote document or affects its math: per-panel BOM (qty, price, lead time, source, PN,
// description, manufacturer, notes), drawing identity + version + page count, ship dates,
// pricing config, line qty, and the entire `project.quote` blob (markup, terms, line
// notes, contacts, addresses, etc.).
// DECISION(v1.19.820): Narrowed the quote-rev hash. Previously this included
// `bomVersion` (redundant — derived from the BOM hash), `bomNotes` (auto-rewritten
// by the Lead Drivers refresh effect on every project open → spurious bumps),
// `pageCount` (ECO Phase 2.J added pages tagged with `ecoId` to `panel.pages`,
// which would tick the count without any base-BOM change), and the entire
// `pricing` object (too wide — any new field anywhere added a difference). The
// runaway bumps were cascading into the BC drawing-sync prompt firing on every
// open. Hash now covers exactly the things that actually print on the quote and
// affect customer-visible totals: drawing identity, ship dates, lineQty, the BOM
// (PN/qty/price/lead/desc/mfr), the explicit pricing knobs that drive sell
// price (markup/manualLaborCost/laborRate/laborHoursOverride/isBudgetary), and
// the entire `quote` blob (terms, contacts, addresses, notes).
// DECISION(v1.19.853, ECO Stage A): Reverted v1.19.852's narrow hash. The user
// confirmed all the previously-included fields are valid bump triggers — the
// real issue was that opening a project was triggering bumps via spurious
// saves, which is now addressed by the ECO suppression in saveProject /
// saveProjectPanel (v1.19.850). Hash is back to the v1.19.820 shape: narrow
// enough that bomNotes / bomVersion / pageCount / whole-pricing don't drift it
// (those caused the original runaway bumps), broad enough that any real
// quote-affecting change (unit price, lead time, description, manufacturer,
// drawing identity, ship dates, markup, budgetary, quote terms / contacts)
// is captured.
function _computeQuoteHash(project){
  if(!project)return"";
  const data={
    panels:(project.panels||[]).map(p=>{
      const pr=p.pricing||{};
      return{
        drawingNo:p.drawingNo||"",
        drawingDesc:p.drawingDesc||"",
        drawingRev:p.drawingRev||"",
        requestedShipDate:p.requestedShipDate||"",
        productionEndDate:p.productionEndDate||"",
        lineQty:p.lineQty??1,
        markup:pr.markup??null,
        manualLaborCost:pr.manualLaborCost??null,
        laborRate:pr.laborRate??null,
        laborHoursOverride:pr.laborHoursOverride??null,
        isBudgetary:!!pr.isBudgetary,
        bom:(p.bom||[]).filter(r=>!r.isLaborRow).map(r=>({
          pn:(r.partNumber||"").trim(),
          q:r.qty||0,
          up:r.unitPrice||0,
          ld:r.leadTimeDays??null,
          ls:r.leadTimeSource||"",
          d:(r.description||"").trim(),
          m:(r.manufacturer||"").trim(),
        })),
      };
    }),
    quote:project.quote||{},
  };
  const str=JSON.stringify(data);
  let h=5381;
  for(let i=0;i<str.length;i++){h=((h<<5)+h)+str.charCodeAt(i);h=h&h;}
  return String(h);
}
if(typeof window!=="undefined"){window._computeQuoteHash=_computeQuoteHash;}

// ── FIRESTORE ──
const _saveHighWater={}; // {projectId: {panelCount, panels:[{pages,bomItems,savedPages,savedBom,...}]}}
async function saveProject(uid,project){
  const path=_appCtx.projectsPath||`users/${uid}/projects`;
  const col=fbDb.collection(path);
  const ref=project.id?col.doc(project.id):col.doc();
  const data={...project,id:ref.id,updatedAt:Date.now(),schemaVersion:APP_SCHEMA_VERSION,...(!project.id&&{createdBy:uid})};
  // SAFETY: Use in-memory high-water marks to prevent data loss from stale saves
  if(project.id){
    const newPanels=data.panels||[];
    const hw=_saveHighWater[project.id];
    if(hw){
      if(hw.panelCount>0&&newPanels.length<hw.panelCount){
        console.error(`SAVE BLOCKED: would reduce panels from ${hw.panelCount} to ${newPanels.length} for project ${project.id}`);
        return data;
      }
      for(let i=0;i<Math.min(hw.panels.length,newPanels.length);i++){
        const ehw=hw.panels[i];if(!ehw)continue;
        const nPg=(newPanels[i].pages||[]).length;
        const nBom=(newPanels[i].bom||[]).filter(r=>!r.isLaborRow).length;
        if(ehw.pages>0&&nPg===0&&ehw.savedPages){
          console.error(`SAVE GUARD: preserving ${ehw.pages} pages for panel ${i}`);
          newPanels[i]={...newPanels[i],pages:ehw.savedPages};
        }
        if(ehw.bomItems>0&&nBom===0&&ehw.savedBom){
          console.error(`SAVE GUARD: preserving ${ehw.bomItems} BOM items for panel ${i}`);
          newPanels[i]={...newPanels[i],bom:ehw.savedBom};
        }
        for(const f of ['drawingNo','drawingDesc','drawingRev','validation','laborData','complianceReview']){
          if(ehw[f]&&!newPanels[i][f])newPanels[i]={...newPanels[i],[f]:ehw[f]};
        }
      }
    }
    // DECISION(v1.19.744): Consolidated single Firestore read powering THREE guards:
    //   (1) storageUrl regression guard (v1.19.739) — restore URLs that stale incoming
    //       saves dropped.
    //   (2) bomVersion bump (v1.19.743) — bump per-panel Drawing Version when BOM hash
    //       differs.
    //   (3) quoteRev bump (v1.19.744) — bump project-level Quote Rev when ANY quote-
    //       relevant content has changed since the last persisted state.
    // Single ref.get() per save to keep latency low.
    let _curDoc=null;
    try{
      _curDoc=await ref.get();
      if(_curDoc.exists){
        const curPanels=_curDoc.data().panels||[];
        // (1) storageUrl + reviewNotes regression guard
        // DECISION(v1.19.776): Same pattern that protects storageUrl from stale-save
        // overwrites is now extended to reviewNotes. When Andrew adds a note on a page
        // while Jon's client is mid-edit on the same project, Jon's incoming save would
        // previously have a stale `reviewNotes` array (missing Andrew's note) and wipe
        // it. Now we merge by note `id`: incoming notes win on conflicts (so edits to
        // the same note still apply), but any current notes whose id is missing from
        // the incoming array are restored. Same merge applies to `reviewShapes`.
        for(let i=0;i<newPanels.length;i++){
          const np=newPanels[i];
          const cp=curPanels.find(p=>p.id===np.id);
          if(!cp||!(cp.pages||[]).length||!(np.pages||[]).length)continue;
          const curById=new Map(cp.pages.map(pg=>[String(pg.id),pg]));
          let restoredUrls=0,restoredNotes=0,restoredShapes=0;
          const merged=(np.pages||[]).map(pg=>{
            const prev=curById.get(String(pg.id));
            if(!prev)return pg;
            let next=pg;
            if(!pg.storageUrl&&prev.storageUrl){restoredUrls++;next={...next,storageUrl:prev.storageUrl};}
            // Merge reviewNotes: incoming wins per id; current-only ids are restored.
            if(Array.isArray(prev.reviewNotes)&&prev.reviewNotes.length>0){
              const incoming=Array.isArray(pg.reviewNotes)?pg.reviewNotes:[];
              const incomingIds=new Set(incoming.map(n=>n&&n.id).filter(Boolean));
              const missing=prev.reviewNotes.filter(n=>n&&n.id&&!incomingIds.has(n.id));
              if(missing.length>0){restoredNotes+=missing.length;next={...next,reviewNotes:[...incoming,...missing]};}
            }
            // Same merge for reviewShapes (drawing redlines).
            if(Array.isArray(prev.reviewShapes)&&prev.reviewShapes.length>0){
              const incoming=Array.isArray(pg.reviewShapes)?pg.reviewShapes:[];
              const incomingIds=new Set(incoming.map(s=>s&&s.id).filter(Boolean));
              const missing=prev.reviewShapes.filter(s=>s&&s.id&&!incomingIds.has(s.id));
              if(missing.length>0){restoredShapes+=missing.length;next={...next,reviewShapes:[...incoming,...missing]};}
            }
            return next;
          });
          if(restoredUrls>0||restoredNotes>0||restoredShapes>0){
            const parts=[];
            if(restoredUrls>0)parts.push(`storageUrl×${restoredUrls}`);
            if(restoredNotes>0)parts.push(`reviewNotes×${restoredNotes}`);
            if(restoredShapes>0)parts.push(`reviewShapes×${restoredShapes}`);
            console.warn(`SAVE GUARD (saveProject): restored ${parts.join(", ")} on panel ${i} — stale incoming save`);
            newPanels[i]={...np,pages:merged};
          }
        }
        // (2) bomVersion bump
        for(let i=0;i<newPanels.length;i++){
          const np=newPanels[i];
          const cp=curPanels.find(p=>p.id===np.id);
          newPanels[i]=_bumpBomVersionIfChanged(np,cp);
        }
        // (3) quoteRev bump — compute hash AFTER bomVersion has been applied so
        // version changes are part of the quote-state hash. Compare to the last-
        // persisted hash; if different, bump quoteRev and record the new hash. First
        // save under the new logic seeds quoteRev=1 + lastQuoteHash without bumping.
        // DECISION(v1.19.850, ECO Stage A): Suppress quote-rev bumps entirely while
        // a draft ECO is active. The quote rev tracks revisions of the BASE quote
        // sent to the customer; during an ECO round the customer is reviewing the
        // change order, not a new revision of the BASE. Once the ECO closes
        // (Stage F auto-relock) bumps resume normally. Hash is still recorded so
        // the next post-ECO save compares cleanly.
        const _hasActiveEcoSP=!!data.ecoEditUnlocked||(Array.isArray(data.ecoSummary)&&data.ecoSummary.some(e=>e&&e.status==="draft"));
        const oldQuoteHash=_curDoc.data().lastQuoteHash;
        const newQuoteHash=_computeQuoteHash(data);
        if(oldQuoteHash){
          if(newQuoteHash!==oldQuoteHash&&!_hasActiveEcoSP){
            data.quoteRev=(data.quoteRev||1)+1;
            data.lastQuoteHash=newQuoteHash;
            console.log(`[QUOTE REV] bumped to ${data.quoteRev}`);
          }else if(newQuoteHash!==oldQuoteHash&&_hasActiveEcoSP){
            // Hash diff detected but suppressed — refresh persisted hash anyway so
            // post-ECO saves don't see a stale baseline.
            data.lastQuoteHash=newQuoteHash;
            console.log("[QUOTE REV] suppressed — active ECO in flight");
          }
        }else{
          // First save with the new system — initialize without bumping
          data.quoteRev=data.quoteRev||1;
          data.lastQuoteHash=newQuoteHash;
        }
      }else{
        // No prior Firestore doc (brand-new project) — seed quoteRev=1.
        data.quoteRev=1;
        data.lastQuoteHash=_computeQuoteHash(data);
      }
    }catch(e){console.warn("saveProject consolidated guards read failed:",e.message);}
    // Update high-water marks from what we're about to save
    _saveHighWater[project.id]={panelCount:newPanels.length,panels:newPanels.map(p=>({
      pages:(p.pages||[]).length,bomItems:(p.bom||[]).filter(r=>!r.isLaborRow).length,
      savedPages:(p.pages||[]).length>0?(p.pages||[]).map(pg=>{const{dataUrl,...r}=pg;return r;}):null,
      savedBom:(p.bom||[]).filter(r=>!r.isLaborRow).length>0?p.bom:null,
      drawingNo:p.drawingNo||null,drawingDesc:p.drawingDesc||null,drawingRev:p.drawingRev||null,
      validation:p.validation||null,laborData:p.laborData||null,complianceReview:p.complianceReview||null
    }))};
  }
  // Don't store page images in Firestore — strip dataUrls from panels
  // DECISION(v1.19.421): Include updatedBy (uid) so concurrent editing detection can
  // distinguish own saves from other users' saves.
  const stripped={...data,updatedBy:uid,updatedAt:Date.now(),panels:(data.panels||[]).map(panel=>({...panel,pages:(panel.pages||[]).map(p=>{const {dataUrl,...rest}=p;return rest;})}))};
  const toSave=JSON.parse(JSON.stringify(stripped));
  await ref.set(toSave);
  return data; // return with dataUrls intact for in-memory use
}
// DECISION(v1.19.405): Safe save wrapper — retries on failure and shows user notification.
// Replaces silent `.catch(()=>{})` patterns that swallowed save errors.
let _saveFailBanner=null; // global setter for save-fail banner (set by App component)
async function safeSave(uid,project,retries=2){
  for(let attempt=0;attempt<=retries;attempt++){
    try{await saveProject(uid,project);return true;}
    catch(e){
      console.warn(`Save failed (attempt ${attempt+1}/${retries+1}):`,e.message);
      if(attempt<retries)await new Promise(r=>setTimeout(r,2000));
    }
  }
  console.error("Save failed after all retries for project:",project?.id||project?.name);
  if(_saveFailBanner)_saveFailBanner("Save failed — changes may not be persisted. Check your connection.");
  return false;
}

// DECISION(v1.19.407): Snapshot system — saves panel state before destructive operations.
// Stored in Firestore at {projectPath}/_snapshots/{timestamp}. Max 10 per project, auto-cleanup oldest.
async function saveSnapshot(uid,projectId,panel,reason){
  try{
    const path=_appCtx.projectsPath||`users/${uid}/projects`;
    const snapPath=`${path}/${projectId}/_snapshots`;
    const snap={panelId:panel.id,panelName:panel.name||"",reason,createdAt:Date.now(),
      bom:JSON.parse(JSON.stringify(panel.bom||[])),
      pricing:panel.pricing||null,validation:panel.validation||null,laborData:panel.laborData||null,
      status:panel.status||"draft"};
    await fbDb.collection(snapPath).add(snap);
    // Auto-cleanup: keep only last 10 snapshots per project
    const allSnaps=await fbDb.collection(snapPath).orderBy("createdAt","desc").get();
    if(allSnaps.size>10){const toDelete=allSnaps.docs.slice(10);for(const d of toDelete)await d.ref.delete().catch(()=>{});}
    console.log(`SNAPSHOT: saved "${reason}" for ${panel.name||panel.id}`);
  }catch(e){console.warn("Snapshot save failed:",e.message);}
}
async function loadSnapshots(uid,projectId){
  try{
    const path=_appCtx.projectsPath||`users/${uid}/projects`;
    const snap=await fbDb.collection(`${path}/${projectId}/_snapshots`).orderBy("createdAt","desc").limit(10).get();
    return snap.docs.map(d=>({id:d.id,...d.data()}));
  }catch(e){console.warn("Snapshot load failed:",e);return[];}
}
async function restoreSnapshot(uid,projectId,snapshot,panel,onUpdate,onSaveImmediate){
  const restored={...panel,bom:snapshot.bom||panel.bom,pricing:snapshot.pricing||panel.pricing,
    validation:snapshot.validation||panel.validation,laborData:snapshot.laborData||panel.laborData,
    status:snapshot.status||panel.status};
  onUpdate(restored);
  try{if(onSaveImmediate)onSaveImmediate(restored);else await saveProject(uid,{...restored});}catch(e){}
  console.log(`SNAPSHOT: restored "${snapshot.reason}" from ${new Date(snapshot.createdAt).toLocaleString()}`);
  return restored;
}

// Save a single panel into its project in Firestore (used by background extraction tasks)
// Uses a mutex to prevent concurrent saves from racing
const _panelSaveLocks={};
async function saveProjectPanel(uid,projectId,panelId,updatedPanel,skipNotify=false){
  // Skip if panel was deleted
  if(window._deletedPanelIds&&window._deletedPanelIds.has(panelId)){console.log("saveProjectPanel: skipped — panel",panelId,"was deleted");return;}
  // Serialize saves per project to prevent race conditions
  const lockKey=projectId;
  while(_panelSaveLocks[lockKey])await _panelSaveLocks[lockKey];
  let resolve;
  _panelSaveLocks[lockKey]=new Promise(r=>{resolve=r;});
  try{
    const path=_appCtx.projectsPath||`users/${uid}/projects`;
    const ref=fbDb.collection(path).doc(projectId);
    const snap=await ref.get();
    if(!snap.exists){resolve();delete _panelSaveLocks[lockKey];return;}
    const proj={id:ref.id,...snap.data()};
    // DECISION(v1.19.738): Symmetric target-panel pages guard. Previously only OTHER
    // panels were protected from zero-pages overwrite; the target panel was "trusted"
    // unconditionally, leaving a hole where a caller handing a broken panel (transient
    // state mid-extraction, accidental spread that drops pages, etc.) could silently
    // wipe its drawings. Now the target is also guarded: if updatedPanel.pages is empty
    // but Firestore already has pages on this panel, we preserve them and log a loud
    // error for triage. Legitimate removal via `removePage` takes an explicit code path
    // that will already have pages=[] AND drawingNo/bom cleared — this guard only
    // misfires on accidents.
    const existingTarget=(proj.panels||[]).find(p=>p.id===panelId);
    let safeUpdated=updatedPanel;
    if(existingTarget&&(existingTarget.pages||[]).length>0&&(updatedPanel.pages||[]).length===0){
      console.error(`SAVE GUARD: refusing to wipe ${existingTarget.pages.length} pages on panel ${panelId} — preserving existing (caller stack: ${(new Error()).stack?.split('\n').slice(1,4).join(' | ')})`);
      safeUpdated={...updatedPanel,pages:existingTarget.pages};
    }
    // DECISION(v1.19.739): Per-page storageUrl regression guard. An extraction running in
    // the background uploads pages to Storage and stamps storageUrl on the Firestore copy.
    // If, in parallel, a UI action triggers saveProjectPanel with stale React state (no
    // storageUrl), the old "replace target panel" logic would wipe the just-stamped URLs.
    // This is the exact failure mode that orphaned all 18 pages of PRJ402079. Now: for each
    // incoming page that lacks storageUrl, restore it from the Firestore copy matched by id.
    // Also restores dataUrl-less pages that regressed to having dataUrl (rare but possible).
    // DECISION(v1.19.776): Same merge applied to reviewNotes + reviewShapes alongside
    // storageUrl. Without it, two reviewers (e.g. Andrew + Jon) writing notes on the
    // same project simultaneously would lose whichever note was overwritten by the
    // later save. Now the later save preserves notes/shapes by id.
    if(existingTarget&&(safeUpdated.pages||[]).length>0&&(existingTarget.pages||[]).length>0){
      const existingById=new Map(existingTarget.pages.map(pg=>[String(pg.id),pg]));
      let restoredCount=0,restoredNotes=0,restoredShapes=0;
      const mergedPages=safeUpdated.pages.map(pg=>{
        const prev=existingById.get(String(pg.id));
        if(!prev)return pg;
        const patch={};
        if(!pg.storageUrl&&prev.storageUrl){patch.storageUrl=prev.storageUrl;restoredCount++;}
        if(Array.isArray(prev.reviewNotes)&&prev.reviewNotes.length>0){
          const incoming=Array.isArray(pg.reviewNotes)?pg.reviewNotes:[];
          const incomingIds=new Set(incoming.map(n=>n&&n.id).filter(Boolean));
          const missing=prev.reviewNotes.filter(n=>n&&n.id&&!incomingIds.has(n.id));
          if(missing.length>0){patch.reviewNotes=[...incoming,...missing];restoredNotes+=missing.length;}
        }
        if(Array.isArray(prev.reviewShapes)&&prev.reviewShapes.length>0){
          const incoming=Array.isArray(pg.reviewShapes)?pg.reviewShapes:[];
          const incomingIds=new Set(incoming.map(s=>s&&s.id).filter(Boolean));
          const missing=prev.reviewShapes.filter(s=>s&&s.id&&!incomingIds.has(s.id));
          if(missing.length>0){patch.reviewShapes=[...incoming,...missing];restoredShapes+=missing.length;}
        }
        return Object.keys(patch).length?{...pg,...patch}:pg;
      });
      if(restoredCount>0||restoredNotes>0||restoredShapes>0){
        const parts=[];
        if(restoredCount>0)parts.push(`storageUrl×${restoredCount}`);
        if(restoredNotes>0)parts.push(`reviewNotes×${restoredNotes}`);
        if(restoredShapes>0)parts.push(`reviewShapes×${restoredShapes}`);
        console.warn(`SAVE GUARD: restored ${parts.join(", ")} on panel ${panelId} — incoming save had stale page state (caller stack: ${(new Error()).stack?.split('\n').slice(1,4).join(' | ')})`);
        safeUpdated={...safeUpdated,pages:mergedPages};
      }
    }
    // DECISION(v1.19.743): Drawing Version bump. Compares the BOM hash of the incoming
    // panel against the Firestore copy and assigns a fresh `bomVersion` when they differ.
    // First-ever BOM extraction sets v.1; any subsequent BOM mutation (manual edit, re-
    // extract with new output, supplier-apply, scraper-apply) bumps. Re-saves with no BOM
    // change leave the field untouched. Existing pre-v1.19.743 panels with no version stay
    // un-versioned until their first mutation under the new code (per user spec — "leave
    // existing panels as-is").
    safeUpdated=_bumpBomVersionIfChanged(safeUpdated,existingTarget);
    let panels=(proj.panels||[]).map(p=>p.id===panelId?safeUpdated:p);
    // If panel wasn't found in existing array, append it
    if(!panels.some(p=>p.id===panelId))panels=[...panels,safeUpdated];
    // SAFETY: preserve pages from Firestore if updatedPanel has none but Firestore has some
    panels=panels.map(p=>{
      if(p.id===panelId)return p; // already guarded above
      const existing=(proj.panels||[]).find(ep=>ep.id===p.id);
      if(existing&&(existing.pages||[]).length>0&&(p.pages||[]).length===0){
        return{...p,pages:existing.pages}; // preserve existing pages for other panels
      }
      return p;
    });
    let liveProject={...proj,panels,updatedAt:Date.now(),schemaVersion:APP_SCHEMA_VERSION};
    // DECISION(v1.19.744): Quote Rev bump on per-panel save. Same logic as in saveProject —
    // hash the quote-relevant content; if it differs from the persisted hash, bump.
    // saveProjectPanel is the more common save path (every BOM-row edit hits it), so this
    // is where most live-bumps actually fire.
    // DECISION(v1.19.850, ECO Stage A): Bumps suppressed while a draft ECO is
    // active — see saveProject for the rationale. Hash is still refreshed so
    // the post-ECO save sees a clean baseline.
    const _hasActiveEcoSPP=!!liveProject.ecoEditUnlocked||(Array.isArray(liveProject.ecoSummary)&&liveProject.ecoSummary.some(e=>e&&e.status==="draft"));
    const oldQuoteHash=proj.lastQuoteHash;
    const newQuoteHash=_computeQuoteHash(liveProject);
    if(oldQuoteHash){
      if(newQuoteHash!==oldQuoteHash&&!_hasActiveEcoSPP){
        liveProject={...liveProject,quoteRev:(liveProject.quoteRev||1)+1,lastQuoteHash:newQuoteHash};
        console.log(`[QUOTE REV] bumped to ${liveProject.quoteRev} (panel save)`);
      }else if(newQuoteHash!==oldQuoteHash&&_hasActiveEcoSPP){
        liveProject={...liveProject,lastQuoteHash:newQuoteHash};
        console.log("[QUOTE REV] suppressed (panel save) — active ECO in flight");
      }
    }else{
      liveProject={...liveProject,quoteRev:liveProject.quoteRev||1,lastQuoteHash:newQuoteHash};
    }
    const stripped=JSON.parse(JSON.stringify({...liveProject,panels:liveProject.panels.map(p=>({...p,pages:(p.pages||[]).map(pg=>{const{dataUrl,...r}=pg;return r;})}))}));
    await ref.set(stripped);
    if(!skipNotify)notifyProjectListeners(projectId,liveProject);
  }finally{resolve();delete _panelSaveLocks[lockKey];}
}
async function loadProjects(uid){
  const path=_appCtx.projectsPath||`users/${uid}/projects`;
  const snap=await fbDb.collection(path).orderBy("updatedAt","desc").get();
  return snap.docs.map(d=>migrateProjectShape(d.data()));
}

// DECISION(v1.19.785): Lazy migration shim for projects loaded from Firestore. Anything
// the ECO system relies on gets defaulted in memory so render code can assume the fields
// exist. Persisted Firestore docs are unchanged; the next save through saveProject()
// stamps the new schemaVersion + writes the defaults back. Keeps legacy projects working
// without forcing a backfill batch job. Add additional migration logic here as schemaVersion
// climbs further (v3 = ECO introduction).
function migrateProjectShape(p){
  if(!p)return p;
  const out={...p};
  if(out.ecoCounter==null)out.ecoCounter=0;
  if(out.activeEcoId===undefined)out.activeEcoId=null;
  if(!Array.isArray(out.ecoSummary))out.ecoSummary=[];
  // DECISION(v1.19.834, ECO Stage 0): One-time cleanup of legacy Phase 2 ECO data.
  // The original Phase 2 BOM Delta tab created tagged rows (ecoTag/ecoOp) on
  // panel.bom plus stored ECOs in a subcollection. The redesign uses the same
  // tag fields but with a different model (in-place modify with `ecoOriginal`).
  // For projects that were tested under the old model (PRJ402064 specifically,
  // but this runs against any project with legacy fields), strip the old data
  // so the new flow starts clean. Idempotent — once a project has no tagged
  // rows / pages and no ecoSummary entries, this is a no-op.
  let _ecoCleanupApplied=false;
  if(Array.isArray(out.panels)){
    out.panels=out.panels.map(panel=>{
      const newBom=Array.isArray(panel.bom)?panel.bom.filter(r=>!r.ecoTag):panel.bom;
      const bomChanged=Array.isArray(panel.bom)&&newBom.length!==panel.bom.length;
      let newPages=panel.pages;
      let pagesChanged=false;
      if(Array.isArray(panel.pages)){
        newPages=panel.pages.map(pg=>{
          if(!pg.ecoTag&&!pg.ecoId&&pg.ecoNumber==null&&pg.ecoUploadedAt==null)return pg;
          pagesChanged=true;
          const{ecoTag:_a,ecoId:_b,ecoNumber:_c,ecoUploadedAt:_d,aiDetectedTypes:_e,...rest}=pg;
          return rest;
        });
      }
      if(bomChanged||pagesChanged){
        _ecoCleanupApplied=true;
        return{...panel,bom:newBom,pages:newPages};
      }
      return panel;
    });
  }
  // If we stripped tagged rows/pages OR the project still has ecoSummary entries
  // pointing at orphaned subcollection ECO docs from Phase 2, reset project-level
  // ECO state so the new model starts fresh.
  if(_ecoCleanupApplied||(Array.isArray(out.ecoSummary)&&out.ecoSummary.length>0&&!out._ecoLegacyMigrated)){
    if(_ecoCleanupApplied||out.ecoSummary.length>0){
      out.ecoCounter=0;
      out.ecoSummary=[];
      out.activeEcoId=null;
      out._ecoLegacyMigrated=true;
    }
  }
  return out;
}
async function deleteProject(uid,id){
  const path=_appCtx.projectsPath||`users/${uid}/projects`;
  await fbDb.doc(`${path}/${id}`).delete();
}
// DECISION(v1.19.747): Cascade-delete the project's pageImages blobs from Firebase
// Storage. Without this, deleting a project from ARC leaves all the drawing JPEGs
// orphaned at `pageImages/{uid}/{projectId}/...` — the audit found 16 such projects
// with ~441MB of dead weight.
//
// Strategy: collect the union of uids that may have uploaded pages for this project
// (the deleter, `project.createdBy`, plus any uid encoded in each page's storageUrl),
// then run `listAll()` on `pageImages/{uid}/{projectId}/` for each candidate and delete
// every blob found. Storage rules on `pageImages/{uid}/**` permit any authenticated
// user to read+delete (`storage.rules:6-8`), so this works even when the deleter
// wasn't the original uploader. Best-effort — never throws; failures get logged so
// the Firestore doc deletion still succeeds.
async function deleteProjectStorageBlobs(currentUid,projectId,project){
  const uids=new Set();
  if(currentUid)uids.add(currentUid);
  if(project?.createdBy)uids.add(project.createdBy);
  // Walk every page's storageUrl to harvest uids — handles team-member uploads.
  for(const pan of (project?.panels||[])){
    for(const pg of (pan?.pages||[])){
      const url=pg?.storageUrl;
      if(!url)continue;
      const m=url.match(/\/o\/pageImages%2F([^%/]+)%2F/);
      if(m&&m[1])uids.add(decodeURIComponent(m[1]));
    }
  }
  if(uids.size===0)return{deleted:0,failed:0,uids:[]};
  let deleted=0,failed=0;
  const errors=[];
  for(const uid of uids){
    try{
      const folderRef=fbStorage.ref(`pageImages/${uid}/${projectId}`);
      const list=await folderRef.listAll();
      for(const item of (list.items||[])){
        try{await item.delete();deleted++;}
        catch(e){failed++;errors.push(`${item.fullPath}: ${e.message||e}`);}
      }
    }catch(e){
      // listAll failure (e.g. folder doesn't exist) is fine — just no blobs at that prefix.
      console.log(`[CASCADE DELETE] no pageImages found at pageImages/${uid}/${projectId} (${e.code||"unknown"})`);
    }
  }
  if(failed>0)console.warn(`[CASCADE DELETE] failed to delete ${failed} blob(s):`,errors.slice(0,5));
  console.log(`[CASCADE DELETE] project ${projectId} — deleted ${deleted} pageImage blob(s) across ${uids.size} uid(s)`);
  return{deleted,failed,uids:[...uids]};
}

// ── COPY PROJECT ──
async function copyProject(uid,sourceProject,onProgress){
  const pp=onProgress||(()=>{});
  const src=sourceProject;
  const srcPanels=src.panels||[];

  // Step 1: Create new BC project with same customer
  pp({step:"bc",msg:"Creating BC project…",pct:5});
  if(!_bcToken)await acquireBcToken(true);
  if(!_bcToken)throw new Error("Could not connect to Business Central");
  const bc=await bcCreateProject(src.name+" (Copy)",src.bcCustomerNumber);

  // Step 2: Create panel task structure in BC
  pp({step:"tasks",msg:"Creating BC tasks…",pct:15});
  const panelStubs=srcPanels.map((p,i)=>({id:`panel-${i+1}`,name:p.name||`Panel ${i+1}`}));
  try{await bcCreatePanelTaskStructure(bc.number,src.name+" (Copy)",panelStubs);}catch(e){console.warn("Copy: task structure warning:",e.message);}

  // Step 3: Deep clone panels (BOM, validation, labor, pages metadata)
  pp({step:"clone",msg:"Cloning panel data…",pct:25});
  const newPanels=srcPanels.map((panel,i)=>{
    const newPages=(panel.pages||[]).map(pg=>({...pg,id:`pg-${Date.now()}-${Math.random().toString(36).slice(2,8)}`,dataUrl:undefined,storageUrl:undefined,_srcStorageUrl:pg.storageUrl||null,_srcPageId:pg.id}));
    const newBom=(panel.bom||[]).map(r=>({...r,id:`row-${Date.now()}-${Math.random().toString(36).slice(2,8)}`}));
    return{...panel,id:`panel-${i+1}`,pages:newPages,bom:newBom};
  });

  // Step 4: Save new project to Firestore (without images yet)
  pp({step:"save",msg:"Saving project…",pct:35});
  const newProj=await saveProject(uid,{
    name:src.name+" (Copy)",
    bcProjectId:bc.id,
    bcProjectNumber:bc.number,
    bcEnv:_bcConfig.env,
    bcCustomerNumber:src.bcCustomerNumber,
    bcCustomerName:src.bcCustomerName,
    status:src.status||"draft",
    panels:newPanels,
    quote:src.quote?{...src.quote}:undefined,
    createdAt:Date.now(),updatedAt:Date.now()
  });

  // Step 5: Copy page images from source to new project in Storage
  const allPages=newPanels.flatMap((panel,pi)=>(panel.pages||[]).map((pg,pgi)=>({pi,pgi,pg})));
  const totalPages=allPages.filter(x=>x.pg._srcStorageUrl).length;
  let copied=0;
  for(const{pi,pgi,pg}of allPages){
    if(!pg._srcStorageUrl)continue;
    pp({step:"images",msg:`Copying drawing ${copied+1}/${totalPages}…`,pct:35+Math.round((copied/Math.max(totalPages,1))*40)});
    try{
      const loaded=await ensureDataUrl({storageUrl:pg._srcStorageUrl});
      if(loaded.dataUrl){
        const newUrl=await uploadPageImage(uid,newProj.id,pg.id,loaded.dataUrl);
        newPanels[pi].pages[pgi].storageUrl=newUrl;
        newPanels[pi].pages[pgi].dataUrl=loaded.dataUrl;
      }
    }catch(e){console.warn("Copy image failed for page",pg._srcPageId,e.message);}
    copied++;
  }
  // Clean up temp fields
  newPanels.forEach(panel=>(panel.pages||[]).forEach(pg=>{delete pg._srcStorageUrl;delete pg._srcPageId;}));

  // Step 6: Re-save with storage URLs
  pp({step:"save2",msg:"Saving images…",pct:80});
  const finalProj=await saveProject(uid,{...newProj,panels:newPanels,updatedAt:Date.now()});

  // Step 7: Sync planning lines to BC for each panel
  pp({step:"sync",msg:"Syncing planning lines to BC…",pct:85});
  for(let i=0;i<newPanels.length;i++){
    pp({step:"sync",msg:`Syncing panel ${i+1}/${newPanels.length} to BC…`,pct:85+Math.round((i/newPanels.length)*12)});
    try{await bcSyncPanelPlanningLines(bc.number,i+1,newPanels[i],src.name);}catch(e){console.warn("Copy: planning line sync failed for panel",i+1,e.message);}
  }

  pp({step:"done",msg:"Project copied!",pct:100});
  return finalProj;
}

// ── FIREBASE STORAGE HELPERS ──
async function uploadPageImage(uid,projectId,pageId,dataUrl){
  const ref=fbStorage.ref(`pageImages/${uid}/${projectId}/${pageId}.jpg`);
  _dbg("UPLOAD IMAGE: starting",pageId,"to",ref.fullPath);
  // Use putString with data_url format — avoids blob conversion issues
  const snap=await ref.putString(dataUrl,"data_url");
  _dbg("UPLOAD IMAGE: uploaded",pageId,"state="+snap.state);
  const url=await ref.getDownloadURL();
  _dbg("UPLOAD IMAGE: got URL",pageId);
  return url;
}
async function ensureDataUrl(page){
  if(page.dataUrl)return page;
  if(!page.storageUrl)return page;
  try{
    // Get a fresh download URL from Firebase Storage SDK
    let url=page.storageUrl;
    const pathMatch=page.storageUrl.match(/\/o\/([^?]+)/);
    if(pathMatch){
      const storagePath=decodeURIComponent(pathMatch[1]);
      url=await fbStorage.ref(storagePath).getDownloadURL();
    }
    // Load via <img> + canvas to avoid CORS fetch issues
    const dataUrl=await new Promise((resolve,reject)=>{
      const img=new Image();
      img.crossOrigin="anonymous";
      img.onload=()=>{
        const c=document.createElement("canvas");
        c.width=img.naturalWidth;c.height=img.naturalHeight;
        c.getContext("2d").drawImage(img,0,0);
        resolve(c.toDataURL("image/jpeg",0.92));
      };
      img.onerror=()=>reject(new Error("Image load failed"));
      img.src=url;
    });
    return{...page,dataUrl};
  }catch(e){
    console.warn("ensureDataUrl failed for page",page.id,e);
    return page;
  }
}

// ── PROJECT MIGRATION (flat → panels) ──
function migrateProject(p){
  if(p.panels) return p;
  const panel={id:'panel-1',name:'Panel 1',pages:p.pages||[],bom:p.bom||[],validation:p.validation||null,pricing:p.pricing||null,budgetaryQuote:p.budgetaryQuote||null,status:p.status||'draft'};
  const {pages,bom,validation,pricing,budgetaryQuote,...rest}=p;
  return{...rest,panels:[panel]};
}

// ── PART LIBRARY ──
function _libPath(uid){
  return _appCtx.configPath?`${_appCtx.configPath}/partLibrary`:`users/${uid}/config/partLibrary`;
}
function _libKey(manufacturer,description){
  const n=s=>(s||"").toLowerCase().replace(/[^a-z0-9\s]/g,"").replace(/\s+/g," ").trim();
  return `${n(manufacturer)}||${n(description).slice(0,80)}`;
}
async function loadPartLibrary(uid){
  try{const d=await fbDb.doc(_libPath(uid)).get();return d.exists?(d.data().entries||[]):[];}
  catch(e){return[];}
}
async function savePartLibraryEntry(uid,{manufacturer,description,partNumber}){
  if(!partNumber||!partNumber.trim())return;
  if(!manufacturer&&!description)return;
  const path=_libPath(uid);
  let entries=[];
  try{const d=await fbDb.doc(path).get();if(d.exists)entries=d.data().entries||[];}catch(e){}
  const key=_libKey(manufacturer,description);
  const idx=entries.findIndex(e=>e.key===key);
  const entry={key,manufacturer:manufacturer||"",description:description||"",partNumber:partNumber.trim(),updatedAt:Date.now()};
  if(idx>=0)entries[idx]=entry;else entries.push(entry);
  await fbDb.doc(path).set({entries});
}
function findPartSuggestion(library,row){
  if(!library||!library.length)return null;
  if(row.partNumber&&row.partNumber.trim())return null;
  if(!row.manufacturer&&!row.description)return null;
  const n=s=>(s||"").toLowerCase().replace(/[^a-z0-9\s]/g,"").replace(/\s+/g," ").trim();
  const exact=library.find(e=>e.key===_libKey(row.manufacturer,row.description));
  if(exact)return exact.partNumber;
  const words=s=>s.split(/\s+/).filter(w=>w.length>2);
  const rowWords=words(n(row.description));
  if(rowWords.length<2)return null;
  const mfr=n(row.manufacturer);
  let best=null,bestScore=0;
  for(const e of library){
    const eMfr=n(e.manufacturer);
    if(mfr&&eMfr&&!eMfr.includes(mfr)&&!mfr.includes(eMfr))continue;
    const eWords=words(n(e.description));
    const common=rowWords.filter(w=>eWords.includes(w)).length;
    const score=common/Math.max(rowWords.length,eWords.length,1);
    if(score>0.6&&score>bestScore){bestScore=score;best=e.partNumber;}
  }
  return best;
}
async function loadPartCorrections(uid){
  try{const d=await fbDb.doc(_libPath(uid)).get();return d.exists?(d.data().corrections||[]):[];}
  catch(e){return[];}
}
async function savePartCorrection(uid,{wrongValue,correctValue,description,manufacturer}){
  if(!wrongValue||!wrongValue.trim()||!correctValue||!correctValue.trim())return;
  const path=_libPath(uid);
  let corrections=[];
  try{const d=await fbDb.doc(path).get();if(d.exists)corrections=d.data().corrections||[];}catch(e){}
  const key=(wrongValue||"").trim().toLowerCase();
  const idx=corrections.findIndex(c=>c.key===key);
  const entry={key,wrongValue:wrongValue.trim(),correctValue:correctValue.trim(),description:description||"",manufacturer:manufacturer||"",updatedAt:Date.now()};
  if(idx>=0)corrections[idx]=entry;else corrections.push(entry);
  try{await fbDb.doc(path).set({corrections},{merge:true});}catch(e){}
}
function applyPartCorrections(corrections,bom){
  if(!corrections||!corrections.length)return bom;
  return bom.map(row=>{
    if(!row.partNumber||!row.partNumber.trim())return row;
    const key=(row.partNumber||"").trim().toLowerCase();
    const match=corrections.find(c=>c.key===key);
    return match?{...row,partNumber:match.correctValue,correctedByLibrary:true}:row;
  });
}

// DECISION(v1.19.626): Centralized learning-DB application. Runs on EVERY newly-extracted BOM
// (initial, re-extract, feedback re-extract). Applies in this order:
//   1. Alternates (autoReplace=true)         → sets isCrossed + crossedFrom + autoReplaced
//   2. Correction DB (bad PN → corrected PN) → sets isCorrection + correctionFrom
//   3. Part library corrections              → sets correctedByLibrary
//   4. Supplier cross-refs                   → sets crossRef (informational, PN unchanged)
// Each path checks the row's existing flags so corrections don't cascade/double-apply.
// The resulting flags (isCrossed/isCorrection/correctedByLibrary) are THE signal that tells
// the audit's self-healing NOT to override these rows — the user has already vetted them.
async function applyLearnedCorrections(bom,uid){
  if(!bom||!bom.length||!uid)return{bom,appliedLog:[]};
  let userAlts=[],userCorrs=[],userPartCorrs=[];
  try{[userAlts,userCorrs,userPartCorrs]=await Promise.all([
    loadAlternates(uid).catch(()=>[]),
    loadCorrectionDB(uid).catch(()=>[]),
    loadPartCorrections(uid).catch(()=>[]),
  ]);}catch(e){console.warn("applyLearnedCorrections: load failed:",e.message);return{bom,appliedLog:[]};}
  if(!userAlts.length&&!userCorrs.length&&!userPartCorrs.length)return{bom,appliedLog:[]};
  const normPN=s=>(s||"").replace(/[-\s./\\]/g,"").toUpperCase();
  const appliedLog=[];
  const result=bom.map(r=>{
    if(r.isLaborRow||r.isContingency)return r;
    const pn=(r.partNumber||"").trim();
    if(!pn)return r;
    // 1. Auto-replace alternates (part crosses)
    // DECISION(v1.19.635/638): Swap PN/description + flag as crossed/BC-locked. Carry over
    // the cached unitPrice from the learning DB (so the row isn't momentarily blank before
    // BC lookup confirms) but leave priceDate null — the UI shows "—" in the Priced column
    // until runPricingOnPanel fetches the real BC Starting_Date. priceSource="bc" tells the
    // pricing phase to use an EXACT BC lookup, preventing re-crossing of an already-crossed PN.
    if(!r.isCrossed){
      const alt=userAlts.find(a=>a.autoReplace&&a.replacement&&(a.originalPN===pn||normPN(a.originalPN)===normPN(pn)));
      if(alt){
        appliedLog.push({rowId:r.id,kind:"alternate",from:pn,to:alt.replacement.partNumber,reason:"auto-cross from learning DB"});
        return{...r,partNumber:alt.replacement.partNumber,description:alt.replacement.description||r.description,unitPrice:alt.replacement.unitCost??r.unitPrice,priceSource:"bc",priceDate:null,isCrossed:true,crossedFrom:pn,autoReplaced:true};
      }
    }
    // 2. Bad PN → corrected PN (from correctionDB)
    if(!r.isCorrection){
      const corr=userCorrs.find(c=>c.badPN===pn||normPN(c.badPN)===normPN(pn));
      if(corr&&corr.correctedPN){
        appliedLog.push({rowId:r.id,kind:"correction",from:pn,to:corr.correctedPN,reason:"auto-fix from correction DB"});
        return{...r,partNumber:corr.correctedPN,isCorrection:true,correctionType:corr.type||"extraction",correctionFrom:pn};
      }
    }
    // 3. Part library correction (legacy partLibrary.corrections)
    if(!r.correctedByLibrary){
      const pcKey=pn.toLowerCase();
      const pc=userPartCorrs.find(c=>c.key===pcKey);
      if(pc&&pc.correctValue){
        appliedLog.push({rowId:r.id,kind:"partCorrection",from:pn,to:pc.correctValue,reason:"auto-fix from part library"});
        return{...r,partNumber:pc.correctValue,correctedByLibrary:true};
      }
    }
    return r;
  });
  if(appliedLog.length>0){
    console.log(`[LEARNING DB] Applied ${appliedLog.length} correction${appliedLog.length>1?"s":""} from memory:`,appliedLog.map(l=>`${l.kind}: ${l.from} → ${l.to}`));
  }
  return{bom:result,appliedLog};
}

// ── DEFAULT BOM ITEMS (appended after extraction if not already present) ──
// DECISION(v1.19.413): Combined "BOM CONTINGENCY" + "WIRE & CONSUMABLES" into single "Contingency" item.
// Old items changed to Inventory type in BC and can't be retyped — new Non-Inventory item created.
// Price is sum of both old defaults. Old part numbers kept in CONTINGENCY_PNS for backward compatibility
// so existing projects with old items still get recognized as contingency rows.
const CONTINGENCY_ITEMS=[
  {partNumber:"Contingency",description:"Contingency",getPrice:()=>((_pricingConfig.contingencyBOM||1500)+(_pricingConfig.contingencyConsumables||400))}
];
const CONTINGENCY_PNS=new Set([...CONTINGENCY_ITEMS.map(c=>c.partNumber.toUpperCase()),"BOM CONTINGENCY","WIRE & CONSUMABLES"]);

// DECISION(v1.19.629): Sort the extracted BOM in the same top-to-bottom order the rows appear
// on the drawing. This lets the user spot-check by visually scanning the drawing alongside
// ARC's list. Rows without position data (manual additions, labor, contingency, defaults)
// stay at the end in their existing order — preserved for stable UX.
function sortBomByDrawingPosition(bom){
  if(!Array.isArray(bom)||bom.length<2)return bom;
  const positioned=[],unpositioned=[];
  for(const r of bom){
    if(r.isLaborRow||r.isContingency){unpositioned.push(r);continue;}
    if(typeof r.y_top==="number"&&!isNaN(r.y_top)){positioned.push(r);}
    else{unpositioned.push(r);}
  }
  positioned.sort((a,b)=>{
    const pa=+a.sourcePageIdx||0,pb=+b.sourcePageIdx||0;
    if(pa!==pb)return pa-pb;
    const yDiff=(a.y_top||0)-(b.y_top||0);
    if(Math.abs(yDiff)>0.002)return yDiff;
    return (a.x_left||0)-(b.x_left||0);
  });
  return [...positioned,...unpositioned];
}

function appendDefaultBomItems(bom){
  console.log("APPEND DEFAULTS: _defaultBomItems=",_defaultBomItems.length,"items:",_defaultBomItems.map(d=>d.description));
  const lower=new Set(bom.map(r=>(r.description||"").trim().toLowerCase()));
  const pnSet=new Set(bom.map(r=>(r.partNumber||"").trim().toUpperCase()));
  console.log("APPEND DEFAULTS: existing BOM descriptions:",[...lower]);
  const _laborPns=new Set(LABOR_BOM_GROUPS.map(g=>g.partNumber));
  const items=[];
  if(_defaultBomItems.length){
    for(const tpl of _defaultBomItems){
      if(_laborPns.has((tpl.partNumber||"").trim()))continue;
      const desc=(tpl.description||"").trim().toLowerCase();
      if(desc&&lower.has(desc)){console.log("APPEND DEFAULTS: skipped (duplicate):",tpl.description);continue;}
      items.push({id:Date.now()+Math.random(),qty:tpl.qty||1,partNumber:tpl.partNumber||"",description:tpl.description||"",manufacturer:tpl.manufacturer||"",notes:"",unitPrice:tpl.unitPrice||0,priceSource:tpl.priceSource||null,priceDate:Date.now(),autoLoaded:true});
      console.log("APPEND DEFAULTS: adding:",tpl.description,"$"+tpl.unitPrice);
    }
  }
  // Always append contingency items if not already present
  for(const ci of CONTINGENCY_ITEMS){
    if(pnSet.has(ci.partNumber.toUpperCase()))continue;
    if(lower.has(ci.description.toLowerCase()))continue;
    items.push({id:Date.now()+Math.random(),qty:1,partNumber:ci.partNumber,description:ci.description,manufacturer:"Matrix Systems",notes:"",unitPrice:ci.getPrice(),priceSource:"bc",priceDate:Date.now(),bcPoDate:Date.now(),bcVendorName:"Matrix Systems",autoLoaded:true,isContingency:true});
    console.log("APPEND DEFAULTS: adding contingency:",ci.partNumber,"$"+ci.getPrice());
  }
  console.log("APPEND DEFAULTS: appended",items.length,"defaults. BOM total:",bom.length+items.length);
  return items.length?[...bom,...items]:bom;
}

// ── BOM MERGER (combine by partNumber, sum qty) ──
// DECISION(v1.19.597): Fuzzy BOM dedup to collapse OCR-variant duplicates.
// Users reported ~40% false-duplicate rate on scanned drawings (PRJ402079: 51 items → 71 extracted)
// where the same part reads differently on page 1 vs page 2 (O/0, B/8, S/5, missing chars).
// Strategy: after exact-normalized merge, run an edit-distance pass that collapses near-duplicates
// when manufacturer matches AND description is similar (both signals → almost certainly same part).
// Bounded Levenshtein — early-exits once distance exceeds threshold, so it's fast on long lists.
function _bomLevDistBounded(a,b,max){
  if(a===b)return 0;
  const la=a.length,lb=b.length;
  if(Math.abs(la-lb)>max)return max+1;
  if(!la)return lb;if(!lb)return la;
  const prev=new Array(lb+1),curr=new Array(lb+1);
  for(let j=0;j<=lb;j++)prev[j]=j;
  for(let i=1;i<=la;i++){
    curr[0]=i;let rowMin=curr[0];
    for(let j=1;j<=lb;j++){
      const cost=a.charCodeAt(i-1)===b.charCodeAt(j-1)?0:1;
      curr[j]=Math.min(prev[j]+1,curr[j-1]+1,prev[j-1]+cost);
      if(curr[j]<rowMin)rowMin=curr[j];
    }
    if(rowMin>max)return max+1;
    for(let j=0;j<=lb;j++)prev[j]=curr[j];
  }
  return prev[lb];
}
function _bomNormPn(s){return(s||"").replace(/[\s\-\.\/\u00a0_]+/g,"").toUpperCase();}
function _bomDescSim(a,b){
  // Return true if descriptions are similar enough to be the same item
  const na=(a||"").replace(/\s+/g," ").trim().toLowerCase();
  const nb=(b||"").replace(/\s+/g," ").trim().toLowerCase();
  if(!na||!nb)return false;
  if(na===nb)return true;
  // First 25 chars match (same prefix = same item, just truncated differently)
  if(na.length>=15&&nb.length>=15&&na.slice(0,25)===nb.slice(0,25))return true;
  // One is a prefix of the other (truncation)
  if(na.startsWith(nb)||nb.startsWith(na))return true;
  // Word-level overlap: ≥60% of words shared
  const wa=new Set(na.split(/\s+/).filter(w=>w.length>2));
  const wb=new Set(nb.split(/\s+/).filter(w=>w.length>2));
  if(!wa.size||!wb.size)return false;
  let shared=0;for(const w of wa)if(wb.has(w))shared++;
  return shared/Math.max(wa.size,wb.size)>=0.6;
}
// Fuzzy merge: assumes exact-normalized dedup has already run. Collapses near-duplicates.
// Returns { items, merges } where merges is [{ kept, dropped, editDist, reason, manufacturer, description }].
function fuzzyMergeBomItemsWithReport(items){
  const out=[];const consumed=new Set();const merges=[];
  for(let i=0;i<items.length;i++){
    if(consumed.has(i))continue;
    let base=items[i];
    const pnA=_bomNormPn(base.partNumber);
    if(pnA.length<5){out.push(base);continue;} // too short → skip fuzzy (too many false matches)
    const mfrA=(base.manufacturer||"").trim().toLowerCase();
    for(let j=i+1;j<items.length;j++){
      if(consumed.has(j))continue;
      const b=items[j];
      const pnB=_bomNormPn(b.partNumber);
      if(pnB.length<5)continue;
      if(pnA===pnB)continue; // exact dedup already handled elsewhere
      // Length delta ≤ 2 keeps us safe (OCR typically adds/drops 1-2 chars)
      if(Math.abs(pnA.length-pnB.length)>2)continue;
      // DECISION(v1.19.628): CRITICAL Y-position guard. If both items have y_top and they're
      // at materially different positions on the page, they are DIFFERENT ROWS in the same
      // BOM table — never merge. This was silently destroying legitimate product-family
      // variants (Allen-Bradley 800FP-F2/F3/F4 pilot lights that differ only by color code,
      // Phoenix Contact 2907561/2907563/2907566 terminal blocks, etc.). All are real BC parts.
      // Positional dedup runs before fuzzy and only collapses items at the SAME Y (cross-quadrant
      // duplicates, which we no longer generate anyway after v1.19.622 full-page revert). For
      // single-pass extraction, fuzzy should ONLY merge items without Y data OR items at the
      // same Y (already handled). If both have Y and they differ, STOP.
      //
      // DECISION(v1.19.642): Override Y-guard ONLY when descriptions are IDENTICAL (after
      // normalization — whitespace / punctuation stripped). Legit product-family variants
      // (800FP-F2 "Flush, Green" vs 800FP-F3 "Flush, Red") always have distinguishing
      // descriptions. Identical descriptions at different Y-positions + near-identical PN
      // = AI-hallucinated duplicate (e.g. WKDH12126 + WKDH2126). Catches this case while
      // still protecting the variant-family pattern the original guard was added for.
      let ydiffOcrDupOverride=false;
      if(typeof base.y_top==="number"&&typeof b.y_top==="number"){
        const yDiff=Math.abs((base.y_top||0)-(b.y_top||0));
        if(yDiff>0.008){
          const normDesc=s=>(s||"").replace(/[\s,.()\/\-]/g,"").toLowerCase();
          const dA=normDesc(base.description),dB=normDesc(b.description);
          const descIdentical=dA&&dB&&dA===dB&&dA.length>=8;
          if(!descIdentical){
            // Different rows, distinguishing descriptions → legit variants, don't merge.
            continue;
          }
          ydiffOcrDupOverride=true; // signal: merge but use MAX qty, not SUM
        }
      }
      // Edit-distance threshold scales with PN length — short PNs get stricter
      const maxLen=Math.max(pnA.length,pnB.length);
      const threshold=maxLen<=8?1:maxLen<=14?2:3;
      const ed=_bomLevDistBounded(pnA,pnB,threshold);
      if(ed>threshold)continue;
      // Guard: require either matching manufacturer OR matching description
      // (both signals would be ideal but users don't always fill both)
      const mfrB=(b.manufacturer||"").trim().toLowerCase();
      const mfrMatch=mfrA&&mfrB&&mfrA===mfrB;
      const descMatch=_bomDescSim(base.description,b.description);
      if(!mfrMatch&&!descMatch)continue;
      // Both signals weak? require stricter edit distance
      if(!mfrMatch&&descMatch&&ed>1)continue;
      if(mfrMatch&&!descMatch&&ed>2)continue;
      // Merge: prefer the LONGER partNumber as canonical (more chars = more likely correct reading)
      const keepA=pnA.length>=pnB.length;
      const mergedNotes=[base.notes,b.notes].filter(Boolean).join("; ")||base.notes||b.notes||"";
      const kept=keepA?base.partNumber:b.partNumber;
      const dropped=keepA?b.partNumber:base.partNumber;
      merges.push({
        kept,dropped,editDist:ed,
        reason:mfrMatch&&descMatch?"mfr+desc match":mfrMatch?"mfr match":"desc match",
        manufacturer:base.manufacturer||b.manufacturer||"",
        description:((base.description||"").length>=(b.description||"").length?base.description:b.description)||"",
      });
      // DECISION(v1.19.642): When the Y-guard was overridden because descriptions were identical,
      // use MAX qty — not SUM. A hallucinated duplicate row shouldn't double the quantity. Legit
      // same-item-twice cases (rare) are already handled by positional dedup upstream. Normal
      // fuzzy merges (same-Y or no-Y) still sum, since those are legit repeat rows.
      const mergedQty=ydiffOcrDupOverride
        ? Math.max(+base.qty||1,+b.qty||1)
        : (+base.qty||1)+(+b.qty||1);
      base={
        ...base,
        partNumber:kept,
        qty:mergedQty,
        description:(base.description||"").length>=(b.description||"").length?base.description:b.description,
        manufacturer:base.manufacturer||b.manufacturer,
        notes:mergedNotes,
      };
      consumed.add(j);
      console.log(`BOM FUZZY MERGE${ydiffOcrDupOverride?" (OCR-dup override)":""}: "${dropped}" → "${kept}" (editDist=${ed}, qty=${base.qty})`);
    }
    out.push(base);
  }
  return {items:out,merges};
}
// Back-compat wrapper (items-only)
function fuzzyMergeBomItems(items){return fuzzyMergeBomItemsWithReport(items).items;}

// DECISION(v1.19.620): Positional BOM dedup — same Y position in the original page means
// same row, regardless of how different quadrants read the part number/description.
// This is critical for the v1.19.603 quadrant extraction which can produce 2–4 readings
// of the same row (if the row falls in the overlap region between quadrants). Fuzzy PN
// dedup catches variants where MFR or description match, but misses cases where the AI
// read the description differently in each quadrant (e.g. truncated at a quadrant edge).
// Y-coord match is a near-deterministic signal: rows in a BOM table are horizontal, and
// our translateItemsToPageCoords(v1.19.603) normalizes Y to original-page fractions.
function positionalMergeBomItems(items){
  // Items without y_top are passed through untouched (legacy rows, manual adds, labor rows, etc.).
  // DECISION(v1.19.645): CRITICAL fix — items without sourcePageIdx also bypass positional
  // dedup. Previously items from DIFFERENT pages at similar Y coordinates were wrongly
  // merged as duplicates. For a 2-page BOM this dropped ~50% of page-2 rows because their
  // y_top values (0–1, per-page) collided with page-1 y_top values. Now positional dedup
  // ONLY merges items from the SAME page.
  const withY=[],withoutY=[];
  for(const it of items){
    if(typeof it.y_top==="number"&&typeof it.y_bottom==="number"&&it.y_bottom>it.y_top&&typeof it.sourcePageIdx==="number"){
      withY.push(it);
    }else{
      withoutY.push(it);
    }
  }
  if(withY.length<2)return items;
  // Sort by (sourcePageIdx, y_top) so same-page items cluster together. Inner loop breaks
  // when sourcePageIdx changes — never compares items across different pages.
  withY.sort((a,b)=>{
    if(a.sourcePageIdx!==b.sourcePageIdx)return a.sourcePageIdx-b.sourcePageIdx;
    return (a.y_top||0)-(b.y_top||0);
  });
  const merged=[];const consumed=new Set();const posMerges=[];
  // DECISION(v1.19.630): Tightened from 0.008 to 0.004 (0.4% of page). For a tight BOM with
  // 51 rows over 60% of page height, row spacing ≈ 1.18%; 0.8% was close enough to that
  // spacing that AI noise could make adjacent rows merge. 0.4% is safer for dense tables.
  // Since the v1.19.622 quadrant revert, we no longer need loose tolerance to catch cross-
  // quadrant duplicates (there are none in single-pass extraction).
  const Y_TOL=0.004;
  for(let i=0;i<withY.length;i++){
    if(consumed.has(i))continue;
    let base={...withY[i]};
    for(let j=i+1;j<withY.length;j++){
      if(consumed.has(j))continue;
      const b=withY[j];
      // DECISION(v1.19.645): Different page → not the same row, and sorted by page first
      // so no further candidates can match this base either. Break out immediately.
      if(b.sourcePageIdx!==base.sourcePageIdx)break;
      // Y-tops within tolerance → likely same row
      if(Math.abs((b.y_top||0)-(base.y_top||0))>Y_TOL){
        // Sorted by y_top within same page — if we've exceeded tolerance, no more candidates.
        break;
      }
      // Also require similar y_bottom (guards against rows that happen to start at the same y but span different heights, e.g. multi-line cell vs single-line).
      if(Math.abs((b.y_bottom||0)-(base.y_bottom||0))>Y_TOL*2)continue;
      // DECISION(v1.19.622): Keep the ENTIRE row data from the more-complete source, not
      // independent max-length per field. Previous bug: picking the longest PN from source A
      // and longest description from source B could glue the wrong description to a part #
      // (producing scrambled BOM rows). Now we pick the source with more populated fields
      // and use ITS values as a coherent unit. Qty is MAX (a row has one qty, regardless of
      // how many sources saw it).
      const scoreItem=(it)=>{
        let s=0;
        if((it.partNumber||"").trim())s+=3;
        if((it.description||"").trim())s+=2;
        if((it.manufacturer||"").trim())s+=1;
        if((it.itemNo||"").trim())s+=1;
        if((+it.qty||0)>0)s+=1;
        return s+((it.partNumber||"").length*0.01)+((it.description||"").length*0.005);
      };
      const winner=scoreItem(b)>scoreItem(base)?b:base;
      const keepQty=Math.max(+base.qty||1,+b.qty||1);
      const keepNotes=[base.notes,b.notes].filter(Boolean).join("; ")||"";
      posMerges.push({
        kept:winner.partNumber,dropped:winner===base?b.partNumber:base.partNumber,
        y:base.y_top?.toFixed(3),reason:"position match",
      });
      base={...winner,id:base.id,qty:keepQty,notes:keepNotes,y_top:base.y_top,y_bottom:base.y_bottom};
      consumed.add(j);
      console.log(`BOM POS MERGE: y≈${base.y_top?.toFixed(3)} — kept "${winner.partNumber}" (score wins), dropped "${posMerges[posMerges.length-1].dropped}"`);
    }
    merged.push(base);
  }
  return [...merged,...withoutY];
}
// DECISION(v1.19.603): When an extraction unit is a cropped portion of the page, the AI
// returns y_top/y_bottom/x_left/x_right as fractions of the CROP. Translate them back to
// fractions of the original page so Drawing Reference previews still point at the right spot.
function translateItemsToPageCoords(items,cropBounds){
  if(!cropBounds)return items;
  const {x:cx,y:cy,w:cw,h:ch}=cropBounds;
  return items.map(it=>{
    const out={...it};
    if(typeof it.y_top==="number")out.y_top=Math.max(0,Math.min(1,cy+(it.y_top*ch)));
    if(typeof it.y_bottom==="number")out.y_bottom=Math.max(0,Math.min(1,cy+(it.y_bottom*ch)));
    if(typeof it.x_left==="number")out.x_left=Math.max(0,Math.min(1,cx+(it.x_left*cw)));
    if(typeof it.x_right==="number")out.x_right=Math.max(0,Math.min(1,cx+(it.x_right*cw)));
    return out;
  });
}
function mergeBoms(bomArrays){
  const map={};
  bomArrays.flat().forEach(item=>{
    const pn=_bomNormPn(item.partNumber);
    const key=pn||("desc:"+((item.description||"").replace(/\s+/g," ").trim().toLowerCase().slice(0,40)));
    if(map[key]){map[key]={...map[key],qty:(+map[key].qty||1)+(+item.qty||1)};}
    else{map[key]={...item};}
  });
  return fuzzyMergeBomItems(Object.values(map));
}

// DECISION(v1.19.638): Post-extraction sanity check — flag obvious column-alignment errors.
// When a BOM row's description implies a single physical assembly (enclosure, window kit,
// door, mounting bracket, nameplate, etc.) but qty > 10, the AI almost certainly grabbed the
// qty from the wrong row (e.g. assigned 143 terminal blocks to a window kit). Mark the row
// with `suspectQty:true` so the audit pass gets a second look at it and the UI can flag it.
const SUSPECT_QTY_PATTERNS=[
  /\benclos(ure|er)s?\b/i,/\bcabinet\b/i,/\bhousing\b/i,
  /\bwindow\s*kit\b/i,/\bviewing\s*(kit|window)\b/i,/\bdeep.?hinged\b/i,
  /\bdoor\s*(kit)?\b/i,/\bhinge\s*kit\b/i,
  /\bwall.?mount(ing|ed)?\s*(bracket|kit)\b/i,/\bmounting\s*bracket\b/i,/\bsub.?panel\b/i,/\bbackplane\b/i,/\bback.?panel\b/i,
  /\bheater\b/i,
  /\bpower\s*supply\b/i,/\bPSU\b/,
  /\bnameplate\b/i,/\bname\s*plate\b/i,
  /\bmain\s*(disconnect|breaker|switch)\b/i,
  /\btorque\s*indicator\b/i,
  /\bHMI\b/,/\btouchscreen\b/i,/\boperator\s*interface\b/i,
  /\bPLC\b/,/\bcontroller\b/i,
];
// DECISION(v1.19.672): Companion-part auto-splitter. Some BOM lines list a primary
// component with a companion catalog code embedded in the description column (e.g.
// "RH2B-ULC-DC24" with "w/ SH2B-05 Base" in the description). The AI prompt already
// instructs Claude to split these, but this is a belt-and-suspenders post-processor:
// scan each row's description for an additional catalog code adjacent to a companion
// keyword, and emit a new BOM row for it.
//
// Conservative matching — we only split when:
//   (a) description contains a companion keyword ("base","socket","aux","holder","mount",
//       "includes","w/","with","&","+","kit"), AND
//   (b) a plausible catalog code (4+ chars, letter+digit mix, optional dashes) appears
//       within ~3 tokens of that keyword, AND
//   (c) that code normalizes to something DIFFERENT from the primary partNumber, AND
//   (d) that code isn't already in the BOM as its own row.
const _COMPANION_KEYWORDS=["base","socket","holder","mount","aux","auxiliary","module","kit","includes","w/","with"];
const _COMPANION_PN_RE=/\b([A-Z][A-Z0-9]{1,}(?:-[A-Z0-9]+){0,5})\b/g;
// Tokens that LOOK like a PN but are almost always specs / non-parts — skip these.
const _COMPANION_PN_BLACKLIST=new Set(["VDC","VAC","AWG","NEMA","IP65","IP67","IP54","IP66","NC","NO","DIN","UL","CSA","SPST","SPDT","DPDT","3PH","1PH","AC","DC","HP","RPM","PLC","HMI","LED","LCD","PCB","USB","COM","RS485","RS232","PNP","NPN","PNPNPN","MOV","TVS","EMI","EMC","RTD","PT100","0-10V","4-20MA","24V","12V","120V","240V","480V","277V","208V","600V"]);
function _looksLikeCompanionPn(token,primaryPn){
  if(!token||token.length<4)return false;
  const up=token.toUpperCase();
  if(_COMPANION_PN_BLACKLIST.has(up))return false;
  if(/^\d+$/.test(up))return false; // all digits → spec, not PN
  if(!/[A-Z]/.test(up)||!/[0-9]/.test(up))return false; // PNs have both letters and digits
  // DECISION(v1.19.675): Reject classic ref-designator shapes (1-3 letters + 2-4 digits,
  // no dash). Examples: CR155, CR159, M2, OL12, PB3, SS1, CB12, TDR4, MCR2, TB14. These
  // live in the notes/tag column alongside the part number and were getting misclassified
  // as companion catalog codes, creating bogus BOM rows. Real catalog codes almost always
  // have a dash (SH2B-05, 100-FA22, RH2B-ULC-DC24) OR are 7+ chars without one.
  if(/^[A-Z]{1,3}\d{1,4}$/.test(up))return false;
  // DECISION(v1.19.793): Commas can't appear in real catalog codes. If the AI glued two
  // tokens together with a comma ("CB252, CB260"), reject. Cheap, no false-positive risk.
  if(up.includes(","))return false;
  if(!up.includes("-")&&up.length<7)return false;
  // DECISION(v1.19.793): Primary defense against tag-column-as-companion-code is in
  // BOM_PROMPT (column-header rule). If the AI follows it, additionalPartNumbers never
  // contains tag values to begin with. Pattern matching here was tried in v1.19.793 to
  // catch ref-designator ranges (VFD108-VFD138 etc.) but was reverted — too narrow to be
  // worth the false-positive risk on legitimate dashed catalog codes.
  // Normalized difference check
  if(normPart(up)===normPart(primaryPn||""))return false;
  return true;
}
function _makeCompanionRow(parentRow,pn,relationship){
  return{
    id:(Date.now()+Math.random()),
    itemNo:parentRow.itemNo||"",
    qty:+parentRow.qty||1,
    partNumber:pn,
    description:`Companion of ${parentRow.partNumber||"item"}${relationship?" ("+relationship+")":""}`,
    manufacturer:parentRow.manufacturer||"",
    notes:`Auto-added — companion part identified on same BOM line as ${parentRow.partNumber||"item"}${relationship?" ("+relationship+")":""}`,
    unitPrice:0,
    priceSource:"",
    priceDate:null,
    autoAddedCompanion:true,
    companionOfPartNumber:parentRow.partNumber||"",
    // DECISION(v1.19.677): Companion rows inherit the parent's qty verbatim, which is
    // correct for the common case (1 base per relay) but wrong for edge cases like
    // "1 kit w/ 3 bases". Set suspectQty:true so the ⚠ qty badge shows on the row,
    // prompting the user to verify — until the user confirms and edits the qty away.
    suspectQty:true,
    suspectQtyReason:`Auto-inherited qty from ${parentRow.partNumber||"parent item"}. Verify the companion's qty matches the drawing (e.g. 1 kit with 3 bases would need manual adjustment).`,
    y_top:(typeof parentRow.y_top==="number"?parentRow.y_top:undefined),
    y_bottom:(typeof parentRow.y_bottom==="number"?parentRow.y_bottom:undefined),
    sourcePageIdx:parentRow.sourcePageIdx,
    sourcePageId:parentRow.sourcePageId,
  };
}
function splitCompanionParts(bom){
  const existing=new Set(bom.filter(r=>!r.isLaborRow).map(r=>normPart(r.partNumber||"")).filter(Boolean));
  const results=[];
  const added=[];
  for(const row of bom){
    results.push(row);
    if(row.isLaborRow||row.isContingency)continue;
    const primary=(row.partNumber||"").trim();
    if(!primary)continue;
    const seen=new Set();
    // DECISION(v1.19.673): First pass — consume the AI's structured `additionalPartNumbers`
    // array. This is the authoritative channel — the AI is instructed (in BOM_PROMPT) to put
    // EVERY extra catalog code from the row here, regardless of which column it was in.
    const addl=Array.isArray(row.additionalPartNumbers)?row.additionalPartNumbers:[];
    for(const a of addl){
      const tok=(a&&a.partNumber||"").trim();
      if(!tok)continue;
      if(!_looksLikeCompanionPn(tok,primary))continue;
      const nk=normPart(tok);
      if(seen.has(nk)||existing.has(nk))continue;
      seen.add(nk);existing.add(nk);
      const companion=_makeCompanionRow(row,tok,a.relationship||"");
      if(a.context)companion.notes+=` · ${a.context}`;
      results.push(companion);
      added.push({primary,companion:tok,source:"additionalPartNumbers"});
      const parentNote=`Companion part ${tok} auto-added as separate BOM row`;
      if(!(row.notes||"").includes(parentNote))row.notes=row.notes?(row.notes+" · "+parentNote):parentNote;
    }
    // DECISION(v1.19.673): Second pass (safety net) — scan description for catalog codes
    // near companion keywords, in case the AI didn't populate additionalPartNumbers.
    // DECISION(v1.19.794): Removed `notes` from this scan. The notes field now legitimately
    // contains TAGS column values (ref designators) per the column-header rule. Scanning
    // notes was pulling tag values like "VFD108-VFD138" out as companion catalog codes
    // whenever the description contained a companion keyword like "module" or "kit".
    const scanText=row.description||"";
    if(!scanText)continue;
    const scanLow=scanText.toLowerCase();
    if(!_COMPANION_KEYWORDS.some(k=>scanLow.includes(k)))continue;
    let m;_COMPANION_PN_RE.lastIndex=0;
    while((m=_COMPANION_PN_RE.exec(scanText))!==null){
      const tok=m[1];
      if(!_looksLikeCompanionPn(tok,primary))continue;
      const nk=normPart(tok);
      if(seen.has(nk)||existing.has(nk))continue;
      const idx=m.index;
      const win=scanText.slice(Math.max(0,idx-25),Math.min(scanText.length,idx+tok.length+25)).toLowerCase();
      if(!_COMPANION_KEYWORDS.some(k=>win.includes(k)))continue;
      seen.add(nk);existing.add(nk);
      const companion=_makeCompanionRow(row,tok,"");
      results.push(companion);
      added.push({primary,companion:tok,source:"regex"});
      const parentNote=`Companion part ${tok} auto-added as separate BOM row`;
      if(!(row.notes||"").includes(parentNote))row.notes=row.notes?(row.notes+" · "+parentNote):parentNote;
    }
  }
  if(added.length)console.log(`COMPANION SPLIT: added ${added.length} companion part row${added.length>1?"s":""}:`,added.map(a=>`${a.primary} → ${a.companion} (${a.source})`).join(", "));
  else console.log("COMPANION SPLIT: no companion parts detected");
  return results;
}

function flagSuspectQuantities(bom){
  for(const r of bom){
    if(r.isLaborRow||r.isContingency)continue;
    const qty=+r.qty||0;
    const desc=(r.description||"").trim();
    if(qty>10&&SUSPECT_QTY_PATTERNS.some(re=>re.test(desc))){
      r.suspectQty=true;
      r.suspectQtyReason=`qty=${qty} but description implies single assembly; likely column-alignment error`;
      console.warn(`BOM QTY SANITY: ${r.partNumber} "${desc.slice(0,60)}" qty=${qty} — flagged as suspect`);
    }
  }
  return bom;
}

// DECISION(v1.19.646): Structural + pattern-based filter for non-BOM rows. A real BOM row
// must have all four essentials: qty > 0, partNumber, description, manufacturer. Anything
// missing one of those is likely a sheet-index entry, title-block artifact, or drawing-set
// reference that Opus wrongly picked up. Additionally, known non-BOM PN patterns (sheet
// identifiers like =CCD1+A01/05, barcodes, all-letter short codes) get filtered explicitly.
// Runs AFTER dedup, BEFORE sort + appendDefaultBomItems, so we only filter AI-extracted
// rows — never the contingency/labor/default rows added by the pipeline.
const NON_BOM_PN_PATTERNS=[
  // Sheet identifier patterns — always contain a "+" between alphanumerics and end with /NN or /NNN
  /^=?[A-Za-z]+\d*\+[A-Za-z]+\d+\/\d+$/,
  // Bare "=" prefix followed by anything with + or /
  /^=[A-Za-z0-9]+[+\/][A-Za-z0-9\/+]+$/,
  // DECISION(v1.19.647): REMOVED the `/^\d{10,}$/` pure-digit pattern. It was a false
  // positive for legitimate 10+-digit manufacturer PNs (Weidmuller uses 3137290000 etc).
  // Barcode filtering now relies on structural checks (4-field rule) — a real barcode row
  // from a title block lacks manufacturer/description so gets caught by the structural pass.
];
// DECISION(v1.19.741): Description patterns that strongly indicate a SHEET TITLE (not a
// component description). Removed "end cover" and "panel grounding" — both are legitimate
// component descriptions used by Phoenix Contact, Wago, Allen-Bradley, etc. for terminal-
// block accessories. Reported false positive: PRJ402079 had Phoenix Contact PN 3047028
// (a real end-cover part) filtered out as a non-BOM row. Remaining patterns only match
// strings that are unambiguously drawing/sheet artifacts and never component names.
const NON_BOM_DESC_PATTERNS=[
  /^(list of assemblies|electrical schematic diagram|schematic diagram|drawing index|sheet index|title page|cover sheet|cover page|revision block|notes page|legend page|general notes)$/i,
  /^drawing (no|number|list|index)/i,
  /^sheet (no|number|index|list)/i,
  /^title none$/i,
];
function filterNonBomRows(bom){
  const kept=[],dropped=[];
  for(const r of bom){
    // Flag-based exemptions — user-added, labor, contingency, auto-loaded rows pass through.
    if(r.isLaborRow||r.isContingency||r.autoLoaded||r.isCrossed||r.isCorrection||r.correctedByLibrary){
      kept.push(r);
      continue;
    }
    const pn=(r.partNumber||"").trim();
    const desc=(r.description||"").trim();
    const mfr=(r.manufacturer||"").trim();
    const qty=+r.qty||0;
    // STRUCTURAL CHECK: a true BOM row has all four essentials populated.
    // If missing 2+ of the four, definitely not a BOM row — drop.
    const missing=[];
    if(qty<=0)missing.push("qty");
    if(pn.length<2)missing.push("partNumber");
    if(desc.length<3)missing.push("description");
    if(mfr.length<2)missing.push("manufacturer");
    if(missing.length>=2){
      dropped.push({partNumber:pn,description:desc,reason:`Not a BOM row — missing ${missing.join(", ")}`});
      continue;
    }
    // PATTERN CHECKS: sheet identifiers, barcodes, drawing references
    if(NON_BOM_PN_PATTERNS.some(re=>re.test(pn))){
      dropped.push({partNumber:pn,description:desc,reason:`Sheet identifier / drawing reference — not a component`});
      continue;
    }
    // DECISION(v1.19.741): Description-pattern check requires the manufacturer to ALSO
    // be missing. A real component with this description (e.g. Phoenix Contact 3047028
    // "End cover") will always have a manufacturer; a drawing-sheet artifact won't.
    // Guards against the PRJ402079 false-positive where a legit Phoenix Contact PN was
    // dropped purely because its description matched a sheet-title regex.
    if(NON_BOM_DESC_PATTERNS.some(re=>re.test(desc))&&mfr.length<2){
      dropped.push({partNumber:pn,description:desc,reason:`Description is a drawing sheet title — not a component`});
      continue;
    }
    // SPATIAL CHECK: rows in the bottom-right quadrant are likely title-block artifacts.
    // Only apply when position data exists and row is clearly in title-block territory.
    if(typeof r.y_top==="number"&&typeof r.x_left==="number"&&
       r.y_top>0.88&&r.x_left>0.65){
      // Bottom-right corner. Unless it's clearly a multi-row repeat, it's likely title block.
      dropped.push({partNumber:pn,description:desc,reason:`Position suggests title-block area (bottom-right corner)`});
      continue;
    }
    kept.push(r);
  }
  if(dropped.length>0){
    console.log(`BOM FILTER: dropped ${dropped.length} non-BOM row${dropped.length>1?"s":""}:`,dropped.slice(0,10));
  }
  return{kept,dropped};
}

// ── FIRESTORE TEAM HELPERS ──
async function loadUserProfile(uid){
  try{const d=await fbDb.doc(`users/${uid}/config/profile`).get();return d.exists?d.data():null;}catch(e){return null;}
}
async function createCompany(uid,email,name){
  const cid=fbDb.collection("companies").doc().id;
  // Step 1: create the company doc first (rule: createdBy == auth.uid)
  await fbDb.doc(`companies/${cid}`).set({name,createdAt:Date.now(),createdBy:uid});
  // Step 2: now that the company doc exists, write member + profile in a batch
  // (member rule does get() on company to verify createdBy)
  const batch=fbDb.batch();
  batch.set(fbDb.doc(`companies/${cid}/members/${uid}`),{email,role:"admin",addedAt:Date.now()});
  batch.set(fbDb.doc(`users/${uid}/config/profile`),{companyId:cid,role:"admin"});
  await batch.commit();
  return cid;
}
async function loadCompanyMembers(companyId){
  const snap=await fbDb.collection(`companies/${companyId}/members`).get();
  return snap.docs.map(d=>({uid:d.id,...d.data()}));
}
async function loadPendingInvites(companyId){
  const snap=await fbDb.collection(`companies/${companyId}/pendingInvites`).get();
  return snap.docs.map(d=>({token:d.id,...d.data()}));
}

