function mergeLayoutResults(layouts){
  _dbg("MERGE LAYOUTS: "+layouts.length+" layout results to merge");
  layouts.forEach((l,i)=>console.log("Layout result "+i+":",JSON.stringify({doorCutouts:l?.doorCutouts?.length,backpanelDevices:l?.backpanelDevices?.length})));
  const merged={doorCutouts:[],backpanelDevices:[],ductRuns:[],dinRails:[],sideTopDevices:[],enclosure:null};
  for(const l of layouts){
    if(!l)continue;
    if(l.enclosure&&!merged.enclosure)merged.enclosure=l.enclosure;
    if(Array.isArray(l.doorCutouts))merged.doorCutouts.push(...l.doorCutouts);
    if(Array.isArray(l.backpanelDevices))merged.backpanelDevices.push(...l.backpanelDevices);
    if(Array.isArray(l.ductRuns))merged.ductRuns.push(...l.ductRuns);
    if(Array.isArray(l.dinRails))merged.dinRails.push(...l.dinRails);
    if(Array.isArray(l.sideTopDevices))merged.sideTopDevices.push(...l.sideTopDevices);
  }
  // Deduplicate door cutouts by tag (same device may appear on multiple layout pages)
  const seenDoor=new Set();
  merged.doorCutouts=merged.doorCutouts.filter(d=>{
    const key=(d.tag||"").toUpperCase();
    if(!key||seenDoor.has(key))return false;
    seenDoor.add(key);return true;
  });
  // Deduplicate backpanel devices by tag
  const seenBack=new Set();
  merged.backpanelDevices=merged.backpanelDevices.filter(d=>{
    const key=(d.tag||"").toUpperCase();
    if(!key||seenBack.has(key))return false;
    seenBack.add(key);return true;
  });
  console.log("AFTER DEDUP: doorCutouts="+merged.doorCutouts.length+", backpanelDevices="+merged.backpanelDevices.length);
  // Deduplicate side/top devices by tag
  const seenSide=new Set();
  merged.sideTopDevices=merged.sideTopDevices.filter(d=>{
    const key=(d.tag||"").toUpperCase();
    if(!key||seenSide.has(key))return false;
    seenSide.add(key);return true;
  });
  // Compute derived counts
  const ductFeet=merged.ductRuns.reduce((s,r)=>s+(r.lengthFt||0),0);
  const dinFeet=merged.dinRails.reduce((s,r)=>s+(r.lengthFt||0),0);
  const ductDinFeet=Math.round((ductFeet+dinFeet)*10)/10;
  // Categorize side/top devices by location and type
  const topBeaconCount=merged.sideTopDevices.filter(d=>d.location==="top"||d.type==="beacon").length;
  const squareCutoutCount=merged.sideTopDevices.filter(d=>d.location!=="top"&&d.type!=="beacon"&&d.type!=="fan"&&d.type!=="air_conditioner").length;
  const sideTopSmallCount=merged.sideTopDevices.filter(d=>d.type==="fan").length;
  const sideTopLargeCount=merged.sideTopDevices.filter(d=>d.type==="air_conditioner").length;
  // Compute unified side-mounted component labor
  const sideDevices=merged.sideTopDevices.filter(d=>d.location!=="top"&&d.type!=="beacon");
  let sideDeviceMinutes=0;
  for(const d of sideDevices){
    if(d.type==="fan"){sideDeviceMinutes+=120;}
    else if(d.type==="air_conditioner"){sideDeviceMinutes+=240;}
    else if(d.type==="fan_shroud"){
      const maxDim=Math.max(d.widthIn||0,d.heightIn||0);
      if(maxDim<4)sideDeviceMinutes+=90;
      else if(maxDim<=6)sideDeviceMinutes+=120;
      else sideDeviceMinutes+=180;
    }
    else{sideDeviceMinutes+=180;} // horn, conduit_hub, other
  }
  const sideDeviceHours=Math.round(sideDeviceMinutes/60*100)/100;
  const sideDeviceCount=sideDevices.length;
  // Panel holes: door cutouts (HMI=25 eq) + top beacons (1 hole each)
  const doorHoles=merged.doorCutouts.reduce((s,c)=>s+(c.type==="hmi"?LABOR_RATES.hmiHoleEquivalent:1),0);
  const panelHoles=doorHoles+topBeaconCount;
  const doorDeviceCount=merged.doorCutouts.length;
  const backpanelDeviceCount=merged.backpanelDevices.length;
  return{...merged,ductDinFeet,panelHoles,doorDeviceCount,backpanelDeviceCount,sideTopSmallCount,sideTopLargeCount,squareCutoutCount,topBeaconCount,sideDeviceHours,sideDeviceCount};
}

// ── LAYOUT LEARNING DB ──
let _layoutLearningCache=null;
function _llPath(uid){return (_appCtx.configPath||`users/${uid}/config`)+"/layout_learning";}
async function loadLayoutLearning(uid){
  if(_layoutLearningCache)return _layoutLearningCache;
  try{const d=await fbDb.doc(_llPath(uid)).get();_layoutLearningCache=d.exists?(d.data().entries||[]):[];}
  catch(e){_layoutLearningCache=[];}
  return _layoutLearningCache;
}
async function saveLayoutLearningEntry(uid,entry){
  const entries=await loadLayoutLearning(uid);
  entries.push({...entry,savedAt:Date.now()});
  _layoutLearningCache=entries;
  await fbDb.doc(_llPath(uid)).set({entries}).catch(()=>{});
}
function buildLayoutLearningHint(entries){
  if(!entries||!entries.length)return"";
  const relevant=entries.slice(-15);
  const lines=relevant.map(e=>{
    const details=[];
    if(e.doorCutoutCount!=null)details.push("doorCutouts="+e.doorCutoutCount);
    if(e.topBeaconCount!=null)details.push("topBeacons="+e.topBeaconCount);
    if(e.aiPanelHoles!=null)details.push("ARC AI calculated "+e.aiPanelHoles+" panel holes");
    if(e.userPanelHoles!=null)details.push("user corrected to "+e.userPanelHoles+" panel holes");
    if(e.note)details.push("note: "+e.note);
    return "- "+details.join(", ");
  });
  return`\n\nLearning from past panel hole corrections by this user:\n${lines.join("\n")}\nUse these patterns to improve door cutout vs backpanel device classification. Common errors: miscounting door cutouts by including backpanel devices, or missing door-mounted devices.`;
}

